1	/**
2	 * Layerinfinite — routes/admin/actions.ts
3	 * Admin action management endpoints.
4	 * ══════════════════════════════════════════════════════════════
5	 * REST endpoints:
6	 * POST /        — register a new action
7	 * GET  /        — list all registered actions
8	 * GET  /:id     — get a single action
9	 * PUT  /:id     — enable/disable an action
10	 *
11	 * Legacy aliases are kept for compatibility:
12	 * POST /register-action, GET /actions, GET /actions/:id, PUT /actions/:id
13	 *
14	 * Authentication via admin-auth.ts middleware (customer_admin).
15	 * ══════════════════════════════════════════════════════════════
16	 */
17	
18	import { Hono } from 'hono';
19	import { z } from 'zod';
20	import { supabase } from '../../lib/supabase.js';
21	import { invalidateActionCache } from '../../middleware/validate-action.js';
22	
23	export const actionsRouter = new Hono();
24	
25	// ── Register action schema ────────────────────────────────────
26	const RegisterActionBody = z.object({
27	    action_name: z.string().min(1).max(255),
28	    // Any string is accepted. Value is normalized to lowercase.
29	    // 'custom' is the default for callers that omit the field.
30	    // Field is a display label — scoring.ts passes it through as-is,
31	    // no branching or scoring weight applied.
32	    action_category: z
33	        .string()
34	        .max(100)
35	        .optional()
36	        .default('custom')
37	        .transform(val => val.trim().toLowerCase()),
38	    action_description: z.string().max(1000).optional(),
39	    required_params: z.array(z.string()).optional().default([]),
40	    validation_mode: z.string().optional().default('none'),
41	});
42	
43	function getCustomerId(c: any): string | null {
44	    return ((c as any).get('customerId') ?? c.get('customer_id') ?? null) as string | null;
45	}
46	
47	async function registerActionHandler(c: any) {
48	    const customerId = getCustomerId(c);
49	    if (!customerId) {
50	        return c.json({ error: 'Unauthorized' }, 401);
51	    }
52	
53	    let body: z.infer<typeof RegisterActionBody>;
54	    try {
55	        body = RegisterActionBody.parse(await c.req.json());
56	    } catch (err: any) {
57	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
58	    }
59	
60	    const { data, error } = await supabase
61	        .from('dim_actions')
62	        .insert({
63	            action_name: body.action_name,
64	            action_category: body.action_category,
65	            action_description: body.action_description ?? null,
66	            required_params: body.required_params,
67	            validation_mode: body.validation_mode ?? 'none',
68	            is_active: true,
69	            customer_id: customerId,
70	        })
71	        .select('action_id, action_name, action_category, is_active, customer_id, created_at')
72	        .single();
73	
74	    if (error) {
75	        if (error.code === '23505') {
76	            return c.json(
77	                { error: `Action "${body.action_name}" already exists.`, code: 'DUPLICATE' },
78	                409
79	            );
80	        }
81	        return c.json({ error: 'Failed to register action', details: error.message }, 500);
82	    }
83	
84	    invalidateActionCache(body.action_name);
85	
86	    return c.json({
87	        success: true,
88	        action: data,
89	        message: `Action "${body.action_name}" registered. Agents can now log outcomes with this action.`,
90	    }, 201);
91	}
92	
93	async function listActionsHandler(c: any) {
94	    const customerId = getCustomerId(c);
95	    if (!customerId) {
96	        return c.json({ error: 'Unauthorized' }, 401);
97	    }
98	
99	    const { data, error } = await supabase
100	        .from('dim_actions')
101	        .select('*')
102	        .eq('customer_id', customerId)
103	        .order('created_at', { ascending: false });
104	
105	    if (error) return c.json({ error: error.message }, 500);
106	
107	    return c.json({
108	        actions: data ?? [],
109	        total: data?.length ?? 0,
110	        note: 'Customer-scoped action registry.',
111	    });
112	}
113	
114	async function getActionByIdHandler(c: any) {
115	    const customerId = getCustomerId(c);
116	    if (!customerId) {
117	        return c.json({ error: 'Unauthorized' }, 401);
118	    }
119	
120	    const actionId = c.req.param('id');
121	    const { data, error } = await supabase
122	        .from('dim_actions')
123	        .select('*')
124	        .eq('action_id', actionId)
125	        .eq('customer_id', customerId)
126	        .maybeSingle();
127	
128	    if (error) return c.json({ error: error.message }, 500);
129	    if (!data) return c.json({ error: 'Action not found' }, 404);
130	
131	    return c.json({ action: data });
132	}
133	
134	async function toggleActionHandler(c: any) {
135	    const customerId = getCustomerId(c);
136	    if (!customerId) {
137	        return c.json({ error: 'Unauthorized' }, 401);
138	    }
139	
140	    const actionId = c.req.param('id');
141	
142	    let body: { is_active?: boolean };
143	    try {
144	        body = await c.req.json();
145	    } catch {
146	        return c.json({ error: 'Invalid JSON body' }, 400);
147	    }
148	
149	    if (typeof body.is_active !== 'boolean') {
150	        return c.json({ error: 'Provide { is_active: true|false }' }, 400);
151	    }
152	
153	    const { data, error } = await supabase
154	        .from('dim_actions')
155	        .update({
156	            is_active: body.is_active,
157	            updated_at: new Date().toISOString(),
158	        })
159	        .eq('action_id', actionId)
160	        .eq('customer_id', customerId)
161	        .select('action_id, action_name, is_active')
162	        .single();
163	
164	    if (error) return c.json({ error: error.message }, 500);
165	    if (!data) return c.json({ error: 'Action not found' }, 404);
166	
167	    invalidateActionCache(data.action_name);
168	
169	    return c.json({
170	        success: true,
171	        action: data,
172	        message: `Action "${data.action_name}" is now ${data.is_active ? 'active' : 'disabled'}.`,
173	    });
174	}
175	
176	// ── RESTful paths ─────────────────────────────────────────────
177	actionsRouter.get('/', listActionsHandler);
178	actionsRouter.post('/', registerActionHandler);
179	actionsRouter.get('/:id', getActionByIdHandler);
180	actionsRouter.put('/:id', toggleActionHandler);
181	
182	// ── Legacy aliases ────────────────────────────────────────────
183	actionsRouter.get('/actions', listActionsHandler);
184	actionsRouter.post('/register-action', registerActionHandler);
185	actionsRouter.get('/actions/:id', getActionByIdHandler);
186	actionsRouter.put('/actions/:id', toggleActionHandler);
187

1	/**
2	 * Layerinfinite — routes/admin/embedding-drift.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * GET  /v1/admin/embedding-drift         → latest drift report
5	 * POST /v1/admin/embedding-drift/check   → run drift detection now
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import { Hono } from 'hono';
10	import { supabase } from '../../lib/supabase.js';
11	import { runDriftDetection } from '../../lib/drift-detector.js';
12	
13	export const embeddingDriftRouter = new Hono();
14	
15	// GET latest drift report
16	embeddingDriftRouter.get('/', async (c) => {
17	    const { data, error } = await supabase
18	        .from('embedding_drift_reports')
19	        .select('*')
20	        .order('checked_at', { ascending: false })
21	        .limit(10);
22	
23	    if (error) return c.json({ error: 'Failed to fetch drift reports', details: error.message }, 500);
24	
25	    return c.json({
26	        reports: data ?? [],
27	        latest: data?.[0] ?? null,
28	    });
29	});
30	
31	// POST trigger a drift check
32	embeddingDriftRouter.post('/check', async (c) => {
33	    const report = await runDriftDetection();
34	    return c.json(report, report.drift_detected ? 200 : 200);
35	});
36

1	/**
2	 * Layerinfinite — routes/admin/reinstate-agent.ts
3	 * POST /v1/admin/reinstate-agent
4	 * ══════════════════════════════════════════════════════════════
5	 * Reinstates a suspended agent to probation status.
6	 * Sets trust_score=0.4, trust_status='probation',
7	 * consecutive_failures=0, and logs to agent_trust_audit.
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { Hono } from 'hono';
12	import { z } from 'zod';
13	import { supabase } from '../../lib/supabase.js';
14	
15	export const reinstateAgentRouter = new Hono();
16	
17	const ReinstateBody = z.object({
18	    agent_id: z.string().uuid(),
19	    reinstated_by: z.string().min(1).max(255),
20	});
21	
22	reinstateAgentRouter.post('/', async (c) => {
23	    const customerId = c.get('customer_id') as string;
24	
25	    let body: z.infer<typeof ReinstateBody>;
26	    try {
27	        body = ReinstateBody.parse(await c.req.json());
28	    } catch (err: any) {
29	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
30	    }
31	
32	    // ── Verify agent belongs to this customer ──────────────────
33	    const { data: agent, error: agentErr } = await supabase
34	        .from('dim_agents')
35	        .select('agent_id, agent_name, customer_id')
36	        .eq('agent_id', body.agent_id)
37	        .eq('customer_id', customerId)
38	        .maybeSingle();
39	
40	    if (agentErr) {
41	        return c.json({ error: 'Agent lookup failed', details: agentErr.message }, 500);
42	    }
43	    if (!agent) {
44	        return c.json({ error: 'Agent not found or does not belong to your account', code: 'NOT_FOUND' }, 404);
45	    }
46	
47	    // ── Verify agent is currently suspended ────────────────────
48	    const { data: trust, error: trustErr } = await supabase
49	        .from('agent_trust_scores')
50	        .select('trust_score, trust_status, consecutive_failures')
51	        .eq('agent_id', body.agent_id)
52	        .maybeSingle();
53	
54	    if (trustErr) {
55	        return c.json({ error: 'Trust lookup failed', details: trustErr.message }, 500);
56	    }
57	
58	    if (!trust || trust.trust_status !== 'suspended') {
59	        return c.json(
60	            { error: 'Agent is not currently suspended', code: 'INVALID_STATE', current_status: trust?.trust_status ?? 'unknown' },
61	            400
62	        );
63	    }
64	
65	    // ── Reinstate: update trust scores ─────────────────────────
66	    const { error: updateErr } = await supabase
67	        .from('agent_trust_scores')
68	        .update({
69	            trust_score: 0.4,
70	            trust_status: 'probation',
71	            consecutive_failures: 0,
72	            updated_at: new Date().toISOString(),
73	        })
74	        .eq('agent_id', body.agent_id);
75	
76	    if (updateErr) {
77	        return c.json({ error: 'Failed to reinstate agent', details: updateErr.message }, 500);
78	    }
79	
80	    // ── Log to agent_trust_audit ───────────────────────────────
81	    await supabase
82	        .from('agent_trust_audit')
83	        .insert({
84	            agent_id: body.agent_id,
85	            customer_id: customerId,
86	            event_type: 'reinstated',
87	            old_score: trust.trust_score,
88	            new_score: 0.4,
89	            old_status: 'suspended',
90	            new_status: 'probation',
91	            performed_by: body.reinstated_by,
92	            reason: `Manually reinstated by ${body.reinstated_by}`,
93	        });
94	
95	    return c.json({
96	        reinstated: true,
97	        agent_id: body.agent_id,
98	        agent_name: agent.agent_name,
99	        new_status: 'probation',
100	        new_score: 0.4,
101	        message: `Agent "${agent.agent_name}" reinstated to probation (score: 0.4).`,
102	    }, 200);
103	});
104

1	/**
2	 * Layerinfinite — routes/admin/reinstate-sandbox.ts
3	 * POST /v1/admin/agents/:agent_id/sandbox-reinstate
4	 * ══════════════════════════════════════════════════════════════
5	 * Reinstates a suspended agent directly into the Sandbox protocol
6	 * to begin a graduated behavioral recovery sequence under review.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import { Hono } from 'hono';
11	import { z } from 'zod';
12	import { supabase } from '../../lib/supabase.js';
13	
14	export const reinstateSandboxRouter = new Hono();
15	
16	const ReinstateSandboxBody = z.object({
17	    consecutive_failures_override: z.number().int().min(0).optional().default(0),
18	    trust_score_boost: z.number().min(0.0).max(1.0).optional().default(0.15),
19	    reason: z.string().min(1).max(1000),
20	});
21	
22	reinstateSandboxRouter.post('/:agent_id/sandbox-reinstate', async (c) => {
23	    const agentId = c.req.param('agent_id');
24	
25	    let body: z.infer<typeof ReinstateSandboxBody>;
26	    try {
27	        body = ReinstateSandboxBody.parse(await c.req.json());
28	    } catch (err: any) {
29	        return c.json(
30	            { error: 'Invalid request body', details: err.errors ?? err.message, code: 'VALIDATION_ERROR' },
31	            400
32	        );
33	    }
34	
35	    // 1. Verify agent exists and is suspended
36	    const { data: trustRec, error: fetchErr } = await supabase
37	        .from('agent_trust_scores')
38	        .select('trust_status, customer_id')
39	        .eq('agent_id', agentId)
40	        .maybeSingle();
41	
42	    if (fetchErr || !trustRec) {
43	        return c.json({ error: 'Agent trust record not found', code: 'NOT_FOUND' }, 404);
44	    }
45	
46	    if (trustRec.trust_status !== 'suspended') {
47	        return c.json(
48	            { error: 'Agent is not currently suspended', code: 'INVALID_STATE', current_status: trustRec.trust_status },
49	            400
50	        );
51	    }
52	
53	    // 2-4. Update trust scores to push them into Sandbox manually
54	    const { error: updateErr } = await supabase
55	        .from('agent_trust_scores')
56	        .update({
57	            trust_score: body.trust_score_boost,
58	            trust_status: 'sandbox',
59	            consecutive_failures: body.consecutive_failures_override,
60	            suspension_reason: null,
61	            updated_at: new Date().toISOString(),
62	        })
63	        .eq('agent_id', agentId);
64	
65	    if (updateErr) {
66	        return c.json({ error: 'Failed to update trust status', code: 'UPDATE_ERROR' }, 500);
67	    }
68	
69	    // 5. Insert audit trail record
70	    const { error: auditErr } = await supabase
71	        .from('agent_trust_audit')
72	        .insert({
73	            agent_id: agentId,
74	            customer_id: trustRec.customer_id,
75	            event_type: 'sandbox_reinstated',
76	            old_score: 0.0, // Arbitrary for suspended
77	            new_score: body.trust_score_boost,
78	            old_status: 'suspended',
79	            new_status: 'sandbox',
80	            reason: body.reason,
81	        });
82	
83	    if (auditErr) {
84	        console.warn('[reinstate-sandbox] Failed to log audit trail:', auditErr.message);
85	    }
86	
87	    return c.json({
88	        success: true,
89	        message: 'Agent reinstated into Sandbox mode. All autonomous functions restabilized but explicitly flagged for human review verification.',
90	        new_status: 'sandbox',
91	        trust_score: body.trust_score_boost,
92	        consecutive_failures: body.consecutive_failures_override,
93	    }, 200);
94	});
95

1	/**
2	 * Layerinfinite — routes/admin/restore-trust-snapshot.ts
3	 * POST /v1/admin/restore-trust-snapshot
4	 * ══════════════════════════════════════════════════════════════
5	 * Restores an agent's trust score to its most recent pre-incident
6	 * snapshot. Used after a coordinated infrastructure failure resolves.
7	 *
8	 * Body:
9	 *   agent_id    — UUID of the agent to restore
10	 *   incident_id — (optional) filter to snapshots tagged with this incident
11	 *   restored_by — name/identifier of the operator performing the restore
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Hono } from 'hono';
16	import { z } from 'zod';
17	import { supabase } from '../../lib/supabase.js';
18	
19	export const restoreTrustSnapshotRouter = new Hono();
20	
21	const RestoreBody = z.object({
22	    agent_id: z.string().uuid(),
23	    incident_id: z.string().optional(),
24	    restored_by: z.string().min(1).max(255),
25	});
26	
27	restoreTrustSnapshotRouter.post('/', async (c) => {
28	    const customerId = c.get('customer_id') as string;
29	
30	    let body: z.infer<typeof RestoreBody>;
31	    try {
32	        body = RestoreBody.parse(await c.req.json());
33	    } catch (err: any) {
34	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
35	    }
36	
37	    // ── Verify agent belongs to this customer ──────────────────
38	    const { data: agent, error: agentErr } = await supabase
39	        .from('dim_agents')
40	        .select('agent_id, agent_name, customer_id')
41	        .eq('agent_id', body.agent_id)
42	        .eq('customer_id', customerId)
43	        .maybeSingle();
44	
45	    if (agentErr) return c.json({ error: 'Agent lookup failed', details: agentErr.message }, 500);
46	    if (!agent) return c.json({ error: 'Agent not found or does not belong to your account' }, 404);
47	
48	    // ── Fetch current trust score ──────────────────────────────
49	    const { data: currentTrust, error: trustErr } = await supabase
50	        .from('agent_trust_scores')
51	        .select('trust_score, trust_status, consecutive_failures')
52	        .eq('agent_id', body.agent_id)
53	        .maybeSingle();
54	
55	    if (trustErr) return c.json({ error: 'Trust lookup failed', details: trustErr.message }, 500);
56	    if (!currentTrust) return c.json({ error: 'Trust record not found for agent' }, 404);
57	
58	    // ── Find the most recent matching snapshot ─────────────────
59	    let snapshotQuery = supabase
60	        .from('agent_trust_snapshots')
61	        .select('id, trust_score, trust_status, consecutive_failures, snapshot_reason, incident_id, created_at')
62	        .eq('agent_id', body.agent_id)
63	        .order('created_at', { ascending: false })
64	        .limit(1);
65	
66	    if (body.incident_id) {
67	        snapshotQuery = snapshotQuery.eq('incident_id', body.incident_id);
68	    } else {
69	        // Without a specific incident, restore from the most recent pre_incident snapshot
70	        snapshotQuery = snapshotQuery.eq('snapshot_reason', 'pre_incident');
71	    }
72	
73	    const { data: snapshot, error: snapErr } = await snapshotQuery.maybeSingle();
74	
75	    if (snapErr) return c.json({ error: 'Snapshot lookup failed', details: snapErr.message }, 500);
76	    if (!snapshot) {
77	        return c.json(
78	            {
79	                error: 'No matching snapshot found',
80	                hint: body.incident_id
81	                    ? `No snapshot found for incident "${body.incident_id}"`
82	                    : 'No pre_incident snapshot found. Use POST /v1/admin/reinstate-agent for manual reinstatement.',
83	            },
84	            404
85	        );
86	    }
87	
88	    // ── Restore trust to snapshot values ──────────────────────
89	    const { error: updateErr } = await supabase
90	        .from('agent_trust_scores')
91	        .update({
92	            trust_score: snapshot.trust_score,
93	            trust_status: snapshot.trust_status,
94	            consecutive_failures: snapshot.consecutive_failures,
95	            suspension_reason: null,
96	            updated_at: new Date().toISOString(),
97	        })
98	        .eq('agent_id', body.agent_id);
99	
100	    if (updateErr) return c.json({ error: 'Failed to restore trust snapshot', details: updateErr.message }, 500);
101	
102	    // ── Audit log ──────────────────────────────────────────────
103	    await supabase.from('agent_trust_audit').insert({
104	        agent_id: body.agent_id,
105	        customer_id: customerId,
106	        event_type: 'reinstated',
107	        old_score: currentTrust.trust_score,
108	        new_score: snapshot.trust_score,
109	        old_status: currentTrust.trust_status,
110	        new_status: snapshot.trust_status,
111	        performed_by: body.restored_by,
112	        reason: `Trust restored from snapshot (incident: ${body.incident_id ?? 'latest pre_incident'}, snapshot_id: ${snapshot.id}). Operator: ${body.restored_by}.`,
113	    });
114	
115	    return c.json({
116	        restored: true,
117	        agent_id: body.agent_id,
118	        agent_name: agent.agent_name,
119	        snapshot_id: snapshot.id,
120	        snapshot_created_at: snapshot.created_at,
121	        incident_id: snapshot.incident_id,
122	        previous_score: currentTrust.trust_score,
123	        previous_status: currentTrust.trust_status,
124	        restored_score: snapshot.trust_score,
125	        restored_status: snapshot.trust_status,
126	        message: `Trust for "${agent.agent_name}" restored to pre-incident snapshot (score: ${snapshot.trust_score.toFixed(3)}, status: ${snapshot.trust_status}).`,
127	    });
128	});
129

1	/**
2	 * Layerinfinite — routes/admin/test-notification.ts
3	 * POST /v1/admin/test-notification
4	 * ══════════════════════════════════════════════════════════════
5	 * Sends a test notification to a specific channel.
6	 * Verifies the channel belongs to the authenticated customer.
7	 * Returns { success, error? } so the dashboard can show results.
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { Hono } from 'hono';
12	import { z } from 'zod';
13	import { supabase } from '../../lib/supabase.js';
14	
15	export const testNotificationRouter = new Hono();
16	
17	const TestBody = z.object({
18	    channel_id: z.string().uuid(),
19	});
20	
21	testNotificationRouter.post('/', async (c) => {
22	    const customerId = c.get('customer_id') as string;
23	
24	    let body: z.infer<typeof TestBody>;
25	    try {
26	        body = TestBody.parse(await c.req.json());
27	    } catch (err: any) {
28	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
29	    }
30	
31	    // ── Verify channel belongs to this customer ────────────────
32	    const { data: channel, error: chErr } = await supabase
33	        .from('alert_notification_channels')
34	        .select('id, channel_type, destination, label, customer_id')
35	        .eq('id', body.channel_id)
36	        .eq('customer_id', customerId)
37	        .maybeSingle();
38	
39	    if (chErr) {
40	        return c.json({ error: 'Channel lookup failed', details: chErr.message }, 500);
41	    }
42	    if (!channel) {
43	        return c.json({ error: 'Channel not found or does not belong to your account', code: 'NOT_FOUND' }, 404);
44	    }
45	
46	    // ── Build synthetic test alert ─────────────────────────────
47	    const testAlert = {
48	        alert_id: '00000000-0000-0000-0000-000000000000',
49	        alert_type: 'latency_spike',
50	        severity: 'warning',
51	        message: 'This is a test notification from Layerinfinite. Your alert channel is configured correctly.',
52	        agent_id: null,
53	        action_name: 'test_action',
54	        metadata: { test: true },
55	        detected_at: new Date().toISOString(),
56	    };
57	
58	    // ── Deliver based on channel type ──────────────────────────
59	    try {
60	        let ok = false;
61	        let status: number | null = null;
62	        let errorMessage: string | null = null;
63	
64	        if (channel.channel_type === 'slack_webhook') {
65	            const payload = {
66	                blocks: [
67	                    {
68	                        type: 'header',
69	                        text: { type: 'plain_text', text: '🟡 Layerinfinite Test: Latency Spike' },
70	                    },
71	                    {
72	                        type: 'section',
73	                        text: { type: 'mrkdwn', text: testAlert.message },
74	                    },
75	                    {
76	                        type: 'context',
77	                        elements: [{
78	                            type: 'mrkdwn',
79	                            text: `*Severity:* warning | *This is a test notification*`,
80	                        }],
81	                    },
82	                ],
83	            };
84	
85	            const res = await fetch(channel.destination, {
86	                method: 'POST',
87	                headers: { 'Content-Type': 'application/json' },
88	                body: JSON.stringify(payload),
89	                signal: AbortSignal.timeout(10000),
90	            });
91	            ok = res.ok;
92	            status = res.status;
93	            if (!res.ok) errorMessage = `Slack returned HTTP ${res.status}`;
94	        } else if (channel.channel_type === 'webhook') {
95	            const payload = {
96	                ...testAlert,
97	                source: 'layerinfinite',
98	            };
99	
100	            const res = await fetch(channel.destination, {
101	                method: 'POST',
102	                headers: {
103	                    'Content-Type': 'application/json',
104	                    'User-Agent': 'Layerinfinite-Alerts/1.0',
105	                    'X-Layerinfinite-Alert-Type': 'latency_spike',
106	                    'X-Layerinfinite-Severity': 'warning',
107	                },
108	                body: JSON.stringify(payload),
109	                signal: AbortSignal.timeout(10000),
110	            });
111	            ok = res.ok;
112	            status = res.status;
113	            if (!res.ok) {
114	                let errBody = '';
115	                try { errBody = await res.text(); } catch { /* ignore */ }
116	                errorMessage = `Webhook returned HTTP ${res.status}: ${errBody}`.slice(0, 500);
117	            }
118	        } else if (channel.channel_type === 'email') {
119	            const resendKey = process.env.RESEND_API_KEY;
120	            if (!resendKey) {
121	                return c.json({
122	                    success: false,
123	                    error: 'Email delivery requires RESEND_API_KEY env var. Set it in your environment.',
124	                }, 200);
125	            }
126	
127	            const fromEmail = process.env.ALERT_FROM_EMAIL ?? 'alerts@layerinfinite.dev';
128	            const res = await fetch('https://api.resend.com/emails', {
129	                method: 'POST',
130	                headers: {
131	                    'Content-Type': 'application/json',
132	                    'Authorization': `Bearer ${resendKey}`,
133	                },
134	                body: JSON.stringify({
135	                    from: fromEmail,
136	                    to: [channel.destination],
137	                    subject: '[Layerinfinite] TEST: Latency Spike detected',
138	                    text: testAlert.message,
139	                    html: `<p>${testAlert.message}</p>`,
140	                }),
141	                signal: AbortSignal.timeout(10000),
142	            });
143	            ok = res.ok;
144	            status = res.status;
145	            if (!res.ok) errorMessage = `Resend returned HTTP ${res.status}`;
146	        } else {
147	            return c.json({ success: false, error: `Unknown channel type: ${channel.channel_type}` }, 400);
148	        }
149	
150	        // Update last delivery stats on the channel
151	        await supabase
152	            .from('alert_notification_channels')
153	            .update({
154	                last_delivery_at: new Date().toISOString(),
155	                last_delivery_ok: ok,
156	                last_delivery_error: errorMessage,
157	            })
158	            .eq('id', channel.id);
159	
160	        return c.json({ success: ok, error: errorMessage, http_status: status }, 200);
161	    } catch (err: any) {
162	        return c.json({ success: false, error: err.message ?? 'Delivery failed' }, 200);
163	    }
164	});
