11	
12	export const triggerTrainingRoute = new Hono();
13	
14	triggerTrainingRoute.post('/', async (c) => {
15	    // 1. Checks training readiness
16	    const { count: outcomeCount } = await supabase
17	        .from('fact_outcomes')
18	        .select('*', { count: 'exact', head: true });
19	
20	    const { count: sequenceCount } = await supabase
21	        .from('action_sequences')
22	        .select('*', { count: 'exact', head: true })
23	        .eq('status', 'closed');
24	
25	    const { data: model } = await supabase
26	        .from('world_model_artifacts')
27	        .select('version, trained_at')
28	        .eq('is_active', true)
29	        .order('trained_at', { ascending: false })
30	        .limit(1)
31	        .maybeSingle();
32	
33	    const readyForTier2 = (outcomeCount || 0) >= 200;
34	    const readyForTier3 = (outcomeCount || 0) >= 1000;
35	
36	    let trainingRecommended = false;
37	    let reason = '';
38	
39	    if (!model && readyForTier2) {
40	        trainingRecommended = true;
41	        reason = `${outcomeCount || 0} outcomes available, no model trained yet`;
42	    } else if (model) {
43	        const days = Math.floor((Date.now() - new Date(model.trained_at).getTime()) / (1000 * 60 * 60 * 24));
44	        if (days >= 7) {
45	            trainingRecommended = true;
46	            reason = `Model trained ${days} days ago`;
47	        } else {
48	            reason = `Model trained recently (${days} days ago)`;
49	        }
50	    } else {
51	        reason = `Not enough outcomes (${outcomeCount || 0}/200) for Tier 2 model`;
52	    }
53	
54	    const report = {
55	        outcome_count: outcomeCount || 0,
56	        sequence_count: sequenceCount || 0,
57	        ready_for_tier2: readyForTier2,
58	        ready_for_tier3: readyForTier3,
59	        active_model_version: model?.version || null,
60	        active_model_trained_at: model?.trained_at || null,
61	        training_recommended: trainingRecommended,
62	        reason: reason
63	    };
64	
65	    const action = c.req.query('action');
66	    if (action === 'trigger') {
67	        const webhookUrl = process.env.TRAINING_WEBHOOK_URL;
68	        if (!webhookUrl) {
69	            return c.json({
70	                ...report,
71	                triggered: false,
72	                message: "Set TRAINING_WEBHOOK_URL env var to enable remote training triggers. Run training/train_world_model.py manually or set up Cloud Run scheduled job (see training/DEPLOY.md)."
73	            }, 200);
74	        }
75	
76	        try {
77	            const res = await fetch(webhookUrl, {
78	                method: 'POST',
79	                headers: { 'Content-Type': 'application/json' },
80	            });
81	
82	            if (!res.ok) {
83	                return c.json({
84	                    ...report,
85	                    triggered: false,
86	                    error: 'Training webhook returned non-2xx status',
87	                    status: res.status,
88	                }, 502);
89	            }
90	
91	            return c.json({
92	                ...report,
93	                triggered: true,
94	                job_id: 'dispatched via webhook'
95	            }, 200);
96	        } catch (err: any) {
97	            return c.json({ error: 'Failed to trigger training webhook', details: err.message }, 500);
98	        }
99	    }
100	
101	    return c.json(report, 200);
102	});
