1	/**
2	 * Layerinfinite — routes/auth/api-keys.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * API key management for authenticated human users.
5	 *
6	 * GET    /  → List customer's API keys (prefix only, never full key)
7	 * POST   /  → Generate new API key (returns full key ONCE)
8	 * DELETE /:key_id → Deactivate an API key (soft delete for audit trail)
9	 *
10	 * Auth: Supabase JWT via userAuthMiddleware (NOT agent API key auth).
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Hono } from 'hono';
15	import { z } from 'zod';
16	import { supabase } from '../../lib/supabase.js';
17	
18	export const apiKeysRouter = new Hono();
19	
20	/**
21	 * Generate a cryptographically random API key.
22	 * Format: layerinfinite_<32 random hex chars>
23	 */
24	function generateApiKey(): string {
25	    const bytes = new Uint8Array(16);
26	    crypto.getRandomValues(bytes);
27	    const hex = Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
28	    return `layerinfinite_${hex}`;
29	}
30	
31	/**
32	 * Hash an API key for storage.
33	 * Uses SHA-256 — same key always produces the same hash.
34	 */
35	async function hashApiKey(key: string): Promise<string> {
36	    const encoder = new TextEncoder();
37	    const data = encoder.encode(key);
38	    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
39	    const hashArray = Array.from(new Uint8Array(hashBuffer));
40	    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
41	}
42	
43	// ── Schema ────────────────────────────────────────────────────
44	const CreateKeyBody = z.object({
45	    name: z.string().min(1).max(255),
46	});
47	
48	// ── GET / — list all keys for customer ────────────────────────
49	apiKeysRouter.get('/', async (c) => {
50	    const customerId = c.get('customer_id') as string;
51	
52	    const { data, error } = await supabase
53	        .from('dim_agents')
54	        .select('agent_id, agent_name, api_key_hash, is_active, created_at')
55	        .eq('customer_id', customerId)
56	        .order('created_at', { ascending: false });
57	
58	    if (error) {
59	        return c.json({ error: 'Failed to fetch API keys', details: error.message }, 500);
60	    }
61	
62	    const keys = (data ?? []).map(row => ({
63	        key_id: row.agent_id,
64	        name: row.agent_name,
65	        prefix: row.api_key_hash ? row.api_key_hash.slice(0, 8) + '...' : null,
66	        is_active: row.is_active,
67	        created_at: row.created_at,
68	    }));
69	
70	    return c.json({ keys });
71	});
72	
73	// ── POST / — generate new API key ────────────────────────────
74	apiKeysRouter.post('/', async (c) => {
75	    const customerId = c.get('customer_id') as string;
76	
77	    let body: z.infer<typeof CreateKeyBody>;
78	    try {
79	        body = CreateKeyBody.parse(await c.req.json());
80	    } catch (err: any) {
81	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
82	    }
83	
84	    // Generate the key
85	    const plainKey = generateApiKey();
86	    const keyHash = await hashApiKey(plainKey);
87	
88	    // Create a dim_agents record for this key
89	    const { data, error } = await supabase
90	        .from('dim_agents')
91	        .insert({
92	            agent_name: body.name,
93	            agent_type: 'api-key',
94	            customer_id: customerId,
95	            api_key_hash: keyHash,
96	            is_active: true,
97	        })
98	        .select('agent_id, agent_name, created_at')
99	        .single();
100	
101	    if (error) {
102	        return c.json({ error: 'Failed to create API key', details: error.message }, 500);
103	    }
104	
105	    // Return the full key ONCE — it is never stored or retrievable again
106	    return c.json({
107	        key: plainKey,
108	        key_id: data.agent_id,
109	        name: data.agent_name,
110	        api_key: plainKey,
111	        agent_id: data.agent_id,
112	        agent_name: data.agent_name,
113	        created_at: data.created_at,
114	        warning: 'Save this API key now — it cannot be shown again. This is the only credential you need. Never hardcode agent_id or customer_id in your application.',
115	    }, 201);
116	});
117	
118	// ── DELETE /:key_id — deactivate an API key ───────────────────
119	apiKeysRouter.delete('/:key_id', async (c) => {
120	    const customerId = c.get('customer_id') as string;
121	    const keyId = c.req.param('key_id');
122	
123	    // Verify the key belongs to this customer before deactivating
124	    const { data: existing, error: lookupError } = await supabase
125	        .from('dim_agents')
126	        .select('agent_id, customer_id, is_active')
127	        .eq('agent_id', keyId)
128	        .maybeSingle();
129	
130	    if (lookupError) {
131	        return c.json({ error: 'Failed to look up key', details: lookupError.message }, 500);
132	    }
133	
134	    if (!existing) {
135	        return c.json({ error: 'API key not found', code: 'NOT_FOUND' }, 404);
136	    }
137	
138	    if (existing.customer_id !== customerId) {
139	        return c.json({ error: 'API key not found', code: 'NOT_FOUND' }, 404);
140	    }
141	
142	    if (!existing.is_active) {
143	        return c.json({ error: 'API key is already deactivated', code: 'ALREADY_DEACTIVATED' }, 409);
144	    }
145	
146	    // Soft deactivate — preserve audit trail
147	    const { error: updateError } = await supabase
148	        .from('dim_agents')
149	        .update({ is_active: false })
150	        .eq('agent_id', keyId);
151	
152	    if (updateError) {
153	        return c.json({ error: 'Failed to deactivate key', details: updateError.message }, 500);
154	    }
155	
156	    // After successful deletion from Supabase:
157	    const { invalidateAuthCacheByAgentId } = await import('../../middleware/auth.js');
158	    invalidateAuthCacheByAgentId(keyId);
159	    // This gives instant revocation for the 
160	    // current API server instance.
161	    // Note: Does not invalidate cache on OTHER 
162	    // server instances (if horizontally scaled).
163	    // 60s TTL is the safety net for that case.
164	
165	    return c.json({ success: true, key_id: keyId, message: 'API key deactivated' });
166	});
