1	/**
2	 * Layerinfinite — routes/get-patterns.ts
3	 * GET /v1/get-patterns
4	 * ══════════════════════════════════════════════════════════════
5	 * Returns the most successful action sequences (episodes)
6	 * for a given context. Powers "pattern-based recommendations"
7	 * which go beyond single-action scoring by returning whole
8	 * playbooks (ordered sequences of actions that resolved issues).
9	 * Reads from mv_episode_patterns (refreshed nightly).
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const getPatternsRouter = new Hono();
17	
18	// ── GET /v1/get-patterns ──────────────────────────────────────
19	getPatternsRouter.get('/', async (c) => {
20	    const customerId = c.get('customer_id') as string;
21	
22	    const issueType = c.req.query('issue_type');
23	    const contextId = c.req.query('context_id');
24	    const minSamples = parseInt(c.req.query('min_samples') ?? '2', 10);
25	    const topN = parseInt(c.req.query('top_n') ?? '5', 10);
26	
27	    if (!issueType && !contextId) {
28	        return c.json(
29	            { error: 'Provide either issue_type or context_id', code: 'MISSING_PARAM' },
30	            400
31	        );
32	    }
33	
34	    // ── Resolve context_id ────────────────────────────────────
35	    let resolvedContextId = contextId;
36	
37	    if (!resolvedContextId && issueType) {
38	        const { data, error } = await supabase
39	            .from('dim_contexts')
40	            .select('context_id')
41	            .eq('issue_type', issueType)
42	            .limit(1)
43	            .maybeSingle();
44	
45	        if (error) {
46	            return c.json({ error: 'Context lookup failed', details: error.message }, 500);
47	        }
48	        if (!data) {
49	            return c.json(
50	                {
51	                    patterns: [],
52	                    total_found: 0,
53	                    context_id: null,
54	                    issue_type: issueType,
55	                    message: `No patterns yet for "${issueType}". Patterns appear after 2+ complete episodes.`,
56	                    cold_start: true,
57	                },
58	                200
59	            );
60	        }
61	        resolvedContextId = data.context_id;
62	    }
63	
64	    // ── Fetch patterns from materialized view ─────────────────
65	    const { data: patterns, error } = await supabase
66	        .from('mv_episode_patterns')
67	        .select('*')
68	        .eq('customer_id', customerId)
69	        .eq('context_id', resolvedContextId)
70	        .gte('sample_count', minSamples)
71	        .gte('episode_success_rate', 0.5)     // only show patterns with >50% success
72	        .order('episode_success_rate', { ascending: false })
73	        .limit(Math.min(topN, 20));
74	
75	    if (error) {
76	        return c.json({ error: 'Pattern query failed', details: error.message, code: 'DB_ERROR' }, 500);
77	    }
78	
79	    if (!patterns || patterns.length === 0) {
80	        return c.json({
81	            patterns: [],
82	            total_found: 0,
83	            context_id: resolvedContextId,
84	            issue_type: issueType ?? null,
85	            message: 'No patterns found yet. Patterns appear after 2+ complete episodes with shared action sequences.',
86	            cold_start: true,
87	        }, 200);
88	    }
89	
90	    // ── Enrich action_sequence with names ─────────────────────
91	    // action_sequence is stored as [{action_id, success, ...}, ...]
92	    // Batch-resolve action names from dim_actions
93	    const allActionIds = new Set<string>();
94	    patterns.forEach((p: any) => {
95	        const seq = p.action_sequence ?? [];
96	        seq.forEach((step: any) => {
97	            if (step?.action_id) allActionIds.add(step.action_id);
98	        });
99	    });
100	
101	    let actionNameMap: Record<string, string> = {};
102	    if (allActionIds.size > 0) {
103	        const { data: actions } = await supabase
104	            .from('dim_actions')
105	            .select('action_id, action_name')
106	            .in('action_id', Array.from(allActionIds));
107	
108	        if (actions) {
109	            actionNameMap = Object.fromEntries(actions.map((a: any) => [a.action_id, a.action_name]));
110	        }
111	    }
112	
113	    const enriched = patterns.map((p: any) => ({
114	        context_id: p.context_id,
115	        customer_id: p.customer_id,
116	        episode_success_rate: p.episode_success_rate,
117	        avg_duration_ms: p.avg_duration_ms,
118	        sample_count: p.sample_count,
119	        last_seen_at: p.last_seen_at,
120	        view_refreshed_at: p.view_refreshed_at,
121	        action_sequence: (p.action_sequence ?? []).map((step: any) => ({
122	            ...step,
123	            action_name: actionNameMap[step?.action_id] ?? step?.action_id,
124	        })),
125	    }));
126	
127	    return c.json({
128	        patterns: enriched,
129	        total_found: enriched.length,
130	        context_id: resolvedContextId,
131	        issue_type: issueType ?? null,
132	        cold_start: false,
133	    });
134	});
