1	/**
2	 * Layerinfinite — routes/simulate.ts
3	 * POST /v1/simulate
4	 * ══════════════════════════════════════════════════════════════
5	 * Public API for the 3-tier simulation engine.
6	 * Accepts proposed sequences, returns predictions with
7	 * confidence intervals and tier metadata.
8	 *
9	 * Auth: same API key middleware as other /v1 endpoints.
10	 * Rate limited by customer tier.
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Hono } from 'hono';
15	import { z } from 'zod';
16	import { runSimulation } from '../lib/simulation/tier-selector.js';
17	import { supabase } from '../lib/supabase.js';
18	
19	export const simulateRouter = new Hono();
20	
21	// ── Request validation schema ─────────────────────────────────
22	const SimulateBody = z.object({
23	  agent_id: z.string().min(1),
24	  context: z.record(z.string(), z.unknown()),
25	  proposed_sequence: z.array(z.string().min(1)).min(1).max(5),
26	  episode_history: z.array(z.string()).optional().default([]),
27	  simulate_alternatives: z.number().int().min(0).max(3).optional().default(2),
28	  max_sequence_depth: z.number().int().min(1).max(5).optional().default(5),
29	});
30	
31	/**
32	 * Compute a deterministic context hash from a context object.
33	 * Matches the pattern used in get-scores.ts / log-outcome.ts:
34	 *   context_hash = `${context_id}:${issue_type}`
35	 *
36	 * For simulation we use a simplified stable-sorted JSON hash.
37	 */
38	function computeContextHash(context: Record<string, unknown>): string {
39	  // Use issue_type if present (most common pattern)
40	  const issueType = context.issue_type ?? context.context_type ?? '';
41	  const contextId = context.context_id ?? '';
42	  if (contextId) {
43	    return `${contextId}:${issueType}`;
44	  }
45	  // Fallback: stable JSON key — deterministic across calls
46	  const keys = Object.keys(context).sort();
47	  const stable = keys.map((k) => `${k}=${JSON.stringify(context[k])}`).join('|');
48	  return stable;
49	}
50	
51	// ── POST /v1/simulate ─────────────────────────────────────────
52	simulateRouter.post('/', async (c) => {
53	  // Parse and validate body
54	  let body: z.infer<typeof SimulateBody>;
55	  try {
56	    const raw = await c.req.json();
57	    body = SimulateBody.parse(raw);
58	  } catch (err: any) {
59	    return c.json(
60	      {
61	        error: 'Invalid request body',
62	        details: err.errors ?? err.message,
63	        code: 'VALIDATION_ERROR',
64	        agent_id: '',
65	      },
66	      400,
67	    );
68	  }
69	
70	  const {
71	    agent_id,
72	    context,
73	    proposed_sequence,
74	    episode_history,
75	    simulate_alternatives,
76	    max_sequence_depth,
77	  } = body;
78	
79	  const customerId = c.get('customer_id') as string;
80	
81	  if (!customerId) {
82	    return c.json({ error: 'Missing agent context', code: 'MISSING_AGENT', agent_id: '' }, 401);
83	  }
84	
85	  const { data: agentRow, error: agentLookupError } = await supabase
86	    .from('dim_agents')
87	    .select('agent_id')
