2	 * Layerinfinite — routes/audit.ts
3	 * GET /v1/audit
4	 * ══════════════════════════════════════════════════════════════
5	 * Immutable audit trail for compliance teams.
6	 * Returns a paginated list of logged outcomes (fact_outcomes)
7	 * with filtering by session, action, time range.
8	 * ALL data is read-only. No mutations possible.
9	 * GDPR: soft-deleted rows (is_deleted=TRUE) are excluded.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const auditRouter = new Hono();
17	
18	const MAX_PAGE_SIZE = 100;
19	const DEFAULT_PAGE_SIZE = 50;
20	
21	function csvEscape(value: unknown): string {
22	    const text = value == null ? '' : String(value);
23	    return /[",\r\n]/.test(text)
24	        ? `"${text.replace(/"/g, '""')}"`
25	        : text;
26	}
27	
28	// ── GET /v1/audit ─────────────────────────────────────────────
29	auditRouter.get('/', async (c) => {
30	    const customerId = c.get('customer_id') as string;
31	
32	    const sessionId = c.req.query('session_id');
33	    const actionName = c.req.query('action_name');
34	    const agentId = c.req.query('agent_id');
35	    const success = c.req.query('success');     // 'true' | 'false' | undefined
36	    const from = c.req.query('from');         // ISO date string
37	    const to = c.req.query('to');           // ISO date string
38	    const format = (c.req.query('format') ?? '').toLowerCase();
39	    const cursor = c.req.query('cursor');
40	    const pageStr = c.req.query('page');
41	    const offsetStr = c.req.query('offset');
42	    const sizeStr = c.req.query('page_size') ?? c.req.query('limit') ?? String(DEFAULT_PAGE_SIZE);
43	
44	    const page = Math.max(1, parseInt(pageStr ?? '1', 10) || 1);
45	    const pageSize = Math.min(MAX_PAGE_SIZE, Math.max(1, parseInt(sizeStr, 10) || DEFAULT_PAGE_SIZE));
46	
47	    // ── Build query ───────────────────────────────────────────
48	    let query = supabase
49	        .from('fact_outcomes')
50	        .select(`
51	      outcome_id,
52	      session_id,
53	      timestamp,
54	      success,
55	    execution_status,
56	    failure_reason_code,
57	    failure_stage,
58	    status_origin,
59	      response_time_ms,
60	      error_code,
61	      error_message,
62	      is_synthetic,
63	      salience_score,
64	      dim_agents!inner(agent_id, agent_name, agent_type),
65	      dim_actions!inner(action_id, action_name, action_category),
66	      dim_contexts!inner(context_id, issue_type, environment)
67	    `, { count: 'exact' })
68	        .eq('customer_id', customerId)
69	        .eq('is_deleted', false)           // GDPR: exclude soft-deleted
70	        .order('timestamp', { ascending: false })
71	        .order('outcome_id', { ascending: false })  // secondary sort: stable pagination across tied timestamps
72	        .limit(pageSize);
73	
74	    if (cursor) {
75	        try {
76	            const { ts, id } = JSON.parse(Buffer.from(cursor, 'base64').toString('utf-8'));
77	            // Validate before interpolation to prevent PostgREST filter injection.
78	            // ts must be an ISO 8601 timestamp; id must be a UUID.
79	            const ISO_TS = /^\d{4}-\d{2}-\d{2}T[\d:.]+(?:Z|[+-]\d{2}:\d{2})?$/;
80	            const UUID = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
81	            if (typeof ts !== 'string' || typeof id !== 'string' || !ISO_TS.test(ts) || !UUID.test(id)) {
82	                throw new Error('invalid cursor shape');
83	            }
84	            // Composite row-value comparison (descending): skip rows at or before the cursor position.
85	            // Handles ties at page boundaries: same timestamp rows are ordered by outcome_id descending.
86	            query = query.or(`timestamp.lt.${ts},and(timestamp.eq.${ts},outcome_id.lt.${id})`);
87	        } catch {
88	            // Malformed or invalid cursor — ignore and return from the beginning
89	        }
90	    } else if (pageStr || offsetStr) {
91	        // Fallback for legacy offset pagination
92	        const offset = offsetStr ? parseInt(offsetStr, 10) : (page - 1) * pageSize;
93	        if (!isNaN(offset)) {
94	            query = query.range(offset, offset + pageSize - 1);
95	        }
96	    }
97	
98	    // ── Apply filters ─────────────────────────────────────────
99	    if (sessionId) query = query.eq('session_id', sessionId);
100	    if (agentId) query = query.eq('agent_id', agentId);
101	    if (success !== undefined) {
102	        query = query.eq('success', success === 'true');
103	    }
104	    if (from) query = query.gte('timestamp', from);
105	    if (to) query = query.lte('timestamp', to);
106	
107	    // Filter by action_name (via joined table)
108	    if (actionName) {
109	        // Supabase supports filtering on joined tables
110	        query = (query as any).eq('dim_actions.action_name', actionName);
111	    }
112	
113	    const { data, error, count } = await query;
114	
115	    if (error) {
116	        console.error('[audit] Query error:', error.message);
117	        return c.json({ error: 'Audit query failed', details: error.message, code: 'DB_ERROR' }, 500);
118	    }
119	
120	    const totalPages = Math.ceil((count ?? 0) / pageSize);
121	    // hasMore is true only when we filled a full page AND the DB has more rows beyond it.
122	    // Avoids false positives when total rows is an exact multiple of pageSize.
123	    const hasMore = (data?.length ?? 0) === pageSize && (count ?? 0) > (data?.length ?? 0);
124	    const lastRow = hasMore ? data![data!.length - 1] : null;
125	    const nextCursor = (lastRow?.timestamp && lastRow?.outcome_id)
126	        ? Buffer.from(JSON.stringify({ ts: lastRow.timestamp, id: lastRow.outcome_id })).toString('base64')
127	        : null;
128	
129	    const outcomes = (data ?? []).map((row: any) => ({
130	        outcome_id: row.outcome_id,
131	        session_id: row.session_id,
132	        timestamp: row.timestamp,
133	        success: row.success,
134	        execution_status: row.execution_status ?? null,
135	        failure_reason_code: row.failure_reason_code ?? null,
136	        failure_stage: row.failure_stage ?? null,
137	        status_origin: row.status_origin ?? null,
138	        response_time_ms: row.response_time_ms,
139	        error_code: row.error_code,
140	        error_message: row.error_message,
141	        is_synthetic: row.is_synthetic,
142	        salience_score: row.salience_score,
143	        agent: row.dim_agents ? {
144	            id: row.dim_agents.agent_id,
145	            name: row.dim_agents.agent_name,
146	            type: row.dim_agents.agent_type,
147	        } : null,
148	        action: row.dim_actions ? {
149	            id: row.dim_actions.action_id,
150	            name: row.dim_actions.action_name,
151	            category: row.dim_actions.action_category,
152	        } : null,
153	        context: row.dim_contexts ? {
154	            id: row.dim_contexts.context_id,
155	            issue_type: row.dim_contexts.issue_type,
156	            environment: row.dim_contexts.environment,
157	        } : null,
158	    }));
159	
160	    if (format === 'csv') {
161	        const headers = [
162	            'outcome_id',
163	            'session_id',
164	            'timestamp',
165	            'success',
166	            'execution_status',
167	            'failure_reason_code',
168	            'failure_stage',
169	            'status_origin',
170	            'response_time_ms',
171	            'error_code',
172	            'error_message',
173	            'is_synthetic',
174	            'salience_score',
175	            'agent_id',
176	            'agent_name',
177	            'agent_type',
178	            'action_id',
179	            'action_name',
180	            'action_category',
181	            'context_id',
182	            'issue_type',
183	            'environment',
184	        ];
185	
186	        const rows = outcomes.map((o) => [
187	            o.outcome_id,
188	            o.session_id,
189	            o.timestamp,
190	            o.success,
191	            (o as any).execution_status,
192	            (o as any).failure_reason_code,
193	            (o as any).failure_stage,
194	            (o as any).status_origin,
195	            o.response_time_ms,
196	            o.error_code,
197	            o.error_message,
198	            o.is_synthetic,
199	            o.salience_score,
200	            o.agent?.id,
201	            o.agent?.name,
202	            o.agent?.type,
203	            o.action?.id,
204	            o.action?.name,
205	            o.action?.category,
206	            o.context?.id,
207	            o.context?.issue_type,
208	            o.context?.environment,
209	        ].map(csvEscape).join(','));
210	
211	        const csv = [headers.join(','), ...rows].join('\n');
212	        const fileDate = new Date().toISOString().slice(0, 10);
213	
214	        c.header('Content-Type', 'text/csv; charset=utf-8');
215	        c.header('Content-Disposition', `attachment; filename="layerinfinite-audit-${fileDate}.csv"`);
216	        c.header('Cache-Control', 'no-store');
217	        return c.body(csv, 200);
218	    }
219	
220	    return c.json({
221	        outcomes,
222	        pagination: {
223	            page,
224	            page_size: pageSize,
225	            total_rows: count ?? 0,
226	            total_pages: totalPages,
227	            has_next: page < totalPages,
228	            has_prev: page > 1,
229	            // Keyset fields
230	            next_cursor: nextCursor,
231	            has_more: hasMore,
232	        },
233	        pagination_warning: (pageStr || offsetStr) ? 'page/offset parameters deprecated. Use cursor.' : undefined,
234	        filters: {
235	            session_id: sessionId ?? null,
236	            action_name: actionName ?? null,
237	            agent_id: agentId ?? null,
238	            success: success ?? null,
239	            from: from ?? null,
240	            to: to ?? null,
241	        },
242	        note: 'This audit trail is immutable. All rows reflect append-only fact_outcomes.',
243	    });
244	});
245	
246	// ── GET /v1/audit/:outcome_id — Single outcome detail ─────────
247	auditRouter.get('/:outcome_id', async (c) => {
248	    const customerId = c.get('customer_id') as string;
249	    const outcomeId = c.req.param('outcome_id');
250	
251	    const { data, error } = await supabase
252	        .from('fact_outcomes')
253	        .select(`
254	      *,
255	      dim_agents!inner(agent_id, agent_name, agent_type, llm_model),
256	      dim_actions!inner(action_id, action_name, action_category, action_description),
257	      dim_contexts!inner(context_id, issue_type, environment, customer_tier)
258	    `)
259	        .eq('outcome_id', outcomeId)
260	        .eq('customer_id', customerId)
261	        .eq('is_deleted', false)
262	        .maybeSingle();
263	
264	    if (error) {
265	        return c.json({ error: 'Query failed', details: error.message }, 500);
266	    }
267	    if (!data) {
268	        return c.json({ error: `Outcome ${outcomeId} not found`, code: 'NOT_FOUND' }, 404);
269	    }
270	
271	    return c.json({ outcome: data });
272	});
