1	/**
2	 * Layerinfinite — routes/outcome-feedback.ts
3	 * POST /v1/outcome-feedback
4	 * ══════════════════════════════════════════════════════════════
5	 * Accepts delayed outcome feedback — submitted hours/days after
6	 * the original outcome was logged.
7	 *
8	 * This is the ONE permitted UPDATE path on fact_outcomes.
9	 * It updates reconciliation fields (score, business_outcome,
10	 * feedback timestamps, pending/cross-event state, and
11	 * execution-status trace metadata). All identity fields remain immutable.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Hono } from 'hono';
16	import { z } from 'zod';
17	import { supabase } from '../lib/supabase.js';
18	import { invalidateCache } from '../lib/scoring.js';
19	import { invalidateActionBaselineCache } from '../lib/outcome-score-inference.js';
20	
21	export const outcomeFeedbackRouter = new Hono();
22	
23	const FeedbackBody = z.object({
24	    outcome_id: z.string().uuid(),
25	    final_score: z.number().min(0.0).max(1.0),
26	    // Any string is accepted. Values are normalized to the four canonical
27	    // labels at the application layer. Unknown values map to 'unknown'.
28	    // Field is metadata-only — never read by scoring, trust, or policy.
29	    business_outcome: z
30	        .string()
31	        .min(1)
32	        .max(100)
33	        .transform(val => {
34	            const normalized = val.trim().toLowerCase();
35	            const known = ['resolved', 'partial', 'failed', 'unknown'] as const;
36	            return (known as readonly string[]).includes(normalized)
37	                ? (normalized as typeof known[number])
38	                : 'unknown';
39	        }),
40	    feedback_notes: z.string().max(2000).optional(),
41	});
42	
43	outcomeFeedbackRouter.post('/', async (c) => {
44	    const customerId = c.get('customer_id') as string;
45	
46	    let body: z.infer<typeof FeedbackBody>;
47	    try {
48	        body = FeedbackBody.parse(await c.req.json());
49	    } catch (err: any) {
50	        return c.json(
51	            { error: 'Invalid request body', details: err.errors ?? err.message, code: 'VALIDATION_ERROR' },
52	            400
53	        );
54	    }
55	
56	    // ── Verify outcome belongs to this customer ──────────────
57	    const { data: outcome, error: lookupErr } = await supabase
58	        .from('fact_outcomes')
59	        .select('outcome_id, customer_id, context_id, success, signal_pending, cross_event_status, action_id, agent_id')
60	        .eq('outcome_id', body.outcome_id)
61	        .maybeSingle();
62	
63	    if (lookupErr) {
64	        return c.json({ error: 'Lookup failed', details: lookupErr.message }, 500);
65	    }
66	
67	    if (!outcome || outcome.customer_id !== customerId) {
68	        return c.json({ error: 'Outcome not found', code: 'NOT_FOUND' }, 404);
69	    }
70	
71	    // ── Insert feedback record ───────────────────────────────
72	    const { error: feedbackErr } = await supabase
73	        .from('fact_outcome_feedback')
74	        .insert({
75	            outcome_id: body.outcome_id,
76	            customer_id: customerId,
77	            final_score: body.final_score,
78	            business_outcome: body.business_outcome,
79	            feedback_notes: body.feedback_notes ?? null,
80	        });
81	
82	    if (feedbackErr) {
83	        return c.json({ error: 'Failed to store feedback', details: feedbackErr.message }, 500);
84	    }
85	
86	    // ── Update fact_outcomes with final score ────────────────
87	    // This is the ONE permitted UPDATE on fact_outcomes.
88	    // The prevent_outcome_update trigger enforces append-only semantics for
89	    // identity columns while allowing the reconciliation field set below.
90	    const feedbackSignalsSuccess = body.final_score >= 0.5;
91	    const executionStatus = feedbackSignalsSuccess ? 'COMPLETED' : 'FAILED';
92	    const failureReasonCode = executionStatus === 'FAILED'
93	        ? 'delayed_feedback_failed'
94	        : null;
95	    const failureStage = executionStatus === 'FAILED'
96	        ? 'delayed_feedback'
97	        : null;
98	    const crossEventStatus = outcome.signal_pending === true
99	        ? (outcome.success === feedbackSignalsSuccess ? 'confirmed' : 'conflict')
100	        : (outcome.success === feedbackSignalsSuccess ? 'resolved' : 'conflict');
101	    const nowIso = new Date().toISOString();
102	
103	    const { error: updateErr } = await supabase
104	        .from('fact_outcomes')
105	        .update({
106	            outcome_score: body.final_score,
107	            business_outcome: body.business_outcome,
108	            feedback_received_at: nowIso,
109	            signal_pending: false,
110	            signal_updated_at: nowIso,
111	            cross_event_status: crossEventStatus,
112	            cross_event_last_updated: nowIso,
113	            execution_status: executionStatus,
114	            failure_reason_code: failureReasonCode,
115	            failure_stage: failureStage,
116	            status_origin: 'reconciled_feedback',
117	        })
118	        .eq('outcome_id', body.outcome_id)
119	        .eq('customer_id', customerId);
120	
121	    if (updateErr) {
122	        return c.json({ error: 'Failed to update outcome', details: updateErr.message }, 500);
123	    }
124	
125	    // ── Trigger score cache refresh (async, non-blocking) ────
126	    invalidateCache(customerId, outcome.context_id);
127	    invalidateActionBaselineCache(outcome.agent_id ?? undefined, outcome.action_id ?? undefined);
128	
129	    const { error: resolvePendingError } = await supabase
130	        .from('dim_pending_signal_registrations')
131	        .update({
132	            resolved: true,
133	            resolved_at: nowIso,
134	            resolved_by: 'outcome_feedback',
135	        })
136	        .eq('customer_id', customerId)
137	        .eq('outcome_id', body.outcome_id)
138	        .eq('resolved', false);
139	
140	    if (resolvePendingError) {
141	        console.warn('[outcome-feedback] failed to resolve pending registrations:', resolvePendingError.message);
142	    }
143	
144	    if (crossEventStatus === 'conflict') {
145	        const { data: existingConflict } = await supabase
146	            .from('dim_discrepancy_log')
147	            .select('discrepancy_id')
148	            .eq('customer_id', customerId)
149	            .eq('outcome_id', body.outcome_id)
150	            .eq('discrepancy_type', 'cross_event_conflict')
151	            .eq('resolved', false)
152	            .limit(1);
153	
154	        if (!existingConflict || existingConflict.length === 0) {
155	            await supabase
156	                .from('dim_discrepancy_log')
157	                .insert({
158	                    customer_id: customerId,
159	                    outcome_id: body.outcome_id,
160	                    action_name: `action:${outcome.action_id ?? 'unknown'}`,
161	                    discrepancy_type: 'cross_event_conflict',
162	                    expected_outcome: outcome.success,
163	                    actual_outcome: feedbackSignalsSuccess,
164	                    signal_confidence: body.final_score,
165	                    detail:
166	                        'Delayed feedback contradicted initial outcome polarity. ' +
167	                        `initial_success=${String(outcome.success)} final_score=${body.final_score.toFixed(4)}.`,
168	                    reason_code: 'cross_event_feedback_conflict',
169	                    trace_reason_code: 'cross_event_feedback_conflict',
170	                    trace_stage: 'delayed_feedback',
171	                    trace_gate: 'cross_event_status_conflict',
172	                    source_execution_status: executionStatus,
173	                    source_status_origin: 'reconciled_feedback',
174	                    source_failure_reason_code: failureReasonCode,
175	                    source_failure_stage: failureStage,
176	                    trace_payload: {
177	                        initial_success: outcome.success,
178	                        final_score: body.final_score,
179	                        signal_pending_before_feedback: outcome.signal_pending === true,
180	                    },
181	                    trace_context: {
182	                        initial_success: outcome.success,
183	                        final_score: body.final_score,
184	                        signal_pending_before_feedback: outcome.signal_pending === true,
185	                    },
186	                });
187	        }
188	    }
189	
190	    // ── DELAYED SILENT FAILURE DETECTION (Gap 5) ─────────────
191	    // Original outcome was success=true but feedback shows low score.
192	    (async () => {
193	        const { data: original } = await supabase
194	            .from('fact_outcomes')
195	            .select('success, action_id, agent_id')
196	            .eq('outcome_id', body.outcome_id)
197	            .single();
198	
199	        const isDelayedSilentFailure =
200	            original?.success === true &&
201	            body.final_score < 0.3;
202	
203	        if (isDelayedSilentFailure) {
204	            await supabase.from('degradation_alert_events').insert({
205	                customer_id: customerId,
206	                action_id: original.action_id,
207	                alert_type: 'degradation',
208	                severity: 'warning',
209	                current_value: body.final_score,
210	                baseline_value: 1.0,
211	                message: `Delayed silent failure confirmed: "${body.business_outcome}" — originally logged as success, final score: ${body.final_score}. ${body.feedback_notes || ''}`,
212	            });
213	        }
214	    })().catch(err => {
215	        console.warn('[outcome-feedback] Delayed silent failure check failed:', err);
216	    });
217	
218	    return c.json({
219	        updated: true,
220	        outcome_id: body.outcome_id,
221	        final_score: body.final_score,
222	        business_outcome: body.business_outcome,
223	        execution_status: executionStatus,
224	        failure_reason_code: failureReasonCode,
225	        failure_stage: failureStage,
226	        status_origin: 'reconciled_feedback',
227	        cross_event_status: crossEventStatus,
228	        cross_event_conflict: crossEventStatus === 'conflict',
229	    });
230	});
