1	/**
2	 * LAYERINFINITE — routes/import.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Historical log import feature.
5	 *
6	 * POST /v1/import
7	 *   Accepts a JSON/JSONL/CSV file of historical agent outcomes.
8	 *   Runs a synchronous dry-run parse pass (always), then queues
9	 *   an async background job for actual ingestion.
10	 *   Returns immediately with job_id + preview data.
11	 *
12	 * GET /v1/import/:job_id
13	 *   Polls job status. Returns { status, rows_processed, rows_failed, errors }.
14	 *
15	 * Design invariants:
16	 *   - Auth: standard agent API key (same as /v1/log-outcome).
17	 *     customer_id + agent_id always come from the key — never from payload.
18	 *   - ingestion_source = 'import' on all inserted rows.
19	 *   - Trust paths are never triggered for import rows (skipTrust=true).
20	 *   - Idempotency: SHA-256 key per row prevents duplicate inserts on retry.
21	 *   - File cap: 5MB / 10,000 rows.
22	 *   - Async: job runs outside request lifecycle; no timeout risk.
23	 *   - MV refresh: single end-of-batch call (not per-row).
24	 *   - Quality gate: blocks ingestion if avg quality < 0.4.
25	 * ══════════════════════════════════════════════════════════════
26	 */
27	
28	import { Hono } from 'hono';
29	import crypto from 'node:crypto';
30	import { supabase } from '../lib/supabase.js';
31	import {
32	    computeOutcomeDataQuality,
33	    evaluateInconsistencyRules,
34	    ingestOutcome,
35	    resolveTaskName,
36	    type NormalizedOutcomeRow,
37	} from '../lib/ingest-core.js';
38	import { normalizeActionName } from '../middleware/validate-action.js';
39	import { sanitizeString, sanitizeContext } from '../lib/sanitize.js';
40	import { isLangChainTrace, flattenLangChainTrace } from '../lib/adapters/langchain-adapter.js';
41	import { isLangGraphTrace, flattenLangGraphTrace } from '../lib/adapters/langgraph-adapter.js';
42	import { inferSchemaAndMap, standardFieldsPresent } from '../lib/schema-inferrer.js';
43	
44	export const importRouter = new Hono();
45	
46	// ── Constants ─────────────────────────────────────────────────
47	const MAX_FILE_BYTES = 5 * 1024 * 1024; // 5MB
48	const MAX_ROWS = 10_000;
49	const CHUNK_SIZE = 500;               // rows per processing chunk
50	const QUALITY_GATE_BLOCK = 0.40;      // block ingestion entirely below this
51	const QUALITY_GATE_WARN = 0.60;       // warn but allow above this
52	const ENABLE_IMPORT_INFERENCE = ['1', 'true', 'yes', 'on'].includes(
53	    (process.env.LI_IMPORT_ENABLE_INFERENCE ?? '').trim().toLowerCase(),
54	);
55	
56	function parsePositiveInt(raw: string | undefined, fallback: number): number {
57	    const parsed = Number(raw);
58	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
59	    return Math.floor(parsed);
60	}
61	
