132	// ── File parser ───────────────────────────────────────────────
133	
134	/**
135	 * Attempts to recover records from JSON / JSONL / CSV and messy log text.
136	 * Strategy: salvage as much structure as possible instead of hard-failing
137	 * on the first malformed line.
138	 * Never throws — returns { records, error } so the caller can surface
139	 * a clean HTTP error.
140	 */
141	export function parseFileContent(content: string): { records: Record<string, unknown>[]; error?: string } {
142	    const trimmed = content.trim();
143	    if (!trimmed) return { records: [], error: 'File is empty.' };
144	
145	    // 1) Full JSON document parse (array, object, wrapped records).
146	    const jsonDocRecords = parseJsonDocument(trimmed);
147	    if (jsonDocRecords.length > 0) return { records: jsonDocRecords };
148	
149	    // 2) JSON per line / lines containing JSON fragments.
150	    const jsonLineRecords = parseJsonRecordsFromLines(trimmed);
151	    if (jsonLineRecords.length > 0) return { records: jsonLineRecords };
152	
153	    // 3) Embedded JSON object recovery from noisy logs.
154	    const embeddedJsonRecords = extractJsonObjectsFromText(trimmed);
155	    if (embeddedJsonRecords.length > 0) return { records: embeddedJsonRecords };
156	
157	    // 4) Delimited records (CSV/TSV/semicolon/pipe), with or without headers.
158	    const delimitedRecords = parseDelimitedRecords(trimmed);
159	    if (delimitedRecords.length > 0) return { records: delimitedRecords };
160	
161	    // 5) key=value or key:value style log lines.
162	    const kvRecords = parseKeyValueRecords(trimmed);
163	    if (kvRecords.length > 0) return { records: kvRecords };
164	
165	    return {
166	        records: [],
167	        error:
168	            'Could not detect structured records in the file. Include at least action/issue/success fields in JSON, CSV, or log key=value lines.',
169	    };
170	}
171	
172	export function splitCsvLine(line: string): string[] {
173	    return splitDelimitedLine(line, ',');
174	}
175	
176	const JSON_CONTAINER_KEYS = [
177	    'records',
178	    'rows',
179	    'data',
180	    'events',
181	    'logs',
182	    'items',
183	    'results',
184	    'entries',
185	] as const;
186	
187	const DELIMITER_CANDIDATES = [',', ';', '\t', '|'] as const;
188	
189	function normalizeFieldName(raw: string): string {
190	    return raw
191	        .trim()
192	        .replace(/^["']|["']$/g, '')
193	        .toLowerCase()
194	        .replace(/[\s\-]+/g, '_');
195	}
196	
197	function normalizeRecordKeys(record: Record<string, unknown>): Record<string, unknown> {
198	    const normalized: Record<string, unknown> = {};
199	    for (const [key, value] of Object.entries(record)) {
200	        normalized[key] = value;
201	        const canonical = normalizeFieldName(key);
202	        if (!(canonical in normalized)) {
203	            normalized[canonical] = value;
204	        }
205	    }
206	    return normalized;
207	}
208	
209	function isRecordObject(value: unknown): value is Record<string, unknown> {
210	    return typeof value === 'object' && value !== null && !Array.isArray(value);
211	}
212	
213	function toRecords(value: unknown): Record<string, unknown>[] {
214	    if (Array.isArray(value)) {
215	        return value.filter(isRecordObject).map(normalizeRecordKeys);
216	    }
217	
218	    if (!isRecordObject(value)) {
219	        return [];
220	    }
221	
222	    for (const key of JSON_CONTAINER_KEYS) {
223	        const maybeList = value[key];
224	        if (Array.isArray(maybeList)) {
225	            const rows = maybeList.filter(isRecordObject).map(normalizeRecordKeys);
226	            if (rows.length > 0) return rows;
227	        }
228	    }
229	
230	    let largestNestedRows: Record<string, unknown>[] = [];
231	    for (const nested of Object.values(value)) {
232	        if (!Array.isArray(nested)) continue;
233	        const rows = nested.filter(isRecordObject).map(normalizeRecordKeys);
234	        if (rows.length > largestNestedRows.length) {
235	            largestNestedRows = rows;
236	        }
237	    }
238	    if (largestNestedRows.length > 0) return largestNestedRows;
239	
240	    return [normalizeRecordKeys(value)];
241	}
242	
243	function tryParseJson(text: string): unknown | null {
244	    const clean = text.replace(/^\uFEFF/, '').trim();
245	    if (!clean) return null;
246	
247	    try {
248	        return JSON.parse(clean);
249	    } catch {
250	        // Best-effort salvage for trailing commas in arrays/objects.
251	        const relaxed = clean.replace(/,\s*([}\]])/g, '$1');
252	        if (relaxed !== clean) {
253	            try {
254	                return JSON.parse(relaxed);
255	            } catch {
256	                return null;
257	            }
258	        }
259	        return null;
260	    }
261	}
262	
263	function parseJsonDocument(text: string): Record<string, unknown>[] {
264	    const parsed = tryParseJson(text);
265	    if (parsed === null) return [];
266	    return toRecords(parsed);
267	}
268	
269	function parseJsonRecordsFromLines(text: string): Record<string, unknown>[] {
270	    const lines = text
271	        .split(/\r?\n/)
272	        .map((line) => line.trim())
273	        .filter(Boolean);
274	
275	    const rows: Record<string, unknown>[] = [];
276	    for (const line of lines) {
277	        const direct = parseJsonDocument(line);
278	        if (direct.length > 0) {
279	            rows.push(...direct);
280	            continue;
281	        }
282	
283	        const firstBrace = line.indexOf('{');
284	        const lastBrace = line.lastIndexOf('}');
285	        if (firstBrace >= 0 && lastBrace > firstBrace) {
286	            const fragment = line.slice(firstBrace, lastBrace + 1);
287	            const parsedFragment = parseJsonDocument(fragment);
288	            if (parsedFragment.length > 0) {
289	                rows.push(...parsedFragment);
290	            }
291	        }
292	    }
293	    return rows;
294	}
295	
296	function extractJsonObjectsFromText(text: string): Record<string, unknown>[] {
297	    const rows: Record<string, unknown>[] = [];
298	    let depth = 0;
299	    let start = -1;
300	    let inQuotes = false;
301	    let escaped = false;
302	
303	    for (let i = 0; i < text.length; i += 1) {
304	        const ch = text[i];
305	
306	        if (inQuotes) {
307	            if (escaped) {
308	                escaped = false;
309	                continue;
310	            }
311	            if (ch === '\\') {
312	                escaped = true;
313	                continue;
314	            }
315	            if (ch === '"') {
316	                inQuotes = false;
317	            }
318	            continue;
319	        }
320	
321	        if (ch === '"') {
322	            inQuotes = true;
323	            continue;
324	        }
325	
326	        if (ch === '{') {
327	            if (depth === 0) start = i;
328	            depth += 1;
329	            continue;
330	        }
331	
332	        if (ch === '}') {
333	            if (depth === 0) continue;
334	            depth -= 1;
335	            if (depth === 0 && start >= 0) {
336	                const fragment = text.slice(start, i + 1);
337	                const parsed = parseJsonDocument(fragment);
338	                if (parsed.length > 0) rows.push(...parsed);
339	                start = -1;
340	            }
341	        }
342	    }
343	
344	    return rows;
345	}
346	
347	function countDelimiterOutsideQuotes(line: string, delimiter: string): number {
348	    let inQuotes = false;
349	    let count = 0;
350	
351	    for (let i = 0; i < line.length; i += 1) {
352	        const ch = line[i];
353	        if (ch === '"') {
354	            if (inQuotes && line[i + 1] === '"') {
355	                i += 1;
356	                continue;
357	            }
358	            inQuotes = !inQuotes;
359	            continue;
360	        }
361	        if (!inQuotes && ch === delimiter) {
362	            count += 1;
363	        }
364	    }
365	
366	    return count;
367	}
368	
369	function detectDelimiter(lines: string[]): string {
370	    let bestDelimiter = ',';
371	    let bestScore = -1;
372	    const sample = lines.slice(0, 25);
373	
374	    for (const delimiter of DELIMITER_CANDIDATES) {
375	        const score = sample.reduce((sum, line) => sum + countDelimiterOutsideQuotes(line, delimiter), 0);
376	        if (score > bestScore) {
377	            bestScore = score;
378	            bestDelimiter = delimiter;
379	        }
380	    }
381	
382	    return bestDelimiter;
383	}
384	
385	function splitDelimitedLine(line: string, delimiter: string): string[] {
386	    const result: string[] = [];
387	    let current = '';
388	    let inQuotes = false;
389	    for (let i = 0; i < line.length; i += 1) {
390	        const ch = line[i];
391	        if (ch === '"') {
392	            if (inQuotes && line[i + 1] === '"') {
393	                current += '"';
394	                i += 1;
395	                continue;
396	            }
397	            inQuotes = !inQuotes;
398	            continue;
399	        }
400	        if (ch === delimiter && !inQuotes) {
401	            result.push(current.trim());
402	            current = '';
403	            continue;
404	        }
405	        current += ch;
406	    }
407	    result.push(current.trim());
408	    return result.map((v) => v.replace(/^["']|["']$/g, ''));
409	}
410	
411	function looksLikeHeader(values: string[]): boolean {
412	    if (values.length === 0) return false;
413	
414	    const knownFields = new Set([
415	        ...ACTION_FIELDS,
416	        ...ISSUE_FIELDS,
417	        ...SUCCESS_FIELDS,
418	        ...SCORE_FIELDS,
419	        ...TIMESTAMP_FIELDS,
420	        'business_outcome',
421	        'session_id',
422	        'response_time_ms',
423	    ]);
424	
425	    let knownMatches = 0;
426	    for (const v of values) {
427	        if (knownFields.has(normalizeFieldName(v))) {
428	            knownMatches += 1;
429	        }
430	    }
431	    return knownMatches > 0;
432	}
433	
434	function parseDelimitedRecords(text: string): Record<string, unknown>[] {
435	    const lines = text
436	        .split(/\r?\n/)
437	        .map((line) => line.trim())
438	        .filter(Boolean);
439	    if (lines.length === 0) return [];
440	
441	    const delimiter = detectDelimiter(lines);
442	    const firstRow = splitDelimitedLine(lines[0], delimiter);
443	    if (firstRow.length < 2) return [];
444	
445	    const hasHeader = looksLikeHeader(firstRow);
446	    const headers = hasHeader
447	        ? firstRow.map((h) => normalizeFieldName(h))
448	        : firstRow.map((_, idx) => `col_${idx + 1}`);
449	
450	    const startIndex = hasHeader ? 1 : 0;
451	    const rows: Record<string, unknown>[] = [];
452	
453	    for (let i = startIndex; i < lines.length; i += 1) {
454	        const values = splitDelimitedLine(lines[i], delimiter);
455	        if (values.length === 0 || values.every((v) => v.length === 0)) continue;
456	
457	        const width = Math.max(headers.length, values.length);
458	        const row: Record<string, unknown> = {};
459	        for (let col = 0; col < width; col += 1) {
460	            const key = headers[col] ?? `col_${col + 1}`;
461	            row[key] = values[col] ?? '';
462	        }
463	
464	        if (!hasHeader && values.length >= 3) {
465	            if (row.action_name === undefined) row.action_name = values[0];
466	            if (row.issue_type === undefined) row.issue_type = values[1];
467	            if (row.success === undefined) row.success = values[2];
468	            if (values.length >= 4 && row.outcome_score === undefined) row.outcome_score = values[3];
469	            if (values.length >= 5 && row.business_outcome === undefined) row.business_outcome = values[4];
470	        }
471	
472	        rows.push(normalizeRecordKeys(row));
473	    }
474	
475	    return rows;
476	}
477	
478	function stripQuoted(value: string): string {
479	    const trimmed = value.trim();
480	    if (
481	        (trimmed.startsWith('"') && trimmed.endsWith('"'))
482	        || (trimmed.startsWith("'") && trimmed.endsWith("'"))
483	    ) {
484	        return trimmed.slice(1, -1);
485	    }
486	    return trimmed;
487	}
488	
489	function parseKeyValueRecords(text: string): Record<string, unknown>[] {
490	    const lines = text
491	        .split(/\r?\n/)
492	        .map((line) => line.trim())
493	        .filter(Boolean);
494	
495	    const rows: Record<string, unknown>[] = [];
496	    const kvPattern = /([a-zA-Z_][a-zA-Z0-9_.-]*)\s*[:=]\s*("(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*'|[^,\s]+)/g;
497	
498	    for (const line of lines) {
499	        const row: Record<string, unknown> = {};
500	        let match: RegExpExecArray | null;
501	        while ((match = kvPattern.exec(line)) !== null) {
502	            const key = normalizeFieldName(match[1]);
503	            const value = stripQuoted(match[2]);
504	            row[key] = value;
505	        }
506	        if (Object.keys(row).length > 0) {
507	            rows.push(row);
508	        }
509	    }
510	
511	    return rows;
512	}
