514	// ── Field extraction from raw record ─────────────────────────
515	
516	const ACTION_FIELDS = ['action_name', 'action', 'action_taken', 'handler', 'function_name'];
517	const ISSUE_FIELDS = ['issue_type', 'task_type', 'task', 'issue', 'type', 'context', 'category', 'event_type'];
518	const SUCCESS_FIELDS = ['success', 'result', 'outcome', 'status', 'passed', 'succeeded'];
519	const STATUS_FIELDS = ['execution_status', 'run_status', 'result_status'];
520	const SCORE_FIELDS = ['outcome_score', 'score', 'confidence', 'quality'];
521	const TIMESTAMP_FIELDS = ['timestamp', 'created_at', 'occurred_at', 'event_at', 'logged_at', 'date', 'time'];
522	const ENVIRONMENT_FIELDS = ['environment', 'env', 'runtime_environment', 'deployment_environment', 'stage'];
523	const FAILURE_REASON_FIELDS = ['failure_reason_code', 'failure_reason', 'reason_code', 'error_code'];
524	const FAILURE_STAGE_FIELDS = ['failure_stage', 'error_stage', 'stage_name'];
525	const UUID_RE =
526	    /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
527	
528	function extractField<T = string>(
529	    record: Record<string, unknown>,
530	    candidates: string[],
531	    transform: (v: unknown) => T | null,
532	): T | null {
533	    for (const key of candidates) {
534	        const val = record[key] ?? record[key.toUpperCase()] ?? record[key.toLowerCase()];
535	        if (val !== undefined && val !== null && val !== '') {
536	            const result = transform(val);
537	            if (result !== null) return result;
538	        }
539	    }
540	    return null;
541	}
542	
543	export function extractSuccess(record: Record<string, unknown>): boolean | null {
544	    return extractField(record, SUCCESS_FIELDS, (v) => {
545	        const s = String(v).toLowerCase().trim();
546	        if (['true', '1', 'yes', 'success', 'pass', 'passed', 'ok', 'resolved', 'completed', 'complete', 'done'].includes(s)) return true;
547	        if (['false', '0', 'no', 'fail', 'failed', 'error', 'failure', 'partial', 'timeout', 'rejected', 'aborted'].includes(s)) return false;
548	        return null;
549	    });
550	}
551	
552	function extractExecutionStatus(record: Record<string, unknown>): 'COMPLETED' | 'FAILED' | null {
553	    return extractField(record, STATUS_FIELDS, (v) => {
554	        const normalized = String(v).trim().toUpperCase();
555	        if (normalized === 'COMPLETED') return 'COMPLETED';
556	        if (normalized === 'FAILED') return 'FAILED';
557	        return null;
558	    });
559	}
560	
561	function normalizeFailureToken(value: string | null, maxLen: number): string | null {
562	    if (!value) return null;
563	    const normalized = sanitizeString(value, maxLen)
564	        .trim()
565	        .toLowerCase()
566	        .replace(/\s+/g, '_')
567	        .replace(/[^a-z0-9_]/g, '_')
568	        .replace(/_+/g, '_')
569	        .replace(/^_+|_+$/g, '');
570	    if (!normalized) return null;
571	    return normalized.slice(0, maxLen);
572	}
573	
574	const FAILURE_REASON_CODE_VOCAB = new Set([
575	    'execution_failed',
576	    'timeout_error',
577	    'validation_failed',
578	    'dependency_failure',
579	    'policy_blocked',
580	    'feedback_marked_failure',
581	    'cross_event_conflict',
582	    'unknown_failure',
583	]);
584	
585	const FAILURE_STAGE_VOCAB = new Set([
586	    'action_selection',
587	    'action_execution',
588	    'ingest_validation',
589	    'verification',
590	    'delayed_feedback',
591	    'downstream_signal',
592	    'policy_gate',
593	    'unknown_stage',
594	]);
595	
596	function normalizeFailureReasonCode(value: string | null): string | null {
597	    const token = normalizeFailureToken(value, 80);
598	    if (!token) return null;
599	    return FAILURE_REASON_CODE_VOCAB.has(token)
600	        ? token
601	        : 'unknown_failure';
602	}
603	
604	function normalizeFailureStage(value: string | null): string | null {
605	    const token = normalizeFailureToken(value, 40);
606	    if (!token) return null;
607	    return FAILURE_STAGE_VOCAB.has(token)
608	        ? token
609	        : 'unknown_stage';
610	}
611	
612	function statusFromOutcomeScore(score: number | null): 'COMPLETED' | 'FAILED' | null {
613	    if (score === null || !Number.isFinite(score)) return null;
614	    return score >= 0.5 ? 'COMPLETED' : 'FAILED';
615	}
616	
617	export function extractScore(record: Record<string, unknown>): number | null {
618	    return extractField(record, SCORE_FIELDS, (v) => {
619	        const n = Number(v);
620	        if (!Number.isFinite(n)) return null;
621	        // Handle percentage-style scores (e.g. 85 -> 0.85).
622	        // Keep low decimal values above 1 (e.g. 1.5) on the 0-1 scale by clamping.
623	        if (n > 1 && n <= 100 && n >= 10) return Math.round((n / 100) * 10000) / 10000;
624	        return Math.max(0, Math.min(1, n));
625	    });
626	}
