628	function extractTimestamp(record: Record<string, unknown>): Date | null {
629	    return extractField(record, TIMESTAMP_FIELDS, (v) => {
630	        const d = new Date(String(v));
631	        return Number.isNaN(d.getTime()) ? null : d;
632	    });
633	}
