640	        stage: 'staging',
641	        stg: 'staging',
642	        qa: 'staging',
643	        test: 'staging',
644	        uat: 'staging',
645	        staging: 'staging',
646	        dev: 'development',
647	        develop: 'development',
648	        development: 'development',
649	    };
