656	    if (['resolved', 'success', 'done', 'complete', 'completed'].includes(s)) return 'resolved';
657	    if (['partial', 'partial_success', 'partial_failure'].includes(s)) return 'partial';
658	    if (['failed', 'failure', 'error', 'rejected'].includes(s)) return 'failed';
