672	// ── Dry-run parse pass ────────────────────────────────────────
673	
674	/**
675	 * Parses the entire file, normalizes all fields, computes quality scores,
676	 * clusters tasks. Does NOT write to the DB.
677	 * Returns valid rows ready for ingestion + validation errors.
678	 */
679	export function dryRunParse(
680	    records: Record<string, unknown>[],
681	    agentId: string,
682	    customerId: string,
683	): DryRunResult {
684	    const validRows: ParsedRow[] = [];
685	    const validationErrors: RowError[] = [];
686	    const taskCountMap: Record<string, number> = {};
687	
688	    let totalQuality = 0;
689	    let inconsistentCount = 0;
690	    let providedScoreCount = 0;
691	
692	    for (let i = 0; i < records.length; i++) {
693	        const rec = records[i];
694	        const rowIndex = i + 1;
695	        const rowErrors: RowError[] = [];
696	
697	        // Required: action_name
698	        const actionNameRaw = extractField(rec, ACTION_FIELDS, (v) => {
699	            const s = sanitizeString(String(v), 255).trim();
700	            return s.length > 0 ? s : null;
