887	function serializeParsedRows(rows: ParsedRow[]): ParsedRow[] {
888	    return rows.map((row) => ({
889	        row_index: row.row_index,
890	        row: row.row,
891	        idempotency_key: row.idempotency_key,
892	        quality: row.quality,
893	        resolved_task: row.resolved_task,
894	        source_event_at: row.source_event_at,
