898	function deserializeParsedRows(payload: unknown): ParsedRow[] {
899	    if (!Array.isArray(payload)) return [];
900	
901	    const rows: ParsedRow[] = [];
902	    for (const raw of payload) {
903	        if (!raw || typeof raw !== 'object') continue;
904	        const item = raw as Record<string, unknown>;
905	
906	        const rowIndex = Number(item.row_index);
907	        const row = item.row;
908	        const idempotencyKey = typeof item.idempotency_key === 'string' ? item.idempotency_key : null;
909	        const quality = Number(item.quality ?? Number.NaN);
910	        const resolvedTask = typeof item.resolved_task === 'string' ? item.resolved_task : null;
911	        const sourceEventAt = typeof item.source_event_at === 'string' ? item.source_event_at : null;
912	
913	        if (!Number.isFinite(rowIndex) || !row || typeof row !== 'object' || !idempotencyKey || !resolvedTask) {
914	            continue;
915	        }
916	
917	        rows.push({
918	            row_index: rowIndex,
919	            row: row as NormalizedOutcomeRow,
920	            idempotency_key: idempotencyKey,
921	            quality: Number.isFinite(quality) ? quality : 0,
922	            resolved_task: resolvedTask,
923	            source_event_at: sourceEventAt,
924	        });
925	    }
926	
927	    return rows;
928	}
