964	async function listRecoverableJobIds(): Promise<string[]> {
965	    const staleBefore = new Date(
966	        Date.now() - IMPORT_JOB_STALE_MINUTES * 60 * 1000,
967	    ).toISOString();
968	
969	    const [queuedResult, staleRunningResult] = await Promise.all([
970	        supabase
971	            .from('import_jobs')
972	            .select('job_id')
973	            .eq('status', 'queued')
974	            .order('created_at', { ascending: true })
975	            .limit(IMPORT_RECOVERY_BATCH_SIZE),
976	        supabase
977	            .from('import_jobs')
978	            .select('job_id')
979	            .eq('status', 'running')
980	            .lt('updated_at', staleBefore)
981	            .order('updated_at', { ascending: true })
982	            .limit(IMPORT_RECOVERY_BATCH_SIZE),
983	    ]);
984	
985	    if (queuedResult.error) {
986	        console.warn('[import] recovery queued-job lookup failed:', queuedResult.error.message);
