988	    if (staleRunningResult.error) {
989	        console.warn('[import] recovery stale-job lookup failed:', staleRunningResult.error.message);
990	    }
991	
992	    const ids = new Set<string>();
993	    for (const row of [...(queuedResult.data ?? []), ...(staleRunningResult.data ?? [])] as Array<Record<string, unknown>>) {
994	        if (typeof row.job_id === 'string') ids.add(row.job_id);
995	    }
996	    return [...ids];
997	}
