1024	/**
1025	 * Processes an import job asynchronously.
1026	 * Called fire-and-forget from POST /v1/import.
1027	 * Updates import_jobs table with progress and final status.
1028	 */
1029	async function processImportJob(
1030	    jobId: string,
1031	): Promise<void> {
1032	    const claimed = await claimImportJob(jobId);
1033	    if (!claimed) return;
1034	
1035	    const { validRows, customerId } = claimed;
1036	
1037	    let rowsProcessed = 0;
1038	    let rowsFailed = 0;
1039	    const errors: Array<{ row: number; error: string }> = [];
1040	
1041	    // Process in chunks to avoid memory pressure
1042	    for (let offset = 0; offset < validRows.length; offset += CHUNK_SIZE) {
1043	        const chunk = validRows.slice(offset, offset + CHUNK_SIZE);
1044	        // Process chunk concurrently with a strict concurrency limit (20)
1045	        // to avoid database connection pooling issues and OpenAI 429s.
1046	        const CONCURRENCY = 20;
1047	        for (let i = 0; i < chunk.length; i += CONCURRENCY) {
1048	            const subBatch = chunk.slice(i, i + CONCURRENCY);
1049	            await Promise.all(subBatch.map(async (parsed) => {
1050	                try {
1051	                    const sourceEventAt = parsed.source_event_at
1052	                        ? new Date(parsed.source_event_at)
1053	                        : null;
1054	                    const normalizedSourceEventAt =
1055	                        sourceEventAt && Number.isFinite(sourceEventAt.getTime())
1056	                            ? sourceEventAt
1057	                            : null;
1058	
1059	                    await ingestOutcome(parsed.row, customerId, {
1060	                        skipTrustUpdate: true,
1061	                        ingestionSource: 'import',
1062	                        enableInferenceWhenSkipTrust: ENABLE_IMPORT_INFERENCE,
1063	                        sourceEventAt: normalizedSourceEventAt,
1064	                        dedupWindowMs: IMPORT_NEAR_DUP_WINDOW_MS,
1065	                        importJobId: jobId,
1066	                    });
1067	                    rowsProcessed++;
1068	                } catch (err: any) {
1069	                    rowsFailed++;
1070	                    errors.push({ row: parsed.row_index, error: err.message ?? 'Unknown error' });
1071	                    console.warn('[import] row failed:', { jobId, row: parsed.row_index, error: err.message });
1072	                }
1073	            }));
1074	        }
1075	
1076	        // Update progress in DB after each chunk
1077	        await supabase
1078	            .from('import_jobs')
1079	            .update({ rows_processed: rowsProcessed, rows_failed: rowsFailed })
1080	            .eq('job_id', jobId);
1081	    }
1082	
1083	    // End-of-batch: refresh task performance. The RPC also refreshes
1084	    // mv_action_scores, so only call refresh_action_scores as fallback.
1085	    try {
1086	        const { error: refreshTaskError } = await supabase.rpc('refresh_task_action_performance');
1087	        if (refreshTaskError) {
1088	            console.warn('[import] refresh_task_action_performance failed:', refreshTaskError.message);
1089	            const { error: refreshActionError } = await supabase.rpc('refresh_action_scores');
1090	            if (refreshActionError) {
1091	                throw new Error(refreshActionError.message);
1092	            }
1093	        }
1094	        console.info('[import] MV refresh complete', { jobId });
1095	    } catch (err: any) {
1096	        console.warn('[import] MV refresh failed (non-fatal):', err.message);
1097	    }
1098	
1099	    // Clear in-memory score cache so next getScores() reads fresh data
1100	    try {
1101	        const internalSecret = process.env.LAYERINFINITE_INTERNAL_SECRET;
1102	        const apiBase = process.env.API_CACHE_REFRESH_URL ?? '';
1103	        if (internalSecret && apiBase) {
1104	            await fetch(`${apiBase}/internal/refresh-score-cache`, {
1105	                method: 'POST',
1106	                headers: {
1107	                    Authorization: `Bearer ${internalSecret}`,
1108	                    'Content-Type': 'application/json',
1109	                },
1110	                body: JSON.stringify({ triggered_by: 'import', job_id: jobId }),
1111	            });
1112	        }
1113	    } catch (err: any) {
1114	        console.warn('[import] cache refresh notification failed (non-fatal):', err.message);
1115	    }
1116	
1117	    // Mark job complete
1118	    const finalStatus = rowsFailed === validRows.length && validRows.length > 0 ? 'failed' : 'done';
1119	    await supabase
1120	        .from('import_jobs')
1121	        .update({
1122	            status: finalStatus,
1123	            rows_processed: rowsProcessed,
1124	            rows_failed: rowsFailed,
1125	            errors: errors.slice(0, 500), // cap stored errors to avoid JSONB blowup
1126	            payload: null,
1127	            completed_at: new Date().toISOString(),
