69	    if (input.outcomeScoreRaw === null || input.outcomeScoreRaw === undefined) {
70	        // Score was inferred — penalize by inverse of inference confidence.
71	        // High confidence inference (0.75) → penalty ~0.06
72	        // Low confidence inference (0.30)  → penalty ~0.18
73	        // No inference at all              → penalty 0.25 (original behavior)
74	        const conf = input.inferenceConfidence ?? 0;
75	        const penalty = conf > 0
76	            ? Math.max(0.05, 0.25 * (1 - conf))
77	            : 0.25;
78	        score -= penalty;
79	    }
80	    if (input.isInconsistent) {
81	        score -= 0.20;
82	    }
83	    if (input.mappingConfidence < 0.70) {
