393	    // Any string is accepted. Known values are normalized to lowercase.
394	    // Unknown values map to 'none' (neutral — no clear feedback signal).
395	    // Field is metadata-only — never read by scoring, trust, or policy.
396	    feedback_signal: z
397	        .string()
398	        .max(50)
399	        .optional()
400	        .transform(val => {
401	            if (val === undefined || val === null) return 'immediate';
402	            const normalized = val.trim().toLowerCase();
403	            const known = ['immediate', 'delayed', 'none'] as const;
404	            return (known as readonly string[]).includes(normalized)
405	                ? (normalized as typeof known[number])
406	                : 'none';
407	        }),
408	    decision_id: z.string().uuid().optional(),
409	    episode_id: z.string().uuid().optional(),
410	    episode_history: z.array(z.string()).optional(),
411	    verifier_signal: z.object({
412	        source: z.enum([
413	            'http_status_code',
414	            'database_row_count',
415	            'human_review',
416	            'downstream_webhook',
417	            'none',
418	        ]),
419	        value: z.union([
420	            z.number(),
421	            z.boolean(),
422	            z.string(),
423	        ]).optional(),
424	        verified_at: z.string().datetime().optional(),
425	    }).optional(),
426	
427	    // ── Phase 1: Real Outcome Signal Integration ──────────────
428	    // All four fields are optional. Callers that omit them get the
429	    // existing behaviour. real_agent.py sends none of them.
430	    signal_source: z.enum([
431	        'causal_graph',
432	        'signal_contract',
433	        'http_inference',
434	        'explicit',
435	    ]).optional().default('explicit'),
436	    // When signal_source is 'causal_graph', the Proxy interceptor
437	    // inferred which action this outcome belongs to.
438	    inferred_action_id: z.string().uuid().optional(),
439	    // Confidence of the signal: 0.90 at causal depth 0, decays by
440	    // 0.04 per depth level. NULL for explicit signals.
441	    causal_confidence: z.number().min(0).max(1).optional(),
442	    // How many transformation layers the traced value traversed.
443	    // NULL for explicit signals. 0–8 for causal graph signals.
444	    signal_depth: z.number().int().min(0).max(9).optional(),
445	
446	    // ── Decision Recommendation Engine ───────────────────────
447	    // Optional semantic label for what the agent was trying to do.
448	    // Examples: "payment_failed", "ticket_escalation", "refund_request"
449	    // If absent: auto-inferred from issue_type via inferTask().
450	    // TASK RESOLUTION RULE: provided value ALWAYS wins over inferred.
451	    task_name: z.string().min(1).max(255).optional(),
452	    retry_chain_id: z.string().uuid().optional(),
453	    retry_attempt: z.number().int().min(0).max(1000).optional(),
454	    execution_status: z
455	        .preprocess(
456	            (val) => typeof val === 'string' ? val.trim().toUpperCase() : val,
457	            z.enum(['COMPLETED', 'FAILED']).optional(),
458	        ),
459	    failure_reason_code: z.string().max(80).optional(),
460	    failure_stage: z.string().max(40).optional(),
461	
462	    // ── Resource cost tracking ────────────────────────────────
463	    // Tracks token usage, API call count, or compute cost per outcome.
464	    // Agent frameworks (LangChain, CrewAI) report token_usage.total_tokens;
465	    // this field captures that signal for cost-per-outcome analysis.
466	    resource_cost_units: z.preprocess(
467	        (val) => {
468	            if (val === undefined || val === null) return undefined;
469	            const num = Number(val);
470	            return Number.isFinite(num) && num >= 0 ? num : undefined;
471	        },
472	        z.number().min(0).optional(),
473	    ),
474	    resource_cost_type: z.enum(['tokens', 'api_calls', 'compute_seconds']).optional(),
475	});
