713	async function resolveRetryChainState(
714	    customerId: string,
715	    body: any,
716	): Promise<RetryChainState> {
717	    const fromRawContext = body.raw_context && typeof body.raw_context === 'object'
718	        ? body.raw_context
719	        : null;
720	
721	    const derivedChain =
722	        body.retry_chain_id
723	        ?? (typeof fromRawContext?.retry_chain_id === 'string' ? fromRawContext.retry_chain_id : null)
724	        ?? null;
725	
726	    const derivedAttemptRaw =
727	        body.retry_attempt
728	        ?? (typeof fromRawContext?.retry_attempt === 'number' ? fromRawContext.retry_attempt : null);
729	
730	    const derivedAttempt = typeof derivedAttemptRaw === 'number' && Number.isFinite(derivedAttemptRaw)
731	        ? Math.max(0, Math.floor(derivedAttemptRaw))
732	        : null;
733	
734	    if (!derivedChain) {
735	        return {
736	            retryChainId: null,
737	            retryAttempt: null,
738	            crossEventAttemptCount: null,
739	            canonicalOutcomeId: null,
740	        };
741	    }
742	
743	    const { data: previous, error } = await supabase
744	        .from('fact_outcomes')
745	        .select('outcome_id, canonical_outcome_id, cross_event_attempt_count, retry_attempt')
746	        .eq('customer_id', customerId)
747	        .eq('retry_chain_id', derivedChain)
748	        .order('timestamp', { ascending: false })
749	        .limit(1)
750	        .maybeSingle();
751	
752	    if (error) {
753	        console.warn('[log-outcome] retry chain lookup failed:', error.message);
754	    }
755	
756	    const previousAttemptCount = typeof previous?.cross_event_attempt_count === 'number'
757	        ? previous.cross_event_attempt_count
758	        : null;
759	
760	    const previousRetryAttempt = typeof previous?.retry_attempt === 'number'
761	        ? previous.retry_attempt
762	        : null;
763	
764	    const resolvedAttempt = derivedAttempt
765	        ?? (previousRetryAttempt !== null ? previousRetryAttempt + 1 : 0);
766	
767	    const crossEventAttemptCount = previousAttemptCount !== null
768	        ? Math.max(previousAttemptCount + 1, resolvedAttempt + 1)
769	        : resolvedAttempt + 1;
770	
771	    return {
772	        retryChainId: derivedChain,
773	        retryAttempt: resolvedAttempt,
774	        crossEventAttemptCount,
775	        canonicalOutcomeId: previous?.canonical_outcome_id ?? previous?.outcome_id ?? null,
776	    };
777	}
