1032	                `on task "${taskName}". ` +
1033	                `Recent 10-outcome rate: ${(recentRate * 100).toFixed(1)}% vs ` +
1034	                `baseline ${(baselineRate * 100).toFixed(1)}%. ` +
1035	                `This recommendation may not have improved performance. ` +
1036	                `Review in Dashboard -> Discrepancies.`,
1037	        });
1038	
1039	        console.warn('[log-outcome] recommendation_regression', {
1040	            customer_id: customerId,
1041	            agent_id: agentId,
1042	            action_name: actionName,
1043	            task_name: taskName,
1044	            recent_rate: recentRate,
1045	            baseline_rate: baselineRate,
1046	        });
