1517	// Debounce duration: controlled by env var.
1518	// Default 15s for production (safe under load), 2s for development.
1519	const REFRESH_DEBOUNCE_MS = process.env.NODE_ENV === 'production'
1520	    ? Number(process.env.MV_REFRESH_DEBOUNCE_MS ?? 15_000)
1521	    : 2_000;
1522	
1523	const ACTION_SCORES_DEBOUNCE_MS = Number(process.env.ACTION_SCORES_DEBOUNCE_MS ?? 500);
