122	function medianOf(values: number[]): number | null {
123	    const finite = values.filter((v) => Number.isFinite(v)).sort((a, b) => a - b);
124	    if (finite.length === 0) return null;
125	
126	    const middle = Math.floor(finite.length / 2);
127	    if (finite.length % 2 === 1) {
128	        return Number(finite[middle].toFixed(4));
