255	function toUniqueTaskCandidates(values: Array<string | null | undefined>): string[] {
256	    const seen = new Set<string>();
257	    const out: string[] = [];
258	
259	    for (const value of values) {
260	        if (!value) continue;
261	        const trimmed = value.trim();
262	        if (!trimmed || seen.has(trimmed)) continue;
263	        seen.add(trimmed);
264	        out.push(trimmed);
265	    }
266	
267	    return out;
