304	    increment: number,
305	    success: boolean | null,
306	    score: number | null,
307	    scoreRaw: number | null,
308	): void {
309	    if (!agentId || !taskName || !Number.isFinite(increment) || increment <= 0) {
310	        return;
311	    }
312	
313	    let taskMap = agentTaskTotals.get(agentId);
314	    if (!taskMap) {
315	        taskMap = new Map<string, number>();
316	        agentTaskTotals.set(agentId, taskMap);
