320	    agentGrandTotals.set(agentId, (agentGrandTotals.get(agentId) ?? 0) + increment);
321	
322	    // Track win rate across all tasks for this agent
323	    const stats = agentSuccessStats.get(agentId) ?? { wins: 0, rated: 0 };
324	    const finalScore = scoreRaw ?? score ?? (success === true ? 1 : success === false ? 0 : null);
325	    if (finalScore !== null) {
326	        stats.rated += increment;
327	        stats.wins += (finalScore * increment);
