36	// Full-response cache keyed by (customer, agent, issueType, env, tier).
37	// 5s TTL — scores change on every ingested outcome, so longer staleness
38	// could miss recent writes. Under burst traffic, 3 concurrent workers
39	// hitting the same agent's scores → 1 DB call + 2 cache hits.
40	const scoreResultCache = new Map<string, TimedCacheEntry<Record<string, unknown>>>();
41	const SCORE_RESULT_CACHE_TTL_MS = readPositiveInt(
42	    process.env.LI_SCORE_CACHE_TTL_MS,
