57	function pruneScoreResultCache(): void {
58	    if (scoreResultCache.size <= SCORE_RESULT_CACHE_MAX_ENTRIES) return;
59	    // Simple eviction: delete oldest expired first, then oldest entries
60	    const now = Date.now();
61	    for (const [key, entry] of scoreResultCache) {
62	        if (entry.expiresAt <= now) scoreResultCache.delete(key);
63	        if (scoreResultCache.size <= SCORE_RESULT_CACHE_MAX_ENTRIES * 0.8) return;
64	    }
65	    // Still over limit — evict oldest
66	    const keys = [...scoreResultCache.keys()];
67	    const toDelete = keys.slice(0, keys.length - Math.floor(SCORE_RESULT_CACHE_MAX_ENTRIES * 0.8));
68	    for (const key of toDelete) scoreResultCache.delete(key);
