105	function buildTraceFields(overrides: Partial<DiscrepancyTraceFields>): DiscrepancyTraceFields {
106	    const normalizedReasonCode = overrides.reason_code ?? overrides.trace_reason_code ?? null;
107	    const normalizedTracePayload = overrides.trace_payload ?? overrides.trace_context ?? null;
108	
109	    const merged: DiscrepancyTraceFields = {
110	        reason_code: normalizedReasonCode,
111	        trace_reason_code: null,
112	        trace_stage: null,
113	        trace_gate: null,
114	        source_execution_status: null,
115	        source_status_origin: null,
116	        source_failure_reason_code: null,
117	        source_failure_stage: null,
118	        trace_payload: normalizedTracePayload,
119	        trace_context: null,
120	        ...overrides,
121	    };
122	
123	    merged.reason_code = normalizedReasonCode;
124	    merged.trace_reason_code = normalizedReasonCode;
125	    merged.trace_payload = normalizedTracePayload;
126	    merged.trace_context = normalizedTracePayload;
127	    return merged;
128	}
