1	/**
2	 * Layerinfinite — middleware/validate-action.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Hallucination Prevention Middleware for Hono.
5	 *
6	 * Validates that action_name from request body exists in
7	 * dim_actions registry. Blocks unregistered actions with 400.
8	 * Uses 30-min in-memory cache to minimise DB round-trips.
9	 *
10	 * On success: sets action + validated_action on context + calls next()
11	 * On failure: returns 400 UNKNOWN_ACTION (not 422 per PRD)
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Context, Next } from 'hono';
16	import { supabase } from '../lib/supabase.js';
17	import crypto from 'node:crypto';
18	
19	// ── Category-based baseline priors ─────────────────────────
20	// Returns a starting avg_success_rate based on action_category.
21	function getBaselinePrior(actionCategory: string): number {
22	    const priors: Record<string, number> = {
23	        recovery: 0.70,
24	        escalation: 0.45,
25	        automation: 0.60,
26	        'auto-discovered': 0.55,
27	        custom: 0.55,
28	    };
29	    return priors[actionCategory] ?? 0.50;
30	}
31	
32	// Fire-and-forget: seed institutional knowledge for a newly registered action.
33	// Uses INSERT protected by unique constraint so re-registration never overwrites
34	// real accumulated data. Never blocks action registration — errors are only logged.
35	async function seedInstitutionalKnowledge(
36	    actionId: string,
37	    actionCategory: string,
38	    contextType: string | null,
39	): Promise<void> {
40	    const baseline = getBaselinePrior(actionCategory);
41	    const contextSeed = contextType ?? 'global';
42	    try {
43	        const { error } = await supabase
44	            .from('dim_institutional_knowledge')
45	            .insert({
46	                pattern_id: crypto.randomUUID(),
47	                action_id: actionId,
48	                context_type: contextSeed,
49	                avg_success_rate: baseline,
50	                sample_count: 10,
51	            });
52	        // 23505 = unique_violation (row already exists) — correct, ignore silently
53	        if (error && error.code !== '23505') {
54	            console.warn('[validate-action] Knowledge seed failed (non-fatal):', {
55	                action_id: actionId, context_type: contextSeed, error: error.message,
56	            });
57	        }
58	    } catch (err: any) {
59	        console.warn('[validate-action] Knowledge seed exception (non-fatal):', {
60	            action_id: actionId, context_type: contextSeed, error: err.message,
61	        });
62	    }
63	}
