65	const ACTION_CACHE_TTL_MS = 30 * 60 * 1000;  // 30 min
66	
67	interface ActionCacheEntry {
68	    action_id: string;
69	    action_name: string;
70	    action_category: string;
71	    required_params: Record<string, unknown>;
72	    validation_mode: string;
73	    is_active: boolean;
74	    expires_at: number;
75	}
76	
77	// Cache by customer_id:action_name
78	const actionCache = new Map<string, ActionCacheEntry>();
79	
80	function getActionCacheKey(customerId: string, actionName: string): string {
81	    return `${customerId}:${actionName}`;
82	}
83	
84	/**
85	 * Strip trailing version/noise suffixes from a snake_case action name.
86	 * Applied iteratively until stable. Minimum 3 chars preserved.
87	 *
88	 * Patterns (trailing only, never mid-string):
89	 *   _v2, _v1_3          → version numbers
90	 *   _final, _new, _old  → intent noise
91	 *   _test, _prod, _dev  → environment noise
92	 *   _handler, _fn, _impl → code noise
93	 */
94	function stripVersionSuffixes(name: string): string {
95	    let result = name;
96	    let prev = '';
97	    while (prev !== result && result.length > 3) {
98	        prev = result;
99	        result = result
100	            .replace(/_v\d+(_\d+)?$/, '')
101	            .replace(/_(final|new|old|temp|bak|copy)$/, '')
102	            .replace(/_(test|prod|dev|staging)$/, '')
103	            .replace(/_(handler|fn|func|impl|helper)$/, '')
104	            .replace(/_+$/g, '');
105	    }
106	    return result || name;
107	}
108	
109	export function normalizeActionName(raw: string): string {
110	    const base = raw
111	        .trim()
112	        // camelCase / PascalCase → snake_case  (e.g. retryWith → retry_With → retry_with)
113	        .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
114	        // Replace hyphens and spaces with underscores
115	        .replace(/[-\s]+/g, '_')
116	        // Collapse consecutive underscores
117	        .replace(/_+/g, '_')
118	        // Lowercase everything
119	        .toLowerCase()
120	        // Strip leading/trailing underscores
121	        .replace(/^_+|_+$/g, '');
122	    // Strip trailing version/noise suffixes AFTER camelCase split + lowercase.
123	    // Order matters: retryPaymentV2 → retry_payment_v2 → retry_payment
124	    return stripVersionSuffixes(base);
125	}
126	
127	/**
128	 * Fire-and-forget: record an action name alias in dim_action_aliases.
129	 * Used when normalization maps a developer-sent raw name to a different canonical form.
130	 * Never blocks the hot path — errors are only logged.
131	 */
132	async function recordActionAlias(
133	    rawName: string,
134	    canonicalName: string,
135	    customerId: string,
136	    mergeReason: string,
137	): Promise<void> {
138	    if (rawName === canonicalName) return;
139	    try {
140	        const { error } = await supabase
141	            .from('dim_action_aliases')
142	            .upsert({
143	                raw_name: rawName,
144	                canonical_name: canonicalName,
145	                customer_id: customerId,
146	                merge_reason: mergeReason,
147	                merge_confidence: 1.000,
148	                similarity: null,
149	            }, {
150	                onConflict: 'raw_name,customer_id',
151	                ignoreDuplicates: true,
152	            });
153	        // 23505 = unique_violation (row already exists) — correct, ignore silently
154	        if (error && error.code !== '23505') {
155	            console.warn('[validate-action] Alias record failed (non-fatal):', {
156	                raw_name: rawName, canonical_name: canonicalName, error: error.message,
157	            });
158	        }
159	    } catch (err: any) {
160	        console.warn('[validate-action] Alias record exception (non-fatal):', err.message);
161	    }
162	}
163	
164	// Evict expired entries every 5 minutes
165	const CLEANUP_INTERVAL_MS = 5 * 60_000;
166	setInterval(() => {
167	    const now = Date.now();
168	    let evicted = 0;
169	    for (const [key, entry] of actionCache.entries()) {
170	        if (entry.expires_at < now) {
171	            actionCache.delete(key);
172	            evicted++;
173	        }
174	    }
175	    if (evicted > 0) {
176	        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from actionCache`);
177	    }
178	}, CLEANUP_INTERVAL_MS).unref();
179	
180	setInterval(() => {
181	    console.info(`[cache-size] actionCache: ${actionCache.size} entries`);
182	}, 15 * 60_000).unref();
