184	export interface ActionValidationResult {
185	    valid: boolean;
186	    action_id?: string;
187	    action_name?: string;
188	    action_category?: string;
189	    required_params?: Record<string, unknown>;
190	    validation_mode?: string;
191	    error?: string;
192	    error_code?: string;
193	    warnings?: string[];
194	}
195	
196	// Extend Hono Context to recognize validated_action
197	declare module 'hono' {
198	    interface ContextVariableMap {
199	        action: {
200	            action_id: string;
201	            action_name: string;
202	            is_active: boolean;
203	        };
204	        validated_action: {
205	            action_id: string;
206	            action_name: string;
207	            action_category: string;
208	            validation_warnings?: string[];
209	        };
210	        parsed_body: unknown;
211	    }
212	}
