214	// ── Middleware form ───────────────────────────────────────────
215	/**
216	 * Hono middleware that validates action_name in the request body
217	 * against dim_actions. Sets c.set('validated_action', ...) on success.
218	 */
219	export async function validateActionMiddleware(c: Context, next: Next): Promise<Response | void> {
220	    // Clone the request body so downstream handlers can read it
221	    let body: Record<string, unknown>;
222	    try {
223	        body = await c.req.json();
224	    } catch {
225	        return c.json({ error: 'Invalid JSON body', code: 'PARSE_ERROR' }, 400);
226	    }
227	
228	    const rawActionName = body.action_name ?? body.actionName;
229	    const actionName = rawActionName && typeof rawActionName === 'string'
230	        ? normalizeActionName(rawActionName)
231	        : rawActionName;
232	    // Write the normalized name back so downstream handlers see the canonical form
233	    if (actionName && typeof actionName === 'string') {
234	        body.action_name = actionName;
235	    }
236	    const customerId = ((c as any).get('customerId') ?? c.get('customer_id')) as string | undefined;
237	
238	    // Record alias when normalization changed the name (fire-and-forget)
239	    // Must be after customerId is resolved.
240	    if (actionName && typeof actionName === 'string' && customerId) {
241	        const rawLower = String(rawActionName).trim().toLowerCase()
242	            .replace(/[-\s]+/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '');
243	        if (rawLower !== actionName) {
244	            const reason = rawLower.match(/_v\d|_(final|new|old|temp|test|prod|dev|handler|fn|func|impl)$/)
245	                ? 'version_strip'
246	                : 'camel_normalize';
247	            void recordActionAlias(rawLower, actionName, customerId, reason);
248	        }
249	    }
250	
251	    // If action_name is absent but action_id is present,
252	    // skip middleware validation — resolveActionId() handles it.
253	    if (!actionName || typeof actionName !== 'string') {
254	        if (body.action_id || body.action_id_input) {
255	            c.set('parsed_body', body);
256	            await next();
257	            return;
258	        }
259	        return c.json({ error: 'action_name or action_id is required', code: 'MISSING_FIELD' }, 400);
260	    }
261	
262	    if (!customerId) {
263	        return c.json({ error: 'customerId is required', code: 'MISSING_CUSTOMER' }, 401);
264	    }
265	
266	    // ── Cache check (fast path — skip DB on hit) ─────────────────
267	    // actionName is already normalized above — no further trim needed
268	    const cacheKey = getActionCacheKey(customerId, actionName);
269	    const cachedEntry = actionCache.get(cacheKey);
270	
271	    if (cachedEntry && cachedEntry.expires_at > Date.now()) {
272	        if (!cachedEntry.is_active) {
273	            return c.json(
274	                { error: 'Action is disabled', action_name: actionName, code: 'ACTION_DISABLED' },
275	                403
276	            );
277	        }
278	        c.set('action', {
279	            action_id: cachedEntry.action_id,
280	            action_name: cachedEntry.action_name,
281	            is_active: cachedEntry.is_active,
282	        });
283	        c.set('validated_action', {
284	            action_id: cachedEntry.action_id,
285	            action_name: cachedEntry.action_name,
286	            action_category: cachedEntry.action_category,
287	            validation_warnings: [],
288	        });
289	        c.set('parsed_body', body);
290	        await next();
291	        return;
292	    }
293	
294	    // ── Cache miss: look up action scoped to this customer ────────
295	    const { data: existingAction } = await supabase
296	        .from('dim_actions')
297	        .select('action_id, action_name, action_category, required_params, validation_mode, is_active')
298	        .eq('action_name', actionName)
299	        .eq('customer_id', customerId)
300	        .maybeSingle();
301	
302	    if (existingAction) {
303	        // Write to cache so subsequent requests skip DB
304	        actionCache.set(cacheKey, {
305	            ...existingAction,
306	            required_params: existingAction.required_params as Record<string, unknown>,
307	            expires_at: Date.now() + ACTION_CACHE_TTL_MS,
308	        });
309	
310	        if (!existingAction.is_active) {
311	            return c.json(
312	                { error: 'Action is disabled', action_name: actionName, code: 'ACTION_DISABLED' },
313	                403
314	            );
315	        }
316	
317	        c.set('action', {
318	            action_id: existingAction.action_id,
319	            action_name: existingAction.action_name,
320	            is_active: existingAction.is_active,
321	        });
322	        c.set('validated_action', {
323	            action_id: existingAction.action_id,
324	            action_name: existingAction.action_name,
325	            action_category: existingAction.action_category,
326	            validation_warnings: [],
327	        });
328	        c.set('parsed_body', body);
329	        await next();
330	        return;
331	    }
332	
333	    // ── Action not found: AUTO-REGISTER on first use ──────────────
334	    // AUTO-REGISTER: silently create on first use
335	    // This means users never need to manually register actions
336	    const { data: newAction, error: insertError } = await supabase
337	        .from('dim_actions')
338	        .upsert({
339	            action_name: actionName,
340	            customer_id: customerId,
341	            is_active: true,
342	            action_category: 'auto-discovered',
343	            action_description: 'Auto-registered on first use by SDK',
344	            required_params: {},
345	            validation_mode: 'advisory',
346	        }, {
347	            onConflict: 'action_name,customer_id',
348	            ignoreDuplicates: false,
349	        })
350	        .select('action_id, action_name, is_active')
351	        .maybeSingle();
352	
353	    if (insertError || !newAction) {
354	        // Only fail if DB itself errors
355	        console.error('[validate-action] Auto-register failed', {
356	            action_name: actionName,
357	            customer_id: customerId,
358	            error_code: insertError?.code,
359	            error_message: insertError?.message,
360	        });
361	        return c.json({ error: 'Failed to register action' }, 500);
362	    }
363	
364	    // Seed institutional knowledge for this new action.
365	    // issue_type from body determines which context gets the prior.
366	    // void — fire-and-forget, never blocks registration.
367	    void seedInstitutionalKnowledge(
368	        newAction.action_id,
369	        'auto-discovered',
370	        (body.issue_type as string | undefined) ?? null,
371	    );
372	
373	    c.set('action', newAction);
374	    c.set('validated_action', {
375	        action_id: newAction.action_id,
376	        action_name: newAction.action_name,
377	        action_category: 'auto-discovered',
378	        validation_warnings: [],
379	    });
380	
381	    // Cache the newly registered action
382	    actionCache.set(cacheKey, {
383	        action_id: newAction.action_id,
384	        action_name: newAction.action_name,
385	        action_category: 'auto-discovered',
386	        required_params: {},
387	        validation_mode: 'advisory',
388	        is_active: true,
389	        expires_at: Date.now() + ACTION_CACHE_TTL_MS,
390	    });
391	
392	    c.set('parsed_body', body);
393	    await next();
394	}
395	
396	// ── Core validation function (also exported for direct use) ──
397	export async function validateAction(
398	    actionName: string,
399	    customerId: string,
400	    params?: Record<string, unknown>
401	): Promise<ActionValidationResult> {
402	    actionName = normalizeActionName(actionName);
403	    const cacheKey = getActionCacheKey(customerId, actionName);
404	    const cached = actionCache.get(cacheKey);
405	
406	    if (cached && cached.expires_at > Date.now()) {
407	        if (!cached.is_active) {
408	            return { valid: false, error: `Action "${actionName}" is disabled`, error_code: 'ACTION_DISABLED' };
409	        }
410	        return validateParams(cached, params);
411	    }
412	
413	    // Cache miss — lookup in dim_actions
414	    const { data, error } = await supabase
415	        .from('dim_actions')
416	        .select('action_id, action_name, action_category, action_description, required_params, is_active, validation_mode')
417	        .eq('action_name', actionName)
418	        .eq('customer_id', customerId)
419	        .maybeSingle();
420	
421	    if (error) {
422	        return { valid: false, error: `Action lookup failed: ${error.message}`, error_code: 'DB_ERROR' };
423	    }
424	
425	    if (!data) {
426	        return {
427	            valid: false,
428	            error: `action_name '${actionName}' not found in registry and could not be auto-registered.`,
429	            error_code: 'UNKNOWN_ACTION',
430	        };
431	    }
432	
433	    // Cache result
434	    actionCache.set(cacheKey, {
435	        ...data,
436	        required_params: data.required_params as Record<string, unknown>,
437	        expires_at: Date.now() + ACTION_CACHE_TTL_MS,
438	    });
439	
440	    if (!data.is_active) {
441	        return { valid: false, error: `Action "${actionName}" is currently disabled`, error_code: 'ACTION_DISABLED' };
442	    }
443	
444	    return validateParams(data, params);
445	}
446	
447	function validateParams(
448	    action: { action_id: string; action_name: string; action_category: string; required_params: Record<string, unknown>, validation_mode?: string },
449	    params?: Record<string, unknown>
450	): ActionValidationResult {
451	    const mode = action.validation_mode ?? 'advisory';
452	    const required = action.required_params ?? {};
453	    const requiredKeys = Object.keys(required);
454	
455	    const missing = requiredKeys.filter(k => !(k in (params ?? {})));
456	
457	    if (missing.length === 0) {
458	        return {
459	            valid: true,
460	            action_id: action.action_id,
461	            action_name: action.action_name,
462	            action_category: action.action_category,
463	            required_params: action.required_params,
464	        };
465	    }
466	
467	    if (mode === 'strict') {
468	        return {
469	            valid: false,
470	            error: `action '${action.action_name}' requires: ${missing.join(', ')}`,
471	            error_code: 'MISSING_PARAMS',
472	        };
473	    }
474	
475	    if (mode === 'advisory') {
476	        return {
477	            valid: true,
478	            action_id: action.action_id,
479	            action_name: action.action_name,
480	            action_category: action.action_category,
481	            required_params: action.required_params,
482	            warnings: missing.map(k => `param '${k}' is recommended but not provided`),
483	        };
484	    }
485	
486	    // disabled logic
487	    return {
488	        valid: true,
