253	export function computeOutcomeDataQuality(params: {
254	    outcomeScoreRaw: number | null | undefined;
255	    isInconsistent: boolean;
256	    mappingConfidence: number;
257	    businessOutcome: string | null | undefined;
258	    inferenceConfidence?: number | null;
259	}): number {
260	    let score = 1.0;
261	
262	    if (params.outcomeScoreRaw === null || params.outcomeScoreRaw === undefined) {
263	        // Score was inferred — penalize by inverse of inference confidence.
264	        // High confidence inference (0.75) → penalty ~0.06
265	        // Low confidence inference (0.30)  → penalty ~0.18
266	        // No inference at all              → penalty 0.25 (original behavior)
267	        const conf = params.inferenceConfidence ?? 0;
268	        const penalty = conf > 0
269	            ? Math.max(0.05, 0.25 * (1 - conf))
270	            : 0.25;
271	        score -= penalty;
272	    }
273	
274	    if (params.isInconsistent) score -= 0.20;
275	    if (params.mappingConfidence < 0.70) score -= 0.20;
276	    if (!params.businessOutcome) score -= 0.10;
277	    
278	    return Number(Math.max(0.0, score).toFixed(4));
