367	export async function resolveActionIdForIngest(
368	    actionName: string,
369	    customerId: string,
370	): Promise<{ actionId: string; resolvedActionName: string }> {
371	    const { normalizeActionName } = await import('../middleware/validate-action.js');
372	    const normalized = normalizeActionName(actionName);
373	
374	    const rawLower = actionName
375	        .trim()
376	        .toLowerCase()
377	        .replace(/[-\s]+/g, '_')
378	        .replace(/_+/g, '_')
379	        .replace(/^_+|_+$/g, '');
380	
381	    if (rawLower && rawLower !== normalized) {
382	        const mergeReason = rawLower.match(/_v\d|_(final|new|old|temp|test|prod|dev|handler|fn|func|impl)$/)
383	            ? 'version_strip'
384	            : 'camel_normalize';
385	        void (async () => {
386	            try {
387	                const { error } = await supabase
388	                    .from('dim_action_aliases')
389	                    .upsert({
390	                        raw_name: rawLower,
391	                        canonical_name: normalized,
392	                        customer_id: customerId,
393	                        merge_reason: mergeReason,
394	                        merge_confidence: 1.0,
395	                        similarity: null,
396	                    }, {
397	                        onConflict: 'raw_name,customer_id',
398	                        ignoreDuplicates: true,
399	                    });
400	
401	                if (error && error.code !== '23505') {
402	                    console.warn('[ingest-core] alias upsert failed:', error.message);
403	                }
404	            } catch (err: unknown) {
405	                console.warn('[ingest-core] alias upsert threw:', (err as Error).message);
406	            }
407	        })();
408	    }
409	
410	    // Import payloads frequently contain historical/novel action names.
411	    // Resolve existing action first, then auto-register on first use.
412	    const { data: existing, error: lookupError } = await supabase
413	        .from('dim_actions')
414	        .select('action_id, action_name, is_active')
415	        .eq('action_name', normalized)
416	        .eq('customer_id', customerId)
417	        .maybeSingle();
418	
419	    if (lookupError) {
420	        throw new Error(`ACTION_LOOKUP_ERROR:${lookupError.message}`);
421	    }
422	
423	    if (existing) {
424	        if (!existing.is_active) {
425	            throw new Error(`ACTION_DISABLED:Action "${normalized}" is currently disabled`);
426	        }
427	        return { actionId: existing.action_id, resolvedActionName: existing.action_name };
428	    }
429	
430	    const { data: registered, error: registerError } = await supabase
431	        .from('dim_actions')
432	        .upsert(
433	            {
434	                action_name: normalized,
435	                customer_id: customerId,
436	                is_active: true,
437	                action_category: 'auto-discovered',
438	                action_description: 'Auto-registered on first use by historical import',
439	                required_params: {},
440	                validation_mode: 'advisory',
441	            },
442	            {
443	                onConflict: 'action_name,customer_id',
444	                ignoreDuplicates: false,
445	            }
446	        )
447	        .select('action_id, action_name, is_active')
448	        .maybeSingle();
449	
450	    if (registerError || !registered) {
451	        throw new Error(`ACTION_REGISTER_ERROR:${registerError?.message ?? 'No action row returned'}`);
452	    }
453	
454	    if (!registered.is_active) {
455	        throw new Error(`ACTION_DISABLED:Action "${normalized}" is currently disabled`);
