530	function parseNearDedupWindowMs(value: number | undefined): number {
531	    if (typeof value !== 'number' || !Number.isFinite(value)) return 0;
532	    return Math.max(0, Math.floor(value));
533	}
534	
535	function normalizedTextToken(value: string | null | undefined): string | null {
536	    if (!value) return null;
537	    const normalized = value.trim().toLowerCase();
538	    return normalized.length > 0 ? normalized : null;
539	}
540	
541	function isNearDuplicateCandidate(
542	    candidate: {
543	        outcome_score_raw: number | null;
544	        response_time_ms: number | null;
545	        error_code: string | null;
546	        business_outcome: string | null;
547	    },
548	    target: {
549	        outcomeScoreRaw: number | null;
550	        responseTimeMs: number | null;
551	        errorCode: string | null;
552	        businessOutcome: string | null;
553	    },
554	): boolean {
555	    const candidateError = normalizedTextToken(candidate.error_code);
556	    const targetError = normalizedTextToken(target.errorCode);
557	    if (candidateError !== targetError) return false;
558	
559	    const candidateOutcome = normalizedTextToken(candidate.business_outcome);
560	    const targetOutcome = normalizedTextToken(target.businessOutcome);
561	    if (candidateOutcome !== targetOutcome) return false;
562	
563	    if (typeof candidate.response_time_ms === 'number' && typeof target.responseTimeMs === 'number') {
564	        if (Math.abs(candidate.response_time_ms - target.responseTimeMs) > 250) {
565	            return false;
566	        }
567	    }
568	
569	    if (typeof candidate.outcome_score_raw === 'number' && typeof target.outcomeScoreRaw === 'number') {
570	        if (Math.abs(candidate.outcome_score_raw - target.outcomeScoreRaw) > 0.05) {
571	            return false;
572	        }
573	    }
574	
575	    return true;
576	}
