578	async function findNearDuplicateOutcome(params: {
579	    customerId: string;
580	    agentId: string;
581	    actionId: string;
582	    contextId: string;
583	    taskName: string;
584	    success: boolean;
585	    sourceEventAt: Date;
586	    dedupWindowMs: number;
587	    outcomeScoreRaw: number | null;
588	    responseTimeMs: number | null;
589	    errorCode: string | null;
590	    businessOutcome: string | null;
591	}): Promise<string | null> {
592	    const start = new Date(params.sourceEventAt.getTime() - params.dedupWindowMs).toISOString();
593	    const end = new Date(params.sourceEventAt.getTime() + params.dedupWindowMs).toISOString();
594	
595	    const { data, error } = await supabase
596	        .from('fact_outcomes')
597	        .select('outcome_id, outcome_score_raw, response_time_ms, error_code, business_outcome')
598	        .eq('customer_id', params.customerId)
599	        .eq('agent_id', params.agentId)
600	        .eq('action_id', params.actionId)
601	        .eq('context_id', params.contextId)
602	        .eq('task_name', params.taskName)
603	        .eq('success', params.success)
604	        .eq('is_deleted', false)
605	        .eq('is_synthetic', false)
606	        .eq('ingestion_source', 'import')
607	        .gte('timestamp', start)
608	        .lte('timestamp', end)
609	        .order('timestamp', { ascending: false })
610	        .limit(5);
611	
612	    if (error) {
613	        console.warn('[ingest-core] near-duplicate lookup failed:', error.message);
614	        return null;
615	    }
616	
617	    for (const row of (data ?? []) as Array<Record<string, unknown>>) {
618	        const candidateOutcomeId = typeof row.outcome_id === 'string' ? row.outcome_id : null;
619	        if (!candidateOutcomeId) continue;
620	
621	        const matches = isNearDuplicateCandidate(
622	            {
623	                outcome_score_raw: typeof row.outcome_score_raw === 'number' ? row.outcome_score_raw : null,
624	                response_time_ms: typeof row.response_time_ms === 'number' ? row.response_time_ms : null,
625	                error_code: typeof row.error_code === 'string' ? row.error_code : null,
626	                business_outcome: typeof row.business_outcome === 'string' ? row.business_outcome : null,
627	            },
628	            {
629	                outcomeScoreRaw: params.outcomeScoreRaw,
630	                responseTimeMs: params.responseTimeMs,
631	                errorCode: params.errorCode,
632	                businessOutcome: params.businessOutcome,
633	            },
634	        );
635	
636	        if (matches) {
637	            return candidateOutcomeId;
638	        }
639	    }
640	
641	    return null;
642	}
