700	
701	/**
702	 * Insert a single normalized outcome row into fact_outcomes.
703	 * All callers (SDK route + import route) go through this function.
704	 */
705	export async function ingestOutcome(
706	    row: NormalizedOutcomeRow,
707	    customerId: string,
708	    opts: IngestCoreOptions,
709	): Promise<IngestCoreResult> {
710	    // 1. Resolve task name
711	    const taskInferResult = resolveTaskName(row.task_name, row.issue_type);
712	
713	    // Preserve parser-provided mapping metadata when available.
714	    if (
715	        typeof row.task_mapping_confidence === 'number'
716	        && Number.isFinite(row.task_mapping_confidence)
717	        && typeof row.task_mapping_tier === 'string'
718	        && isTaskMappingTier(row.task_mapping_tier)
719	    ) {
720	        taskInferResult.confidence = Math.max(0, Math.min(1, row.task_mapping_confidence));
721	        taskInferResult.tier = row.task_mapping_tier;
722	        if (row.task_name && row.task_name.trim().length > 0) {
723	            taskInferResult.task = row.task_name;
724	        }
725	    }
726	
727	    // 2. Idempotency check
728	    if (row.idempotency_key) {
729	        const existing = await checkIdempotency(row.idempotency_key, customerId);
730	        if (existing) {
731	            const replayRequestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
732	            const replayExecutionStatus: ExecutionStatus = replayRequestedStatus
733	                ?? (row.success ? 'COMPLETED' : 'FAILED');
734	            const replayStatusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
735	                ?? (replayRequestedStatus ? 'explicit' : 'inferred_from_success');
736	
737	            // Return existing outcome — no duplicate insert
738	            return {
739	                outcomeId: existing,
740	                actionId: '', // Not available for idempotent replays
741	                timestamp: new Date().toISOString(),
742	                ingestionQuality: {
743	                    data_quality: 1.0,
744	                    score_origin: 'provided',
745	                    is_inconsistent: false,
746	                    mapping_tier: 'idempotent_replay',
747	                    mapping_confidence: 1.0,
748	                    inference_confidence: null,
749	                    outcome_class: null,
750	                    execution_status: replayExecutionStatus,
751	                    status_origin: replayStatusOrigin,
752	                },
753	            };
754	        }
755	    }
756	
757	    // 3. Verification — reconstruct VerifierSignal from NormalizedOutcomeRow fields.
758	    // The sync path gets verifier_signal from the SDK body directly (log-outcome.ts:1203).
759	    // The queued path stores it as verifier_source/verifier_value in the NormalizedOutcomeRow.
760	    // Both paths must apply the same hallucination correction logic.
761	    const verifierSignal = row.verifier_source
762	        ? { source: row.verifier_source as any, value: row.verifier_value ?? undefined }
763	        : undefined;
764	    const verification = resolveVerifiedSuccess(row.success, row.outcome_score ?? null, verifierSignal);
765	
766	    const computedOutcomeScoreRaw: number | null =
767	        row.outcome_score !== undefined && row.outcome_score !== null
768	            ? Math.max(0, Math.min(1, row.outcome_score))
769	            : null;
770	
771	    const computedFinalSuccess = verification.verified_success;
772	    const computedFinalOutcomeScore: number | null =
773	        verification.confidence_override !== null
774	            ? verification.confidence_override
775	            : computedOutcomeScoreRaw;
776	
777	    const finalSuccess = opts.precomputed?.finalSuccess ?? computedFinalSuccess;
778	    const finalOutcomeScore = opts.precomputed?.finalOutcomeScore ?? computedFinalOutcomeScore;
779	    const outcomeScoreRaw = opts.precomputed?.outcomeScoreRaw ?? computedOutcomeScoreRaw;
780	    const scoreOrigin: 'provided' | 'inferred' =
781	        opts.precomputed?.scoreOrigin
782	        ?? (outcomeScoreRaw !== null ? 'provided' : 'inferred');
783	
784	    const requestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
785	    if (requestedStatus && ((requestedStatus === 'COMPLETED') !== finalSuccess)) {
786	        throw new Error('STATUS_CONFLICT:execution_status conflicts with resolved success value');
787	    }
788	
789	    const scoreDerivedStatus = statusFromOutcomeScore(outcomeScoreRaw);
790	    if (requestedStatus && scoreDerivedStatus && requestedStatus !== scoreDerivedStatus) {
791	        throw new Error('STATUS_CONFLICT:execution_status conflicts with outcome_score_raw polarity');
792	    }
793	
794	    const executionStatus: ExecutionStatus = requestedStatus
795	        ?? (finalSuccess ? 'COMPLETED' : 'FAILED');
796	
797	    const statusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
798	        ?? (requestedStatus
799	            ? 'explicit'
800	            : scoreOrigin === 'inferred'
801	                ? 'inferred_from_score'
802	                : 'inferred_from_success');
803	
804	    // 4. Inconsistency + quality
805	    const computedInconsistency = evaluateInconsistencyRules({
806	        finalSuccess,
807	        outcomeScoreRaw,
808	        businessOutcome: row.business_outcome ?? null,
809	    });
810	
811	    const inconsistency = {
812	        isInconsistent: opts.precomputed?.isInconsistent ?? computedInconsistency.isInconsistent,
813	        type: opts.precomputed?.inconsistencyType ?? computedInconsistency.type,
814	        reason: opts.precomputed?.inconsistencyReason ?? computedInconsistency.reason,
815	        ruleVersion: opts.precomputed?.inconsistencyRuleVersion ?? computedInconsistency.ruleVersion,
816	    };
817	
818	    let mappingConfidence = opts.precomputed?.mappingConfidence ?? taskInferResult.confidence;
819	    const mappingTier = opts.precomputed?.mappingTier ?? taskInferResult.tier;
820	    // dataQuality computed after inference — see step 10 below
821	
822	    // 5. FK resolution
823	    const resolvedAction = opts.resolvedActionId
824	        ? {
825	            actionId: opts.resolvedActionId,
826	            resolvedActionName: opts.resolvedActionName ?? row.action_name,
827	        }
828	        : await resolveActionIdForIngest(row.action_name, customerId);
829	
830	    const actionId = resolvedAction.actionId;
831	    const resolvedActionName = resolvedAction.resolvedActionName;
832	
833	    const contextId = opts.resolvedContextId
834	        ?? await resolveContextIdForIngest(
835	            customerId,
836	            row.issue_type,
837	            row.environment,
838	            row.customer_tier,
839	        );
840	
841	    // Best-effort context vector upkeep. Never blocks ingestion.
842	    const ensureEmbedding = contextEmbed.ensureContextEmbedding?.({
843	        contextId,
844	        customerId,
845	        issueType: row.issue_type,
846	        customerTier: row.customer_tier ?? null,
847	        environment: row.environment ?? null,
848	        rawContext: row.raw_context ?? null,
849	    });
850	    if (ensureEmbedding) {
851	        ensureEmbedding.catch((err: any) => {
852	            console.warn('[ingest-core] ensureContextEmbedding failed:', err?.message ?? err);
853	        });
854	    }
855	
856	    // 6. Semantic cluster
857	    const semanticCluster: SemanticActionClusterResult = inferSemanticActionCluster({
858	        actionName: resolvedActionName,
859	        issueType: row.issue_type,
860	        taskName: taskInferResult.task,
861	    });
862	
863	    // 7. Business outcome normalization
864	    const VALID_BUSINESS_OUTCOMES = new Set(['resolved', 'partial', 'failed', 'unknown']);
865	    const normalizedBusinessOutcome = row.business_outcome
866	        ? (VALID_BUSINESS_OUTCOMES.has(row.business_outcome) ? row.business_outcome : 'unknown')
867	        : null;
868	
869	    // 8. Session ID — import rows get a stable UUID derived from idempotency key
870	    // so replay is safe. Real SDK rows always have their own session_id.
871	    const incomingSessionId = typeof row.session_id === 'string' ? row.session_id.trim() : null;
872	    const sessionId = isUuid(incomingSessionId)
873	        ? incomingSessionId
874	        : row.idempotency_key
875	            ? deterministicUuidFromSeed(`session:${row.idempotency_key}`)
876	            : crypto.randomUUID();
877	
878	    // 9. Sanitize free-text fields
879	    const safeErrorMessage = row.error_message ? sanitizeString(row.error_message, 1000) : null;
880	    const safeErrorCode = row.error_code ? sanitizeString(row.error_code, 100) : null;
881	
882	    let failureReasonCode = normalizeFailureReasonCode(row.failure_reason_code);
883	    let failureStage = normalizeFailureStage(row.failure_stage);
884	
885	    if (executionStatus === 'COMPLETED') {
886	        failureReasonCode = null;
887	        failureStage = null;
888	    } else {
889	        if (!failureReasonCode) {
890	            failureReasonCode = normalizeFailureReasonCode(safeErrorCode) ?? 'execution_failed';
891	        }
892	        if (!failureStage) {
893	            failureStage = row.feedback_signal === 'delayed'
894	                ? 'delayed_feedback'
895	                : 'action_execution';
896	        }
897	    }
898	
899	    // 10. Outcome Score Inference — 3-layer engine
900	    // When developer omits outcome_score, infer from hard + soft + relative signals.
901	    // By default this runs for live SDK rows only.
902	    // Import rows can opt in via enableInferenceWhenSkipTrust=true.
903	    let resolvedScore = finalOutcomeScore;
904	    let resolvedScoreOrigin = scoreOrigin;
905	    let resolvedScoreConfidence: number | null = null;
906	    let resolvedOutcomeClass: string | null = null;
907	
908	    const shouldInferScore =
909	        resolvedScore === null
910	        && (!opts.skipTrustUpdate || opts.enableInferenceWhenSkipTrust === true);
911	
912	    if (shouldInferScore) {
913	        const baseline = await fetchActionBaseline(row.agent_id, actionId);
914	        const inferred = inferOutcomeScore({
915	            success: finalSuccess,
916	            retryAttempt: row.retry_attempt ?? null,
917	            responseMs: row.response_time_ms ?? null,
918	            errorCode: safeErrorCode,
919	            errorMessage: safeErrorMessage,
920	            businessOutcome: normalizedBusinessOutcome,
921	            feedbackSignal: row.feedback_signal ?? null,
922	            crossEventStatus: row.cross_event_status ?? null,
923	            verifierSource: row.verifier_source ?? null,
924	            verifierValue: row.verifier_value ?? null,
925	            actionBaseline: baseline,
926	        });
927	        resolvedScore = inferred.score;
928	        resolvedScoreOrigin = 'inferred';
929	        resolvedScoreConfidence = inferred.confidence;
930	        resolvedOutcomeClass = inferred.class;
931	    }
932	
933	    // 10a. Signal contradiction feedback — degraded/uncertain outcomes
934	    // degrade mapping confidence. The outcome score itself is already adjusted
935	    // by inference; this penalizes the TASK MAPPING quality when signals disagree.
936	    if (resolvedOutcomeClass === 'degraded' || resolvedOutcomeClass === 'uncertain') {
937	        mappingConfidence = Math.max(0, mappingConfidence - 0.05);
938	    }
939	
940	    // 10b. Data quality — computed AFTER inference so penalty reflects confidence.
941	    const dataQuality = opts.precomputed?.dataQuality ?? computeOutcomeDataQuality({
942	        outcomeScoreRaw,
943	        isInconsistent: inconsistency.isInconsistent,
944	        mappingConfidence,
945	        businessOutcome: row.business_outcome ?? null,
946	        inferenceConfidence: resolvedScoreConfidence,
947	    });
948	
949	    // Import replay safety: suppress near-duplicate writes around the same
950	    // source event timestamp when payloads are semantically equivalent.
951	    const nearDuplicateWindowMs = parseNearDedupWindowMs(opts.dedupWindowMs);
952	    if (
953	        opts.ingestionSource === 'import'
954	        && nearDuplicateWindowMs > 0
955	        && opts.sourceEventAt
956	    ) {
957	        const nearDuplicateOutcomeId = await findNearDuplicateOutcome({
958	            customerId,
959	            agentId: row.agent_id,
960	            actionId,
961	            contextId,
962	            taskName: taskInferResult.task,
963	            success: finalSuccess,
964	            sourceEventAt: opts.sourceEventAt,
965	            dedupWindowMs: nearDuplicateWindowMs,
966	            outcomeScoreRaw,
967	            responseTimeMs: row.response_time_ms ?? null,
968	            errorCode: safeErrorCode,
969	            businessOutcome: normalizedBusinessOutcome,
970	        });
971	
972	        if (nearDuplicateOutcomeId) {
973	            await saveIdempotencyRecord(row.idempotency_key, nearDuplicateOutcomeId, customerId);
974	            return {
975	                outcomeId: nearDuplicateOutcomeId,
976	                actionId,
977	                timestamp: opts.sourceEventAt.toISOString(),
978	                ingestionQuality: {
979	                    data_quality: dataQuality,
980	                    score_origin: resolvedScoreOrigin,
981	                    is_inconsistent: inconsistency.isInconsistent,
982	                    mapping_tier: 'near_duplicate_replay',
983	                    mapping_confidence: mappingConfidence,
984	                    inference_confidence: resolvedScoreConfidence,
985	                    outcome_class: resolvedOutcomeClass,
986	                    execution_status: executionStatus,
987	                    status_origin: statusOrigin,
988	                },
989	            };
990	        }
991	    }
992	
993	    // 11. timestamp — use source_event_at if provided (preserves historical ordering),
994	    // else let the DB default to now().
995	    const timestampOverride = opts.sourceEventAt
996	        ? opts.sourceEventAt.toISOString()
997	        : undefined;
998	
999	    // 12. Insert
1000	    const insertPayload: Record<string, unknown> = {
1001	        agent_id: row.agent_id,
1002	        action_id: actionId,
1003	        context_id: contextId,
1004	        customer_id: customerId,
1005	        session_id: sessionId,
1006	        success: finalSuccess,
1007	        response_time_ms: row.response_time_ms ?? null,
1008	        error_code: safeErrorCode,
1009	        error_message: safeErrorMessage,
1010	        raw_context: row.raw_context ?? {},
1011	        is_synthetic: false,
1012	        ingestion_source: opts.ingestionSource,
1013	        import_job_id: opts.importJobId ?? null,
1014	        salience_score: computeSalience(actionId, contextId, customerId, finalSuccess),
1015	        outcome_score: resolvedScore ?? 0.5,
1016	        business_outcome: normalizedBusinessOutcome,
1017	        feedback_signal: row.feedback_signal ?? 'immediate',
1018	        verifier_source: row.verifier_source ?? null,
1019	        verifier_value: row.verifier_value != null ? String(row.verifier_value) : null,
1020	        discrepancy_detected: opts.precomputed?.discrepancyDetected ?? verification.discrepancy_detected,
1021	        backprop_episode_id: row.backprop_episode_id ?? null,
1022	        episode_id: row.episode_id ?? null,
1023	        signal_source: row.signal_source ?? 'explicit',
1024	        signal_confidence: row.signal_confidence ?? null,
1025	        causal_depth: row.signal_depth ?? null,
1026	        signal_pending: row.signal_pending ?? false,
1027	        signal_updated_at: null,
1028	        cross_event_status: row.cross_event_status ?? 'none',
1029	        cross_event_last_updated: new Date().toISOString(),
1030	        retry_chain_id: row.retry_chain_id ?? null,
1031	        retry_attempt: row.retry_attempt ?? null,
1032	        cross_event_attempt_count: row.cross_event_attempt_count ?? null,
1033	        canonical_outcome_id: row.canonical_outcome_id ?? null,
1034	        pending_registration_id: row.pending_registration_id ?? null,
1035	        execution_status: executionStatus,
1036	        failure_reason_code: failureReasonCode,
