46	    episodeId?: string;
47	    businessOutcome?: string;
48	    errorCode?: string | null;
49	    decisionId?: string;
50	    decisionRecord?: any;
51	    signalConfidence?: number | null;
52	    /**
53	     * When true, the trust-update task is skipped entirely.
54	     * Set by the import route — imported historical rows must never
55	     * affect agent trust scores (trust only reflects live SDK signal).
56	     */
57	    skipTrust?: boolean;
