184	// ── Deep-Get Utility ──────────────────────────────────────────
185	
186	/**
187	 * Safely retrieves a value from a nested object using a dot-path.
188	 * E.g. deepGet({ a: { b: { c: 42 } } }, "a.b.c") => 42
189	 *
190	 * Also handles array index notation: "steps.0.name"
191	 */
192	export function deepGet(obj: unknown, path: string): unknown {
193	    if (!path || obj === null || obj === undefined) return undefined;
194	
195	    const parts = path.split('.');
196	    let current: unknown = obj;
197	
198	    for (const part of parts) {
199	        if (current === null || current === undefined) return undefined;
200	
201	        if (typeof current === 'object') {
202	            // Handle array index
203	            const asIndex = Number(part);
204	            if (Array.isArray(current) && Number.isFinite(asIndex)) {
205	                current = current[asIndex];
206	            } else {
207	                current = (current as Record<string, unknown>)[part];
208	            }
209	        } else {
210	            return undefined;
211	        }
212	    }
213	
214	    return current;
215	}
