398	// ── LLM Call (Pluggable backend) ──────────────────────────────
399	
400	export interface LLMProvider {
401	    /** Send a prompt to the LLM and get a text response */
402	    complete(systemPrompt: string, userPrompt: string): Promise<string>;
403	    /** Model identifier for audit logs */
404	    modelId: string;
405	}
406	
407	/**
408	 * Default LLM provider using OpenAI-compatible API.
409	 * Expects SCHEMA_INFERRER_API_KEY and SCHEMA_INFERRER_API_URL env vars.
410	 * Falls back to Gemini Flash if not set.
411	 */
412	export function createDefaultLLMProvider(): LLMProvider | null {
413	    const apiKey = process.env.SCHEMA_INFERRER_API_KEY
414	        || process.env.OPENAI_API_KEY
415	        || process.env.GOOGLE_API_KEY;
416	
417	    let defaultUrl = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent';
418	    if (apiKey && apiKey.trim().startsWith('sk-')) {
419	        defaultUrl = 'https://api.openai.com/v1/chat/completions';
420	    }
421	
422	    const apiUrl = process.env.SCHEMA_INFERRER_API_URL || defaultUrl;
423	
424	    if (!apiKey) return null;
425	
426	    const isGemini = apiUrl.includes('generativelanguage.googleapis.com');
427	
428	    return {
429	        modelId: isGemini ? 'gemini-2.0-flash' : 'openai-compatible',
430	        async complete(systemPrompt: string, userPrompt: string): Promise<string> {
431	            if (isGemini) {
432	                const controller1 = new AbortController();
433	                const timeout1 = setTimeout(() => controller1.abort(), LLM_TIMEOUT_MS);
434	                const res = await fetch(`${apiUrl}?key=${apiKey}`, {
435	                    method: 'POST',
436	                    headers: { 'Content-Type': 'application/json' },
437	                    signal: controller1.signal,
438	                    body: JSON.stringify({
439	                        system_instruction: { parts: [{ text: systemPrompt }] },
440	                        contents: [{ parts: [{ text: userPrompt }] }],
441	                        generationConfig: {
442	                            temperature: 0,
443	                            responseMimeType: 'application/json',
444	                            maxOutputTokens: 1024,
445	                        },
446	                    }),
447	                });
448	                clearTimeout(timeout1);
449	                if (!res.ok) throw new Error(`Gemini API error: ${res.status} ${await res.text()}`);
450	                const json = await res.json() as any;
451	                return json.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
452	            }
453	
454	            // OpenAI-compatible fallback
455	            const controller2 = new AbortController();
456	            const timeout2 = setTimeout(() => controller2.abort(), LLM_TIMEOUT_MS);
457	            const res = await fetch(apiUrl, {
458	                method: 'POST',
459	                headers: {
460	                    'Content-Type': 'application/json',
461	                    'Authorization': `Bearer ${apiKey}`,
462	                },
463	                signal: controller2.signal,
464	                body: JSON.stringify({
465	                    model: process.env.SCHEMA_INFERRER_MODEL || 'gpt-4o-mini',
466	                    messages: [
467	                        { role: 'system', content: systemPrompt },
468	                        { role: 'user', content: userPrompt },
469	                    ],
470	                    temperature: 0,
471	                    max_tokens: 1024,
472	                    response_format: { type: 'json_object' },
473	                }),
474	            });
475	            clearTimeout(timeout2);
476	            if (!res.ok) throw new Error(`LLM API error: ${res.status} ${await res.text()}`);
477	            const json = await res.json() as any;
478	            return json.choices?.[0]?.message?.content ?? '';
479	        },
480	    };
481	}
482	
483	// ── Main Entry Point ──────────────────────────────────────────
484	
485	/**
486	 * Attempts to infer the schema mapping for unknown agent trace data.
487	 *
488	 * @param records - Raw parsed records (from parseFileContent)
489	 * @param provider - LLM provider (pass null to use default)
490	 * @returns InferResult with mapped records, or null if inference failed/unavailable
491	 */
492	export async function inferSchemaAndMap(
493	    records: Record<string, unknown>[],
494	    provider?: LLMProvider | null,
495	): Promise<{ result: InferResult | null; error: string | null }> {
496	    const llm = provider ?? createDefaultLLMProvider();
497	    if (!llm) {
498	        return { result: null, error: 'No LLM API key configured for schema inference (set SCHEMA_INFERRER_API_KEY)' };
499	    }
500	
501	    if (records.length === 0) {
502	        return { result: null, error: 'No records to infer' };
503	    }
504	
505	    // 0. Check cache first — avoid redundant LLM calls for same schema shape.
506	    //    On hit, re-insert to move the entry to the tail (true LRU behaviour).
507	    const fingerprint = computeSchemaFingerprint(records);
508	    const cachedMapping = mappingCache.get(fingerprint);
509	    if (cachedMapping) {
510	        // Re-insert promotes entry to tail so it won't be the next eviction victim.
511	        mappingCache.delete(fingerprint);
512	        mappingCache.set(fingerprint, cachedMapping);
513	        const mappedRecords = applyMapping(records, cachedMapping);
514	        return {
515	            result: {
516	                mapping: cachedMapping,
517	                mappedRecords,
518	                sampleCount: 0,
519	                llmModel: 'cache',
520	            },
521	            error: null,
522	        };
523	    }
524	
525	    // 1–6: Coalesce concurrent requests for the same fingerprint onto a
526	    //      single LLM call. If another request is already in-flight for
527	    //      this fingerprint, wait on its promise — zero extra API calls.
528	    const existing = inflightCalls.get(fingerprint);
529	    if (existing) {
530	        // Re-apply the mapping to THIS request's records once the
531	        // shared call resolves (the in-flight result carries the mapping,
532	        // not the caller's specific rows).
533	        const shared = await existing;
534	        if (shared.result) {
535	            return {
536	                result: {
537	                    mapping: shared.result.mapping,
538	                    mappedRecords: applyMapping(records, shared.result.mapping),
539	                    sampleCount: 0,
540	                    llmModel: 'inflight-dedup',
541	                },
542	                error: null,
543	            };
544	        }
545	        return shared; // propagate the error from the original call
546	    }
547	
548	    const inferencePromise = (async () => {
549	        // 1. Sample records (limit JSON size to avoid token bloat)
550	        const sampleCount = Math.min(SAMPLE_SIZE, records.length);
551	        let samples = records.slice(0, sampleCount);
552	
553	        // Truncate if samples are too large
554	        let samplesJson = JSON.stringify(samples, null, 2);
555	        if (samplesJson.length > MAX_SAMPLE_JSON_LENGTH) {
556	            samples = records.slice(0, 3);
557	            samplesJson = JSON.stringify(samples, null, 2);
558	            if (samplesJson.length > MAX_SAMPLE_JSON_LENGTH) {
559	                samples = samples.map((r) => {
560	                    const truncated: Record<string, unknown> = {};
561	                    let charCount = 0;
562	                    for (const [k, v] of Object.entries(r)) {
563	                        const valStr = JSON.stringify(v);
564	                        charCount += k.length + valStr.length;
565	                        if (charCount > 1500) break;
566	                        truncated[k] = v;
567	                    }
568	                    return truncated;
569	                });
570	            }
571	        }
572	
573	        // 2. Call LLM
574	        const userPrompt = buildUserPrompt(samples);
575	        let llmResponse: string;
576	        try {
577	            llmResponse = await llm.complete(SYSTEM_PROMPT, userPrompt);
578	        } catch (err) {
579	            return { result: null, error: `LLM call failed: ${(err as Error).message}` };
580	        }
581	
582	        // 3. Parse LLM response
583	        let parsedResponse: unknown;
584	        try {
585	            const cleaned = llmResponse
586	                .replace(/^```(?:json)?\s*/i, '')
587	                .replace(/\s*```\s*$/i, '')
588	                .trim();
589	            parsedResponse = JSON.parse(cleaned);
590	        } catch {
591	            return { result: null, error: `LLM returned invalid JSON: ${llmResponse.slice(0, 200)}` };
592	        }
593	
594	        // 4. Validate mapping structure
595	        const { mapping, error: validationError } = validateMapping(parsedResponse);
596	        if (!mapping) {
597	            return { result: null, error: `Invalid mapping: ${validationError}` };
598	        }
599	
600	        // 5. Spot-check against real data
601	        const spotCheck = spotCheckMapping(mapping, records.slice(0, sampleCount));
602	        if (!spotCheck.valid) {
603	            return { result: null, error: `Mapping spot-check failed: ${spotCheck.error}` };
604	        }
605	
606	        // 6. Populate LRU cache for future requests.
607	        if (mappingCache.size >= MAX_CACHE_SIZE) {
608	            const lruKey = mappingCache.keys().next().value;
609	            if (lruKey) mappingCache.delete(lruKey);
610	        }
611	        mappingCache.set(fingerprint, mapping);
612	
613	        // 7. Apply mapping to THIS request's records (deterministic, no LLM)
614	        const mappedRecords = applyMapping(records, mapping);
615	        return {
616	            result: { mapping, mappedRecords, sampleCount, llmModel: llm.modelId },
617	            error: null,
618	        };
619	    })().finally(() => {
620	        // Remove from in-flight map once settled so the next cold-start
621	        // goes through the LRU cache path (not another in-flight wait).
622	        inflightCalls.delete(fingerprint);
623	    });
624	
625	    inflightCalls.set(fingerprint, inferencePromise);
626	    return inferencePromise;
627	}
628	
629	// ── Quick Check: Does standard parsing already work? ──────────
630	
631	/**
632	 * Checks if standard field extraction already works on the records.
633	 * If action_name and success can be found without LLM help, returns true.
634	 * Used to short-circuit the LLM call when it's not needed.
635	 */
636	export function standardFieldsPresent(records: Record<string, unknown>[]): boolean {
637	    const ACTION_FIELDS = ['action_name', 'action', 'action_taken', 'handler', 'function_name'];
638	    const SUCCESS_FIELDS = ['success', 'result', 'outcome', 'status', 'passed', 'succeeded'];
639	
640	    const testRecords = records.slice(0, 3);
641	    let actionHits = 0;
642	    let successHits = 0;
643	
644	    for (const rec of testRecords) {
645	        for (const field of ACTION_FIELDS) {
646	            const val = rec[field] ?? rec[field.toUpperCase()] ?? rec[field.toLowerCase()];
647	            if (val !== undefined && val !== null && String(val).trim().length > 0) {
648	                actionHits++;
649	                break;
650	            }
651	        }
652	        for (const field of SUCCESS_FIELDS) {
653	            const val = rec[field] ?? rec[field.toUpperCase()] ?? rec[field.toLowerCase()];
654	            if (val !== undefined && val !== null) {
655	                successHits++;
656	                break;
657	            }
658	        }
659	    }
660	
661	    return actionHits >= 2 && successHits >= 2;
662	}
