1	/**
2	 * Layerinfinite — lib/predictive-drift.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Predictive drift detection using sliding window linear regression.
5	 *
6	 * Analyzes the last N outcomes for an action and projects whether
7	 * the success rate / outcome score is trending toward a failure
8	 * threshold. Emits a `predicted_drift` alert to degradation_alert_events
9	 * BEFORE the action actually degrades.
10	 *
11	 * Algorithm:
12	 *   1. Fetch last 20 outcomes for (action_id, customer_id)
13	 *   2. Compute simple linear regression: y = a + bx
14	 *      where y = outcome_score, x = sequence index (0..19)
15	 *   3. Project score at x = 30 (10 outcomes into the future)
16	 *   4. If projected score < threshold: emit predicted_drift alert
17	 *   5. Deduplicate: one alert per action per 24h window
18	 * ══════════════════════════════════════════════════════════════
19	 */
20	
21	import { supabase } from './supabase.js';
22	
23	// ── Config ────────────────────────────────────────────────────
24	
25	const MIN_SAMPLES = 20;
26	const PROJECTION_HORIZON = 10; // project N outcomes into the future
27	const DEGRADATION_THRESHOLD = 0.35; // projected score below this triggers alert
28	const ALERT_DEDUP_HOURS = 24;
29	
30	// ── Linear Regression ─────────────────────────────────────────
31	
32	export interface RegressionResult {
33	    slope: number;       // b: change in score per outcome
34	    intercept: number;   // a: baseline score at x=0
35	    r2: number;          // R² goodness of fit (0-1)
36	    projectedScore: number; // score at x = n + PROJECTION_HORIZON
37	}
38	
39	/**
40	 * Simple linear regression: y = a + bx
41	 * Returns slope, intercept, R², and projected score.
42	 */
43	export function linearRegression(scores: number[]): RegressionResult {
44	    const n = scores.length;
45	    if (n < 2) {
46	        return { slope: 0, intercept: scores[0] ?? 0.5, r2: 0, projectedScore: scores[0] ?? 0.5 };
47	    }
48	
49	    let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0, sumY2 = 0;
50	
51	    for (let i = 0; i < n; i++) {
52	        sumX += i;
53	        sumY += scores[i];
54	        sumXY += i * scores[i];
55	        sumX2 += i * i;
56	        sumY2 += scores[i] * scores[i];
57	    }
58	
59	    const denominator = n * sumX2 - sumX * sumX;
60	    if (denominator === 0) {
61	        const avg = sumY / n;
62	        return { slope: 0, intercept: avg, r2: 0, projectedScore: avg };
63	    }
64	
65	    const slope = (n * sumXY - sumX * sumY) / denominator;
66	    const intercept = (sumY - slope * sumX) / n;
67	
68	    // R² calculation
69	    const ssRes = scores.reduce((acc, y, i) => {
70	        const predicted = intercept + slope * i;
71	        return acc + (y - predicted) ** 2;
72	    }, 0);
73	    const mean = sumY / n;
74	    const ssTot = scores.reduce((acc, y) => acc + (y - mean) ** 2, 0);
75	    const r2 = ssTot === 0 ? 1 : Math.max(0, 1 - ssRes / ssTot);
76	
77	    const projectedScore = intercept + slope * (n - 1 + PROJECTION_HORIZON);
78	
79	    return {
80	        slope: Number(slope.toFixed(6)),
81	        intercept: Number(intercept.toFixed(4)),
82	        r2: Number(r2.toFixed(4)),
83	        projectedScore: Number(Math.max(0, Math.min(1, projectedScore)).toFixed(4)),
84	    };
85	}
86	
87	// ── Drift Prediction ──────────────────────────────────────────
88	
89	export interface DriftPrediction {
90	    predicted: boolean;
91	    regression: RegressionResult | null;
92	    alertEmitted: boolean;
93	    reason: string | null;
94	}
95	
96	/**
97	 * Checks whether an action is trending toward degradation.
98	 * Only runs when the action has ≥ MIN_SAMPLES outcomes.
99	 *
100	 * @param actionId - The action to analyze
101	 * @param customerId - Customer context
102	 * @param agentId - Agent context (for alert metadata)
103	 * @param actionName - Human-readable action name (for alert message)
104	 */
105	export async function predictDrift(
106	    actionId: string,
107	    customerId: string,
108	    agentId: string,
109	    actionName: string,
110	): Promise<DriftPrediction> {
111	    // 1. Fetch recent outcomes
112	    const { data: outcomes } = await supabase
113	        .from('fact_outcomes')
114	        .select('outcome_score')
115	        .eq('action_id', actionId)
116	        .eq('customer_id', customerId)
117	        .eq('is_deleted', false)
118	        .order('timestamp', { ascending: false })
119	        .limit(MIN_SAMPLES);
120	
121	    if (!outcomes || outcomes.length < MIN_SAMPLES) {
122	        return { predicted: false, regression: null, alertEmitted: false, reason: 'insufficient_data' };
123	    }
124	
125	    // Reverse to chronological order (oldest first)
126	    const scores = outcomes
127	        .reverse()
128	        .map(o => typeof o.outcome_score === 'number' ? o.outcome_score : 0.5);
129	
130	    // 2. Run regression
131	    const regression = linearRegression(scores);
132	
133	    // 3. Check if trending down significantly
134	    if (regression.slope >= 0) {
135	        return { predicted: false, regression, alertEmitted: false, reason: 'trend_stable_or_improving' };
136	    }
137	
138	    if (regression.projectedScore >= DEGRADATION_THRESHOLD) {
139	        return { predicted: false, regression, alertEmitted: false, reason: 'projection_above_threshold' };
140	    }
141	
142	    // Require minimum R² to avoid noisy regressions
143	    if (regression.r2 < 0.15) {
144	        return { predicted: false, regression, alertEmitted: false, reason: 'low_confidence_fit' };
145	    }
146	
147	    // 4. Deduplicate: check for existing alert in last 24h
148	    const dedupWindow = new Date(Date.now() - ALERT_DEDUP_HOURS * 60 * 60 * 1000).toISOString();
149	    const { data: existing } = await supabase
150	        .from('degradation_alert_events')
151	        .select('id')
152	        .eq('customer_id', customerId)
153	        .eq('action_id', actionId)
154	        .eq('alert_type', 'predicted_drift')
155	        .gte('created_at', dedupWindow)
156	        .limit(1);
157	
158	    if (existing && existing.length > 0) {
159	        return { predicted: true, regression, alertEmitted: false, reason: 'alert_already_exists' };
160	    }
161	
162	    // 5. Emit alert
163	    const currentAvg = scores.slice(-5).reduce((a, b) => a + b, 0) / 5;
164	    await supabase.from('degradation_alert_events').insert({
165	        customer_id: customerId,
166	        agent_id: agentId,
167	        action_id: actionId,
168	        alert_type: 'predicted_drift',
169	        severity: 'warning',
170	        message:
171	            `Predictive drift detected on action "${actionName}". ` +
172	            `Current avg score: ${currentAvg.toFixed(3)}, projected score in ${PROJECTION_HORIZON} outcomes: ${regression.projectedScore}. ` +
173	            `Trend slope: ${regression.slope}/outcome (R²=${regression.r2}).`,
174	    });
175	
176	    return { predicted: true, regression, alertEmitted: true, reason: null };
177	}
