3	export function verifySharedSecret(expectedSecret: string | undefined, providedSecret: string | undefined): boolean {
4	    if (!expectedSecret) return false;
5	
6	    const expected = Buffer.from(expectedSecret);
7	    const provided = Buffer.from(providedSecret ?? '');
8	
9	    if (expected.length === 0 || expected.length !== provided.length) {
10	        return false;
11	    }
12	
13	    return crypto.timingSafeEqual(expected, provided);
14	}
15	
16	export function verifyStripeSignature(
17	    rawBody: string,
18	    signatureHeader: string | undefined,
19	    signingSecret: string | undefined,
20	    toleranceSeconds = 300,
21	    nowSeconds = Math.floor(Date.now() / 1000),
22	): boolean {
23	    if (!signatureHeader || !signingSecret) return false;
24	
25	    let timestamp: number | null = null;
26	    const v1Candidates: string[] = [];
27	
28	    for (const part of signatureHeader.split(',')) {
29	        const [key, value] = part.trim().split('=', 2);
30	        if (!key || !value) continue;
31	
32	        if (key === 't') {
33	            const parsed = Number(value);
34	            timestamp = Number.isFinite(parsed) ? parsed : null;
35	        }
36	
37	        if (key === 'v1') {
38	            v1Candidates.push(value.toLowerCase());
39	        }
40	    }
41	
42	    if (timestamp === null || v1Candidates.length === 0) {
43	        return false;
44	    }
45	
46	    const ageSeconds = Math.abs(nowSeconds - timestamp);
47	    if (ageSeconds > Math.max(1, toleranceSeconds)) {
48	        return false;
49	    }
50	
51	    const signedPayload = `${timestamp}.${rawBody}`;
52	    const expectedSignature = crypto
53	        .createHmac('sha256', signingSecret)
54	        .update(signedPayload)
55	        .digest('hex')
56	        .toLowerCase();
57	
58	    for (const candidate of v1Candidates) {
59	        if (verifySharedSecret(expectedSignature, candidate)) {
60	            return true;
61	        }
62	    }
63	
64	    return false;
65	}
66	
67	export function verifySendgridSignature(
68	    rawBody: string,
69	    timestampHeader: string | undefined,
70	    signatureHeader: string | undefined,
71	    publicKeyPem: string | undefined,
72	): boolean {
73	    if (!timestampHeader || !signatureHeader || !publicKeyPem) {
74	        return false;
75	    }
76	
77	    try {
78	        const verifier = crypto.createVerify('sha256');
79	        verifier.update(`${timestampHeader}${rawBody}`);
80	        verifier.end();
81	        return verifier.verify(publicKeyPem, signatureHeader, 'base64');
82	    } catch {
83	        return false;
84	    }
85	}

1	/**
2	 * Layerinfinite — lib/simulation/tier-selector.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Automatic tier selection per prediction.
5	 * Central orchestration of all three tiers.
6	 * Returns the best prediction the data supports.
7	 *
8	 * Selection logic:
9	 *   Tier 3 if: episodes >= 1000 AND model loaded AND CI < 0.25
10	 *   Tier 2 if: episodes >= 200 AND model loaded
11	 *   Tier 1 always (fallback)
12	 *
13	 * Never throws — returns Tier 1 result on any error.
14	 * ══════════════════════════════════════════════════════════════
15	 */
16	
17	import { supabase } from '../supabase.js';
18	import { loadWorldModel } from './world-model.js';
19	import { tier1Predict, tier1FindAlternatives } from './tier1.js';
20	import { tier2Predict } from './tier2.js';
21	import { tier3MCTS } from './tier3-mcts.js';
22	import type {
23	  SimulationRequest,
24	  SimulationResult,
25	  WorldModelArtifact,
26	} from './types.js';
27	
28	const TIER2_MIN_EPISODES = 200;
29	const TIER3_MIN_EPISODES = 1000;
30	const TIER2_CONFIDENCE_MAX_WIDTH = 0.25;
31	
32	/**
33	 * Count relevant episodes for this agent + context type.
34	 */
35	async function countEpisodes(
36	  agentId: string,
37	  contextHash: string,
38	  customerId: string,
39	): Promise<number> {
40	  const { count } = await supabase
41	    .from('fact_outcomes')
42	    .select('*', { count: 'exact', head: true })
43	    .eq('customer_id', customerId)
44	    .eq('agent_id', agentId)
45	    .eq('context_hash', contextHash);
46	
47	  return count ?? 0;
48	}
49	
50	/**
51	 * Get context frequency (normalized, 0–1) for model features.
52	 */
53	async function getContextFrequency(
54	  customerId: string,
55	  contextHash: string,
56	): Promise<number> {
57	  const [{ count: contextCount }, { count: totalCount }] =
58	    await Promise.all([
59	      supabase
60	        .from('fact_outcomes')
61	        .select('*', { count: 'exact', head: true })
62	        .eq('customer_id', customerId)
63	        .eq('context_hash', contextHash),
64	      supabase
65	        .from('fact_outcomes')
66	        .select('*', { count: 'exact', head: true })
67	        .eq('customer_id', customerId),
68	    ]);
69	
70	  if (!totalCount || totalCount === 0) return 0.5;
71	  return Math.min(1.0, (contextCount ?? 0) / totalCount);
72	}
73	
74	/**
75	 * Get all valid action names for an agent.
76	 * Used by MCTS to enumerate the action space.
77	 */
78	async function getAgentActions(agentId: string): Promise<string[]> {
79	  const { data } = await supabase
80	    .from('dim_actions')
81	    .select('action_name')
82	    .eq('agent_id', agentId);
83	
84	  return (data ?? []).map((a: any) => a.action_name);
85	}
86	
87	/**
88	 * Generate human-readable tier explanation.
89	 */
90	function buildTierExplanation(
91	  tier: 1 | 2 | 3,
92	  episodeCount: number,
93	  modelLoaded: boolean,
94	): string {
95	  if (tier === 3) {
96	    return (
97	      `Planning mode (Tier 3): MCTS over learned world model. ` +
98	      `${episodeCount} episodes available. ` +
99	      `Searching optimal multi-step sequence.`
100	    );
101	  }
102	  if (tier === 2) {
103	    const remaining = TIER3_MIN_EPISODES - episodeCount;
104	    return (
105	      `Statistical model (Tier 2): LightGBM prediction. ` +
106	      `${episodeCount} episodes available. ` +
107	      `Tier 3 planning unlocks after ${remaining} more episodes.`
108	    );
109	  }
110	  if (!modelLoaded) {
111	    const remaining = Math.max(0, TIER2_MIN_EPISODES - episodeCount);
112	    return (
113	      `Historical analysis (Tier 1): Wilson CI on observations. ` +
114	      `${episodeCount} episodes available. ` +
115	      `Statistical model trains after ${remaining} more episodes.`
116	    );
117	  }
118	  return (
119	    `Historical analysis (Tier 1): Wilson CI on observations. ` +
120	    `${episodeCount} episodes available. ` +
121	    `Model confidence too low for Tier 2 this context.`
122	  );
123	}
124	
125	/**
126	 * Main entry point: run simulation and return result.
127	 * Automatically selects the highest eligible tier.
128	 * Never throws — returns Tier 1 result on any error.
129	 */
130	export async function runSimulation(
131	  request: SimulationRequest,
132	): Promise<SimulationResult> {
133	  try {
134	    const [episodeCount, contextFreq, allActions, model] =
135	      await Promise.all([
136	        countEpisodes(request.agentId, request.contextHash, request.customerId),
137	        getContextFrequency(request.customerId, request.contextHash),
138	        getAgentActions(request.agentId),
139	        loadWorldModel(request.customerId),
140	      ]);
141	
142	    const modelLoaded = model !== null;
143	
144	    // Determine tier
145	    let tier: 1 | 2 | 3 = 1;
146	
147	    if (episodeCount >= TIER3_MIN_EPISODES && modelLoaded) {
148	      tier = 3;
149	    } else if (episodeCount >= TIER2_MIN_EPISODES && modelLoaded) {
150	      tier = 2;
151	    }
152	
153	    // Run prediction for proposed sequence
154	    let primaryPrediction = null;
155	    let actualTier: 1 | 2 | 3 = tier;
156	
157	    if (tier === 3) {
158	      primaryPrediction = await tier3MCTS(
159	        request,
160	        allActions,
161	        contextFreq,
162	      ).catch((err) => {
163	        console.error('[SimEngine] MCTS failed, falling back:', err);
164	        return null;
165	      });
166	
167	      if (!primaryPrediction) {
168	        actualTier = 2; // fall back
169	      }
170	    }
171	
172	    if (!primaryPrediction && (tier === 2 || actualTier === 2)) {
173	      const tier2Result = await tier2Predict(request, contextFreq).catch(
174	        () => null,
175	      );
176	
177	      if (tier2Result === null) {
178	        // No model artifact returned. Only try MCTS if this is the first time attempting
179	        // it — i.e., tier was originally 2 (MCTS not yet tried). If tier was 3, MCTS
180	        // already ran and failed above, so retrying it here is redundant and will fail again.
181	        // modelLoaded check: loadWorldModel returned null in the initial
182	        // Promise.all above. MCTS also requires a world model — attempting
183	        // it when modelLoaded=false would return null immediately.
184	        // Skip straight to Tier 1 fallback.
185	        if (tier === 2 && modelLoaded) {
186	          console.info('[tier-selector] No world model for customer — falling back to Tier 3 MCTS', {
187	            customerId: request.customerId,
188	          });
189	          primaryPrediction = await tier3MCTS(request, allActions, contextFreq).catch((err) => {
190	            console.error('[SimEngine] MCTS fallback failed:', err);
191	            return null;
192	          });
193	          if (primaryPrediction) actualTier = 3;
194	        }
195	        // If tier === 3: MCTS was already attempted above and failed — skip straight to tier1.
196	      } else if (tier2Result.confidenceWidth <= TIER2_CONFIDENCE_MAX_WIDTH) {
197	        primaryPrediction = tier2Result;
198	        actualTier = 2;
199	      }
200	      // else: model exists but low confidence — fall through to tier1
201	      if (!primaryPrediction) actualTier = 1;
202	    }
203	
204	    if (!primaryPrediction) {
205	      primaryPrediction = await tier1Predict(request);
206	      actualTier = 1;
207	    }
208	
209	    primaryPrediction.betterThanProposed = false;
210	
211	    // Find alternatives if requested
212	    let alternatives = tier1FindAlternatives(
213	      request,
214	      primaryPrediction.predictedOutcome,
215	      0,
216	    );
217	    if (request.simulateAlternatives > 0) {
218	      alternatives = tier1FindAlternatives(
219	        request,
220	        primaryPrediction.predictedOutcome,
221	        request.simulateAlternatives,
222	      );
223	    }
224	
225	    const resolvedAlternatives = (await alternatives).map((alt) => ({
226	      ...alt,
227	      betterThanProposed:
228	        alt.predictedOutcome > primaryPrediction!.predictedOutcome,
229	    }));
230	
231	    const tierExplanation = buildTierExplanation(
232	      actualTier,
233	      episodeCount,
234	      modelLoaded,
235	    );
236	
237	    const dataSource =
238	      modelLoaded && actualTier >= 2
239	        ? `LightGBM v${(model as WorldModelArtifact).version} trained on ` +
240	        `${(model as WorldModelArtifact).training_episodes} episodes ` +
241	        `(${new Date((model as WorldModelArtifact).trained_at).toISOString().split('T')[0]})`
242	        : `${episodeCount} historical episodes (Wilson CI)`;
243	
244	    const simulationWarning =
245	      primaryPrediction.confidence < 0.4
246	        ? `Low confidence prediction (${(primaryPrediction.confidence * 100).toFixed(0)}%). ` +
247	        `Prediction interval is wide: ` +
248	        `[${primaryPrediction.outcomeIntervalLow.toFixed(2)}, ` +
249	        `${primaryPrediction.outcomeIntervalHigh.toFixed(2)}]. ` +
250	        `Collect more real episodes to improve accuracy.`
251	        : null;
252	
253	    return {
254	      primary: primaryPrediction,
255	      alternatives: resolvedAlternatives,
256	      simulationTier: actualTier,
257	      tierExplanation,
258	      dataSource,
259	      episodeCount,
260	      simulationWarning,
261	    };
262	  } catch (err) {
263	    console.error('[SimEngine] Fatal runSimulation error, returning safe Tier 1 fallback:', err);
264	    return {
265	      primary: {
266	        actions: request.proposedSequence,
267	        predictedOutcome: 0.5,
268	        outcomeIntervalLow: 0.1,
269	        outcomeIntervalHigh: 0.9,
270	        confidenceWidth: 0.8,
271	        confidence: 0.2,
272	        predictedResolution: 0.5,
273	        predictedSteps: 2,
274	        betterThanProposed: false
275	      },
276	      alternatives: [],
277	      simulationTier: 1,
278	      tierExplanation: 'Historical analysis (Tier 1): Wilson CI on observations. 0 episodes available. Statistical model trains after 200 more episodes.',
279	      dataSource: '0 historical episodes (Wilson CI)',
280	      episodeCount: 0,
281	      simulationWarning: 'Low confidence prediction (20%). Prediction interval is wide: [0.10, 0.90]. Collect more real episodes to improve accuracy.'
282	    };
283	  }
284	}
