1	/**
2	 * Layerinfinite — lib/simulation/types.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Shared type definitions for the 3-tier simulation engine.
5	 * Everything depends on this — no runtime code, types only.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	export interface SimulationRequest {
10	  customerId:           string;     // tenant scoping for world model lookup
11	  agentId:              string;
12	  context:              Record<string, unknown>;
13	  contextHash:          string;
14	  proposedSequence:     string[];   // sequence to evaluate
15	  episodeHistory:       string[];   // actions already taken
16	  simulateAlternatives: number;     // how many alternatives (0-3)
17	  maxSequenceDepth:     number;     // max steps to plan (default 5)
18	}
19	
20	export interface SequencePrediction {
21	  actions:             string[];
22	  predictedOutcome:    number;      // 0.0–1.0 point estimate
23	  outcomeIntervalLow:  number;     // lower 95% bound
24	  outcomeIntervalHigh: number;     // upper 95% bound
25	  confidenceWidth:     number;     // interval width (key metric)
26	  confidence:          number;     // 1 - (confidenceWidth / 2)
27	  predictedResolution: number;     // probability of resolving
28	  predictedSteps:      number;     // expected steps to resolution
29	  betterThanProposed:  boolean;    // is this better than primary?
30	}
31	
32	export interface SimulationResult {
33	  primary:            SequencePrediction;
34	  alternatives:       SequencePrediction[];
35	  simulationTier:     1 | 2 | 3;
36	  tierExplanation:    string;
37	  dataSource:         string;
38	  episodeCount:       number;
39	  simulationWarning:  string | null;
40	}
41	
42	export interface WorldModelPrediction {
43	  q50:          number;                       // median prediction
44	  q025:         number;                       // lower 95% bound
45	  q975:         number;                       // upper 95% bound
46	  width:        number;                       // q975 - q025
47	  model_source: 'production' | 'canary';     // which model served this prediction
48	}
49	
50	// LightGBM tree structure (JSON-serialized from Python)
51	export interface LGBMTree {
52	  num_leaves:    number;
53	  split_index:   number[];
54	  split_feature: number[];
55	  threshold:     (number | string)[];
56	  decision_type: string[];
57	  left_child:    number[];
58	  right_child:   number[];
59	  leaf_value:    number[];
60	}
61	
62	export interface WorldModelArtifact {
63	  q50:               { trees: LGBMTree[]; num_trees: number };
64	  q025:              { trees: LGBMTree[]; num_trees: number };
65	  q975:              { trees: LGBMTree[]; num_trees: number };
66	  feature_names:     string[];
67	  num_features:      number;
68	  action_encoding:   Record<string, number>;
69	  context_encoding:  Record<string, Record<string, number>>;
70	  learning_rate:     number;
71	  trained_at:        string;
72	  version:           number;
73	  training_episodes: number;
74	  // Canary routing fields (populated from DB row at load time)
75	  is_canary:         boolean;
