1	/**
2	 * Layerinfinite — lib/simulation/tier2.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Tier 2 simulation using LightGBM model.
5	 * Available after 200 episodes and model training.
6	 * Returns prediction intervals, not just point estimates.
7	 *
8	 * Multi-step aggregation:
9	 *   - Single-step → direct prediction
10	 *   - Multi-step → geometric mean (penalizes long sequences)
11	 *   - Intervals widen with sequence length
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { predictOutcome, loadWorldModel } from './world-model.js';
16	import type { SequencePrediction, SimulationRequest } from './types.js';
17	
18	/**
19	 * Predict outcome for a proposed sequence using Tier 2 model.
20	 *
21	 * For multi-step sequences, predict each step independently
22	 * and combine using conservative aggregation:
23	 *   - Predicted outcome = geometric mean of per-step probabilities
24	 *     (penalizes long sequences appropriately)
25	 *   - Confidence interval widens with sequence length
26	 */
27	export async function tier2Predict(
28	  request: SimulationRequest,
29	  contextFreq: number,
30	): Promise<SequencePrediction | null> {
31	  const model = await loadWorldModel(request.customerId);
32	  if (!model) return null;
33	
34	  const sequence = [
35	    ...request.episodeHistory,
36	    ...request.proposedSequence,
37	  ];
38	
39	  // Predict each step in the proposed sequence
40	  const stepPredictions = await Promise.all(
41	    request.proposedSequence.map(async (action, stepIdx) => {
42	      const history = sequence.slice(
43	        0,
44	        request.episodeHistory.length + stepIdx,
45	      );
46	
47	      return predictOutcome(request.customerId, action, history, request.contextHash, contextFreq);
48	    }),
49	  );
50	
51	  // If any action in the sequence is unknown to the model,
52	  // return null (fall back to Tier 1)
53	  if (stepPredictions.some((p) => p === null)) {
54	    return null;
55	  }
56	
57	  const predictions = stepPredictions as NonNullable<
58	    (typeof stepPredictions)[0]
59	  >[];
60	
61	  // Aggregate multi-step predictions
62	  let aggregateQ50: number;
63	  let aggregateQ025: number;
64	  let aggregateQ975: number;
65	
66	  if (predictions.length === 1) {
67	    aggregateQ50 = predictions[0]!.q50;
68	    aggregateQ025 = predictions[0]!.q025;
69	    aggregateQ975 = predictions[0]!.q975;
70	  } else {
71	    // Multi-step: geometric mean penalizes long sequences
72	    const product = predictions.reduce((acc, p) => acc * p.q50, 1.0);
73	    aggregateQ50 = Math.pow(product, 1 / predictions.length);
74	
75	    // Interval widens: outer predictions bound the aggregate
76	    aggregateQ025 = Math.min(...predictions.map((p) => p.q025));
77	    aggregateQ975 = Math.max(...predictions.map((p) => p.q975));
78	  }
79	
80	  const width = aggregateQ975 - aggregateQ025;
81	
82	  return {
83	    actions: [...request.episodeHistory, ...request.proposedSequence],
84	    predictedOutcome: Math.round(aggregateQ50 * 10000) / 10000,
85	    outcomeIntervalLow: Math.round(aggregateQ025 * 10000) / 10000,
86	    outcomeIntervalHigh: Math.round(aggregateQ975 * 10000) / 10000,
87	    confidenceWidth: Math.round(width * 10000) / 10000,
88	    confidence: Math.max(0.0, 1.0 - width),
89	    predictedResolution:
90	      aggregateQ50 >= 0.7 ? aggregateQ50 : aggregateQ50 * 0.8,
91	    predictedSteps: request.proposedSequence.length,
92	    betterThanProposed: false,
93	  };
94	}
95

1	/**
2	 * Layerinfinite — lib/simulation/tier3-mcts.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Tier 3: Monte Carlo Tree Search over the Tier 2 world model.
5	 * Finds the optimal multi-step sequence, not just scores
6	 * a proposed one.
7	 *
8	 * Available after 1000 real episodes.
9	 * 500 simulations per call. Inference: <100ms.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { predictOutcome, loadWorldModel } from './world-model.js';
14	import type { SequencePrediction, SimulationRequest } from './types.js';
15	
16	const UCT_C = Math.SQRT2;       // exploration constant
17	const MAX_DEPTH = 5;             // max sequence length
18	const NUM_SIMS = 500;            // simulations per call
19	// eslint-disable-next-line @typescript-eslint/no-unused-vars
20	const _MIN_VISITS_EXPAND = 1;    // expand after 1 visit
21	
22	interface MCTSNode {
23	  action: string | null;         // null for root
24	  parent: MCTSNode | null;
25	  children: MCTSNode[];
26	  visits: number;
27	  totalValue: number;
28	  untriedActions: string[];
29	  depth: number;
30	}
31	
32	/**
33	 * Compute UCT score for node selection.
34	 * UCT = exploitation + exploration
35	 *     = Q/N + C * sqrt(ln(N_parent) / N)
36	 */
37	function uctScore(node: MCTSNode): number {
38	  if (node.visits === 0) return Infinity;
39	
40	  const exploitation = node.totalValue / node.visits;
41	  const exploration =
42	    UCT_C * Math.sqrt(Math.log(node.parent!.visits) / node.visits);
43	
44	  return exploitation + exploration;
45	}
46	
47	/**
48	 * Get the sequence of actions from root to this node.
49	 */
50	function pathToNode(node: MCTSNode): string[] {
51	  const path: string[] = [];
52	  let current: MCTSNode | null = node;
53	
54	  while (current && current.action !== null) {
55	    path.unshift(current.action);
56	    current = current.parent;
57	  }
58	
59	  return path;
60	}
61	
62	/**
63	 * Select the most promising leaf using UCT.
64	 */
65	function select(root: MCTSNode): MCTSNode {
66	  let node = root;
67	
68	  while (node.children.length > 0 && node.untriedActions.length === 0) {
69	    node = node.children.reduce((best, child) =>
70	      uctScore(child) > uctScore(best) ? child : best,
71	    );
72	  }
73	
74	  return node;
75	}
76	
77	/**
78	 * Expand the node by adding one untried child.
79	 */
80	function expand(
81	  node: MCTSNode,
82	  allActions: string[],
83	): MCTSNode {
84	  if (node.untriedActions.length === 0) return node;
85	
86	  // Pick random untried action
87	  const idx = Math.floor(Math.random() * node.untriedActions.length);
88	  const action = node.untriedActions.splice(idx, 1)[0]!;
89	
90	  const child: MCTSNode = {
91	    action,
92	    parent: node,
93	    children: [],
94	    visits: 0,
95	    totalValue: 0,
96	    untriedActions:
97	      node.depth + 1 < MAX_DEPTH ? [...allActions] : [],
98	    depth: node.depth + 1,
99	  };
100	
101	  node.children.push(child);
102	  return child;
103	}
104	
105	/**
106	 * Simulate (rollout) from a node using the Tier 2 world model.
107	 * Returns predicted outcome value for the sequence.
108	 */
109	async function rollout(
110	  node: MCTSNode,
111	  customerId: string,
112	  episodeHistory: string[],
113	  contextHash: string,
114	  contextFreq: number,
115	): Promise<number> {
116	  const sequence = pathToNode(node);
117	
118	  if (sequence.length === 0) return 0.5; // root node default
119	
120	  const fullHistory = [...episodeHistory, ...sequence.slice(0, -1)];
121	  const action = sequence[sequence.length - 1]!;
122	
123	  const prediction = await predictOutcome(
124	    customerId,
125	    action,
126	    fullHistory,
127	    contextHash,
128	    contextFreq,
129	  );
130	
131	  return prediction?.q50 ?? 0.5; // fallback to 0.5 if unknown
132	}
133	
134	/**
135	 * Backpropagate value from leaf to root.
136	 */
137	function backpropagate(node: MCTSNode, value: number): void {
138	  let current: MCTSNode | null = node;
139	
140	  while (current !== null) {
141	    current.visits += 1;
142	    current.totalValue += value;
143	    current = current.parent;
144	  }
145	}
146	
147	/**
148	 * Extract the best sequence from the MCTS tree.
149	 * Uses most-visited child at each level (robust policy).
150	 */
151	function extractBestSequence(root: MCTSNode): {
152	  sequence: string[];
153	  expectedOutcome: number;
154	  visits: number;
155	} {
156	  const sequence: string[] = [];
157	  let current = root;
158	
159	  while (current.children.length > 0) {
160	    const best = current.children.reduce((a, b) =>
161	      a.visits > b.visits ? a : b,
162	    );
163	
164	    if (best.action) sequence.push(best.action);
165	    current = best;
166	
167	    if (sequence.length >= MAX_DEPTH) break;
168	  }
169	
170	  const expectedOutcome =
171	    current.visits > 0 ? current.totalValue / current.visits : 0.5;
172	
173	  return {
174	    sequence,
175	    expectedOutcome: Math.max(0.0, Math.min(1.0, expectedOutcome)),
176	    visits: current.visits,
177	  };
178	}
179	
180	/**
181	 * Run MCTS to find the optimal action sequence.
182	 *
183	 * @param request         Simulation request
184	 * @param allActionNames  All valid action names for this agent
185	 * @param contextFreq     Context frequency (0–1 normalized)
186	 * @returns Best sequence found and its predicted outcome
187	 */
188	const MCTS_TIMEOUT_MS = 8000;
189	
190	export async function tier3MCTS(
191	  request: SimulationRequest,
192	  allActionNames: string[],
193	  contextFreq: number,
194	): Promise<SequencePrediction | null> {
195	  const timeoutPromise = new Promise<'TIMEOUT'>((resolve) =>
196	    setTimeout(() => resolve('TIMEOUT'), MCTS_TIMEOUT_MS)
197	  );
198	
199	  const mctsPromise = runTier3MCTS(request, allActionNames, contextFreq);
200	
201	  const result = await Promise.race([mctsPromise, timeoutPromise]);
202	
203	  if (result === 'TIMEOUT') {
204	    console.warn(`[MCTS] Timeout after ${MCTS_TIMEOUT_MS}ms — falling back to Tier 1`);
205	    return null;
206	  }
207	
208	  return result as SequencePrediction | null;
209	}
210	
211	async function runTier3MCTS(
212	  request: SimulationRequest,
213	  allActionNames: string[],
214	  contextFreq: number,
215	): Promise<SequencePrediction | null> {
216	  const model = await loadWorldModel(request.customerId);
217	  if (!model) return null;
218	
219	  // Filter to actions known to the model
220	  const validActions = allActionNames.filter(
221	    (a) => a in model.action_encoding,
222	  );
223	
224	  if (validActions.length === 0) return null;
225	
226	  // Exclude already-tried actions from root expansion
227	  // (they can still appear in deeper nodes)
228	  const initialActions = validActions.filter(
229	    (a) => !request.episodeHistory.includes(a),
230	  );
231	
232	  const root: MCTSNode = {
233	    action: null,
234	    parent: null,
235	    children: [],
236	    visits: 0,
237	    totalValue: 0,
238	    untriedActions: [...initialActions],
239	    depth: 0,
240	  };
241	
242	  // Run MCTS simulations in batches of 10
243	  // BATCHED MCTS NOTE: Within each batch, select() calls happen
244	  // synchronously before Promise.all — they use UCT scores from the
245	  // PREVIOUS batch's backpropagation, not in-batch updates.
246	  // Iterations 1-9 within a batch have stale UCT scores relative to
247	  // each other. This is the "leaf parallelism" trade-off: we accept
248	  // slightly degraded exploration accuracy for throughput.
249	  // To mitigate: keep BATCH_SIZE <= 10 (current value is correct).
250	  // A virtual-loss mechanism could further improve accuracy if needed.
251	  const BATCH_SIZE = 10;
252	  for (let i = 0; i < NUM_SIMS; i += BATCH_SIZE) {
253	    const promises = [];
254	    for (let j = 0; j < BATCH_SIZE && i + j < NUM_SIMS; j++) {
255	      const selected = select(root);
256	      const expanded =
257	        selected.untriedActions.length > 0
258	          ? expand(selected, validActions)
259	          : selected;
260	      promises.push(
261	        rollout(
262	          expanded,
263	          request.customerId,
264	          request.episodeHistory,
265	          request.contextHash,
266	          contextFreq,
267	        ).then(value => ({ expanded, value }))
268	      );
269	    }
270	    const results = await Promise.all(promises);
271	    for (const { expanded, value } of results) {
272	      backpropagate(expanded, value);
273	    }
274	  }
275	
276	  // Extract best sequence
277	  const { sequence, expectedOutcome } = extractBestSequence(root);
278	
279	  if (sequence.length === 0) return null;
280	
281	  // Get Tier 2 confidence interval for the best sequence
282	  const tier2Pred = await predictOutcome(
283	    request.customerId,
284	    sequence[sequence.length - 1]!,
285	    [...request.episodeHistory, ...sequence.slice(0, -1)],
286	    request.contextHash,
287	    contextFreq,
288	  );
289	
290	  const intervalLow =
291	    tier2Pred?.q025 ?? Math.max(0, expectedOutcome - 0.15);
292	  const intervalHigh =
293	    tier2Pred?.q975 ?? Math.min(1, expectedOutcome + 0.15);
294	  const width = intervalHigh - intervalLow;
295	
296	  return {
297	    actions: [...request.episodeHistory, ...sequence],
298	    predictedOutcome: Math.round(expectedOutcome * 10000) / 10000,
299	    outcomeIntervalLow: Math.round(intervalLow * 10000) / 10000,
300	    outcomeIntervalHigh: Math.round(intervalHigh * 10000) / 10000,
301	    confidenceWidth: Math.round(width * 10000) / 10000,
302	    confidence: Math.max(0.0, 1.0 - width),
303	    predictedResolution:
304	      expectedOutcome >= 0.7 ? expectedOutcome : expectedOutcome * 0.8,
305	    predictedSteps: sequence.length,
306	    betterThanProposed: false, // filled by tier-selector
307	  };
308	}
