145	
146	function clamp01(value: number): number {
147	    if (!Number.isFinite(value)) return 0;
148	    return Math.max(0, Math.min(1, value));
149	}
150	
151	function effectiveSampleCount(action: ActionPerformance): number {
152	    const sampleCount = Number(action.effective_sample_count);
153	    if (!Number.isFinite(sampleCount)) {
154	        return Math.max(0, Number(action.total_count ?? 0));
155	    }
156	    return Math.max(0, sampleCount);
157	}
158	
159	function resolutionRateForRanking(action: ActionPerformance): number {
160	    const baseRate = clamp01(Number(action.resolution_rate));
161	    const shadowWeight = Math.max(0, Math.min(1, action.shadow_weight ?? 0));
162	    const shadowSignal = action.shadow_signal;
163	
164	    if (shadowSignal === null || shadowSignal === undefined || shadowWeight <= 0) {
165	        return baseRate;
166	    }
167	
168	    return clamp01(baseRate * (1 - shadowWeight) + clamp01(shadowSignal) * shadowWeight);
169	}
170	
171	function rankingScore(a: ActionPerformance): number {
172	    // Primary signal: task-specific outcome quality (resolution semantics).
173	    // Use Laplace smoothing so tiny sample sets do not dominate.
174	    const n = effectiveSampleCount(a);
175	    const taskSignal = (resolutionRateForRanking(a) * n + 1) / (n + 2);
176	
177	    // Semantic cluster convergence dampens unstable action semantics.
178	    // 0.5 is neutral; low convergence applies a penalty, high convergence
179	    // yields a modest boost so rankings favor coherent action behavior.
180	    const semanticConvergence = clamp01(Number(a.semantic_cluster_convergence ?? 0.5));
181	    const convergenceAdjustment = Math.max(0.8, Math.min(1.1, 1 + ((semanticConvergence - 0.5) * 0.4)));
182	    const convergenceAdjustedSignal = clamp01(taskSignal * convergenceAdjustment);
183	
184	    // Secondary prior: global ML score from mv_action_scores.
185	    // Keep this as a stabilizer, but prioritize task-specific resolution evidence.
186	    if (a.ml_score === null || a.ml_score === undefined) {
187	        return convergenceAdjustedSignal;
188	    }
189	
190	    const globalSignal = Math.max(0, Math.min(1, a.ml_score));
191	    const globalWeight = n >= MIN_SAMPLES_STABLE
192	        ? 0.20
193	        : n >= MIN_SAMPLES
194	            ? 0.30
195	            : 0.40;
196	    return convergenceAdjustedSignal * (1 - globalWeight) + globalSignal * globalWeight;
197	}
198	
199	function confidenceFromSamplesAndLift(
200	    bestCount: number,
201	    worstCount: number,
202	    lift: number,
203	    sampleTarget: number = MIN_SAMPLES_HIGH_CONFIDENCE,
204	): number {
205	    // Harmonic mean penalizes when one arm is under-sampled
206	    const harmonicSamples =
207	        bestCount > 0 && worstCount > 0
208	            ? (2 * bestCount * worstCount) / (bestCount + worstCount)
209	            : 0;
210	
211	    // sampleWeight: how much data do we have? [0, 1]
212	    const sampleWeight = Math.min(
213	        1,
214	        harmonicSamples / Math.max(1, sampleTarget)
215	    );
216	
217	    // liftSignal: how decisive is the gap?
218	    // Normalized so a 0.30+ delta = full signal (1.0).
219	    // This is separate from sampleWeight — large delta with few
220	    // samples should NOT produce high confidence.
221	    const liftSignal = Math.min(1, Math.max(0, lift / 0.30));
222	
223	    // Combined: both dimensions must be high for high confidence.
224	    // Using geometric mean so neither factor dominates alone.
225	    const combined = Math.sqrt(sampleWeight * liftSignal);
226	
227	    return Math.max(0, Number(combined.toFixed(4)));
228	}
229	
230	function assessTaskNoise(
231	    best: ActionPerformance | null,
232	    worst: ActionPerformance | null,
233	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
234	): TaskNoiseAssessment {
235	    if (!best || !worst) {
236	        return {
237	            score: 0,
238	            isNoisyTask: false,
239	            bestWinRate: null,
240	            absoluteGap: null,
241	            reasons: ['insufficient_actions'],
242	        };
243	    }
244	
245	    const bestRate = clamp01(Number(best.resolution_rate));
246	    const worstRate = clamp01(Number(worst.resolution_rate));
247	    const gap = Math.max(0, bestRate - worstRate);
248	
249	    const center = (rolloutConfig.noiseWinRateLower + rolloutConfig.noiseWinRateUpper) / 2;
250	    const halfRange = Math.max(
251	        0.0001,
252	        (rolloutConfig.noiseWinRateUpper - rolloutConfig.noiseWinRateLower) / 2,
253	    );
254	    const distance = Math.abs(bestRate - center);
255	    const bandScore = 1 - Math.min(1, distance / halfRange);
256	    const gapScore = 1 - Math.min(1, gap / rolloutConfig.noiseGapMax);
257	    const score = Number((bandScore * 0.6 + gapScore * 0.4).toFixed(4));
258	
259	    const inWinBand =
260	        bestRate >= rolloutConfig.noiseWinRateLower
261	        && bestRate <= rolloutConfig.noiseWinRateUpper;
262	    const narrowGap = gap <= rolloutConfig.noiseGapMax;
263	
264	    const reasons: string[] = [];
265	    if (inWinBand) reasons.push('best_action_win_rate_in_hard_band');
266	    if (narrowGap) reasons.push('best_worst_gap_is_narrow');
267	    if (score >= rolloutConfig.noiseScoreThreshold) reasons.push('noise_score_above_threshold');
268	
269	    const isNoisyTask = rolloutConfig.noiseAwareGateEnabled
270	        && score >= rolloutConfig.noiseScoreThreshold
271	        && (inWinBand || narrowGap);
272	
273	    return {
274	        score,
275	        isNoisyTask,
276	        bestWinRate: Number(bestRate.toFixed(4)),
277	        absoluteGap: Number(gap.toFixed(4)),
278	        reasons,
279	    };
280	}
281	
282	function resolveEvidenceThresholds(
283	    noise: TaskNoiseAssessment,
284	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
285	): EvidenceThresholds {
286	    if (!rolloutConfig.noiseAwareGateEnabled || !noise.isNoisyTask) {
287	        return {
288	            warmupSamples: rolloutConfig.normalWarmupSamples,
289	            stableSamples: rolloutConfig.stableSamples,
290	            highConfidenceSamples: rolloutConfig.highConfidenceSamples,
291	            reason: 'normal_task_thresholds',
292	        };
293	    }
294	
295	    return {
296	        warmupSamples: rolloutConfig.noisyWarmupSamples,
297	        stableSamples: rolloutConfig.noisyStableSamples,
298	        highConfidenceSamples: rolloutConfig.noisyHighConfidenceSamples,
299	        reason: noise.reasons.join('+') || 'noisy_task_thresholds',
300	    };
301	}
302	
303	function deriveConfidenceSourceFromResult(
304	    result: RecommendationResult,
305	): { source: RecommendationConfidenceSource; reason: string } {
306	    if (result._trust_gate_blocked) {
307	        return {
308	            source: 'bootstrap',
309	            reason: 'trust_gate_blocked',
310	        };
311	    }
312	
313	    if (result.state === 'no_data') {
314	        return {
315	            source: 'bootstrap',
316	            reason: 'insufficient_evidence',
317	        };
318	    }
319	
320	    if (result._simulation_guardrail?.shadow_applied) {
321	        return {
322	            source: 'hybrid_shadow',
323	            reason: 'simulation_shadow_assist',
324	        };
325	    }
326	
327	    if (result.state === 'early_signal') {
328	        return {
329	            source: 'empirical_warmup',
330	            reason: 'empirical_signal_warming',
331	        };
332	    }
333	
334	    return {
335	        source: 'empirical_stable',
336	        reason: 'empirical_signal_stable',
337	    };
338	}
339	
340	function buildTraceabilityFromResult(result: RecommendationResult): RecommendationTraceability {
341	    if (result._trust_gate_blocked) {
342	        return {
343	            reason_code: 'trust_gate_blocked',
344	            stage: 'evidence_gate',
345	            gate: 'trust_status',
346	            detail: `Recommendation blocked by trust status: ${result._trust_status ?? 'unknown'}.`,
347	        };
348	    }
349	
350	    if (result.state === 'no_data') {
351	        return {
352	            reason_code: 'insufficient_evidence',
353	            stage: 'evidence_gate',
354	            gate: result._noise_gate?.decision_gate_reason ?? 'warmup_threshold',
355	            detail: 'Insufficient qualified actions or samples for a recommendation.',
356	        };
357	    }
358	
359	    if (result.state === 'early_signal') {
360	        if (result._simulation_guardrail?.exploit_gate_applied) {
361	            return {
362	                reason_code: 'simulation_exploit_gate',
363	                stage: 'simulation_guardrail',
364	                gate: 'exploit_gate_min_samples',
365	                detail: 'Simulation-assisted top action lacks minimum empirical samples for stable exploit.',
366	            };
367	        }
368	        if (result._simulation_guardrail?.confidence_ceiling_applied) {
369	            return {
370	                reason_code: 'simulation_confidence_ceiling',
371	                stage: 'simulation_guardrail',
372	                gate: 'confidence_ceiling',
373	                detail: 'Confidence capped due to simulation shadow influence.',
374	            };
375	        }
376	        if (result._silent_failure_warning) {
377	            return {
378	                reason_code: 'silent_failure_risk',
379	                stage: 'stability_gate',
380	                gate: 'degradation_alert_recent',
381	                detail: 'Recent degradation alerts detected for qualified actions.',
382	            };
383	        }
384	        return {
385	            reason_code: 'confidence_below_stable_threshold',
386	            stage: 'stability_gate',
387	            gate: result._noise_gate?.decision_gate_reason ?? 'stable_samples_or_gap',
388	            detail: 'Signal exists but has not reached stable confidence thresholds.',
389	        };
390	    }
391	
392	    return {
393	        reason_code: 'stable_recommendation',
394	        stage: 'decision',
395	        gate: null,
396	        detail: 'Recommendation is stable under current reliability gates.',
397	    };
398	}
399	
400	function computeShadowBlendWeight(
401	    sampleCount: number,
402	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
403	): number {
404	    if (sampleCount >= rolloutConfig.simulationShadowBlendUntilSamples) {
405	        return 0;
406	    }
407	
408	    const ratio =
409	        (rolloutConfig.simulationShadowBlendUntilSamples - sampleCount)
410	        / rolloutConfig.simulationShadowBlendUntilSamples;
411	    return Number(
412	        Math.min(rolloutConfig.simulationShadowBlendCap, ratio * rolloutConfig.simulationShadowBlendCap)
413	            .toFixed(4),
414	    );
415	}
416	
417	function applyConfidenceCeiling(
418	    confidence: number,
419	    action: ActionPerformance,
420	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
421	): { confidence: number; applied: boolean; topShadowWeight: number } {
422	    const topShadowWeight = Number((action.shadow_weight ?? 0).toFixed(4));
423	
424	    if (!rolloutConfig.simulationConfidenceCeilingEnabled || topShadowWeight <= 0) {
425	        return {
426	            confidence,
427	            applied: false,
428	            topShadowWeight,
429	        };
430	    }
431	
432	    const capped = Math.min(confidence, rolloutConfig.simulationConfidenceCeiling);
433	    return {
434	        confidence: Number(capped.toFixed(4)),
435	        applied: capped < confidence,
436	        topShadowWeight,
437	    };
438	}
439	
440	function shouldApplySimulationExploitGate(
441	    action: ActionPerformance,
442	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
443	): boolean {
444	    if (!rolloutConfig.simulationExploitGateEnabled) return false;
445	    if ((action.shadow_weight ?? 0) <= 0) return false;
446	    return effectiveSampleCount(action) < rolloutConfig.simulationExploitGateMinSamples;
447	}
