449	async function fetchCounterfactualShadowSignals(
450	    actionIds: string[],
451	    customerId: string,
452	    agentId: string | null,
453	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
454	): Promise<Map<string, number>> {
455	    const uniqueActionIds = [...new Set(actionIds.filter(Boolean))];
456	    if (uniqueActionIds.length === 0) return new Map<string, number>();
457	
458	    let decisionsQuery = supabase
459	        .from('fact_decisions')
460	        .select('id, dim_agents!inner(customer_id, agent_id)')
461	        .eq('dim_agents.customer_id', customerId)
462	        .order('created_at', { ascending: false })
463	        .limit(rolloutConfig.simulationShadowDecisionLookback);
464	
465	    if (agentId) {
466	        decisionsQuery = decisionsQuery.eq('agent_id', agentId);
467	    }
468	
469	    const { data: decisions, error: decisionError } = await decisionsQuery;
470	    if (decisionError) {
471	        console.warn('[recommendation-engine] shadow decision lookup failed:', decisionError.message);
472	        return new Map<string, number>();
473	    }
474	
475	    const decisionIds = (decisions ?? [])
476	        .map((decision: any) => decision.id)
477	        .filter((value: unknown): value is string => typeof value === 'string' && value.length > 0);
478	
479	    if (decisionIds.length === 0) {
480	        return new Map<string, number>();
481	    }
482	
483	    const { data, error } = await supabase
484	        .from('fact_outcome_counterfactuals')
485	        .select('unchosen_action_id, counterfactual_est, ips_weight, created_at')
486	        .in('decision_id', decisionIds)
487	        .in('unchosen_action_id', uniqueActionIds)
488	        .order('created_at', { ascending: false })
489	        .limit(rolloutConfig.simulationShadowRecentPerAction * uniqueActionIds.length);
490	
491	    if (error) {
492	        console.warn('[recommendation-engine] shadow counterfactual lookup failed:', error.message);
493	        return new Map<string, number>();
494	    }
495	    const chunkRows = (data ?? []) as CounterfactualSignalRow[];
496	
497	    const dedupedRows = new Map<string, CounterfactualSignalRow>();
498	    for (const row of chunkRows) {
499	        if (!row.unchosen_action_id || !row.created_at) continue;
500	        const key = `${row.unchosen_action_id}:${row.created_at}`;
501	        if (!dedupedRows.has(key)) dedupedRows.set(key, row);
502	    }
503	
504	    const grouped = new Map<string, CounterfactualSignalRow[]>();
505	    for (const row of dedupedRows.values()) {
506	        if (!row.unchosen_action_id) continue;
507	        const existing = grouped.get(row.unchosen_action_id) ?? [];
508	        existing.push(row);
509	        grouped.set(row.unchosen_action_id, existing);
510	    }
511	
512	    const signals = new Map<string, number>();
513	    for (const actionId of uniqueActionIds) {
514	        const rows = (grouped.get(actionId) ?? [])
515	            .sort(
516	                (a, b) => new Date(b.created_at ?? 0).getTime() - new Date(a.created_at ?? 0).getTime(),
517	            )
518	            .slice(0, rolloutConfig.simulationShadowRecentPerAction);
519	
520	        if (rows.length === 0) continue;
521	
522	        let weightedTotal = 0;
523	        let weightTotal = 0;
524	        let simpleTotal = 0;
525	
526	        for (const row of rows) {
527	            const estimate = clamp01(Number(row.counterfactual_est ?? 0));
528	            const weight = clamp01(Number(row.ips_weight ?? 0));
529	            simpleTotal += estimate;
530	            if (weight > 0) {
531	                weightedTotal += estimate * weight;
532	                weightTotal += weight;
533	            }
534	        }
535	
536	        const signal = weightTotal > 0
537	            ? weightedTotal / weightTotal
538	            : simpleTotal / rows.length;
539	        signals.set(actionId, Number(clamp01(signal).toFixed(4)));
540	    }
541	
542	    return signals;
543	}
