573	async function hasSilentFailureAlertForActions(
574	    actionIds: string[],
575	    customerId: string,
576	): Promise<boolean> {
577	    if (actionIds.length === 0) return false;
578	
579	    const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
580	
581	    // Check degradation alerts for the qualified actions in this task.
582	    const { count, error } = await supabase
583	        .from('degradation_alert_events')
