594	export async function getRecommendation(
595	    customerId: string,
596	    taskName: string,
597	    agentId?: string | null,
598	    contextFilter?: ContextFilter | null,
599	): Promise<RecommendationResult> {
600	    const generatedAt = new Date().toISOString();
601	    const registeredActions = await getRegisteredActions(customerId);
602	    const rolloutConfig = getRecommendationRolloutConfig();
603	
604	    const defaultNoiseMeta: RecommendationNoiseGateMeta = {
605	        enabled: rolloutConfig.noiseAwareGateEnabled,
606	        is_noisy_task: false,
607	        task_noise_score: 0,
608	        best_action_win_rate: null,
609	        absolute_gap: null,
610	        effective_samples: 0,
611	        required_samples: rolloutConfig.normalWarmupSamples,
612	        stable_samples: rolloutConfig.stableSamples,
613	        high_confidence_samples: rolloutConfig.highConfidenceSamples,
614	        decision_gate_reason: null,
615	    };
616	
617	    const defaultSimulationMeta: RecommendationSimulationGuardrailMeta = {
618	        enabled:
619	            rolloutConfig.simulationShadowEnabled
620	            || rolloutConfig.simulationConfidenceCeilingEnabled
621	            || rolloutConfig.simulationExploitGateEnabled,
622	        shadow_applied: false,
623	        assisted_actions: 0,
624	        top_action_shadow_weight: 0,
625	        confidence_ceiling_applied: false,
626	        exploit_gate_applied: false,
627	        confidence_ceiling: rolloutConfig.simulationConfidenceCeiling,
628	        exploit_gate_min_samples: rolloutConfig.simulationExploitGateMinSamples,
629	    };
630	
631	    function withGuardrailMeta(
632	        result: RecommendationResult,
633	        noiseMeta: RecommendationNoiseGateMeta = defaultNoiseMeta,
634	        simulationMeta: RecommendationSimulationGuardrailMeta = defaultSimulationMeta,
635	    ): RecommendationResult {
636	        const enriched: RecommendationResult = {
637	            ...result,
638	            _noise_gate: noiseMeta,
639	            _simulation_guardrail: simulationMeta,
640	        };
641	
642	        const confidenceSource = deriveConfidenceSourceFromResult(enriched);
643	        return {
644	            ...enriched,
645	            confidence_source: confidenceSource.source,
646	            confidence_source_reason: confidenceSource.reason,
647	            traceability: buildTraceabilityFromResult(enriched),
648	        };
649	    }
650	
651	    // Suspended / critically low-trust agents must not emit recommendations.
652	    if (agentId) {
653	        const trustState = await getAgentTrustStatus(agentId);
654	        if (trustState) {
655	            const isBlocked =
656	                TRUST_GATE_STATUSES.includes(trustState.trust_status) ||
657	                (trustState.trust_score !== null &&
658	                    trustState.trust_score < TRUST_GATE_MIN_SCORE);
659	            if (isBlocked) {
660	                return withGuardrailMeta({
661	                    task: taskName,
662	                    state: 'no_data',
663	                    best_action: null,
664	                    worst_action: null,
665	                    confidence: null,
666	                    improvement: null,
667	                    min_sample_count: 0,
668	                    all_actions: [],
669	                    agent_id: agentId,
670	                    generated_at: generatedAt,
671	                    _trust_gate_blocked: true,
672	                    _trust_status: trustState.trust_status,
673	                    _data_source: 'unknown',
674	                    registered_actions: registeredActions,
675	                    action_mismatch: false,
676	                } as any);
677	            }
678	        }
679	    }
680	
681	    function makeResult(
682	        state: RecommendationState,
683	        actions: ActionPerformance[],
684	        best: ActionPerformance | null = null,
685	        worst: ActionPerformance | null = null,
686	        dataSource: RecommendationResult['_data_source'] = 'unknown',
687	    ): RecommendationResult {
688	        return {
689	            task: taskName,
690	            state,
691	            best_action: best,
692	            worst_action: worst,
693	            confidence: null,
694	            improvement: null,
695	            min_sample_count: (best && worst)
696	                ? Number(Math.min(effectiveSampleCount(best), effectiveSampleCount(worst)).toFixed(4))
697	                : Number((best ? effectiveSampleCount(best) : 0).toFixed(4)),
698	            all_actions: actions,
699	            _data_source: dataSource,
700	            agent_id: agentId ?? null,
701	            generated_at: generatedAt,
702	            registered_actions: registeredActions,
703	            action_mismatch: false,
704	            context_filter: contextFilter ?? null,
705	        };
706	    }
707	
708	    try {
709	        // Primary source is a rolling 180-day MV.
710	        // windowStart is still passed so fallback fact queries stay aligned.
711	        const windowStart = new Date(
712	            Date.now() - RECOMMENDATION_WINDOW_DAYS * 24 * 60 * 60 * 1000
713	        ).toISOString();
714	
715	        const { rows, source } = await fetchTaskActionPerformance({
716	            customerId,
717	            taskName,
718	            agentId: agentId ?? null,
719	            windowStart,
720	            contextFilter: contextFilter ?? null,
721	        });
722	
723	        const actions: ActionPerformance[] = rows.map((row) => {
724	            const mlScoreRaw = row.ml_score;
725	            return {
726	                action_id: String(row.action_id),
727	                action_name: String(row.action_name),
728	                total_count: Number(row.total_count),
729	                effective_sample_count: Number(row.effective_sample_count ?? row.total_count ?? 0),
730	                success_count: Number(row.success_count),
731	                success_rate: Number(row.success_rate),
732	                resolution_rate: Number(row.resolution_rate ?? row.success_rate ?? 0),
733	                semantic_cluster_convergence: Number(row.semantic_cluster_convergence ?? 0.5),
734	                ml_score: mlScoreRaw !== null
735	                    && mlScoreRaw !== undefined
736	                    ? Number(mlScoreRaw)
737	                    : null,
738	                last_seen_at: typeof row.last_seen_at === 'string' ? row.last_seen_at : null,
739	                shadow_signal: null,
740	                shadow_weight: 0,
741	            };
742	        });
743	
744	        let simulationShadowAppliedCount = 0;
745	        if (rolloutConfig.simulationShadowEnabled) {
746	            const shadowSignals = await fetchCounterfactualShadowSignals(
747	                actions.map((action) => action.action_id),
748	                customerId,
749	                agentId ?? null,
750	                rolloutConfig,
751	            );
752	
753	            for (const action of actions) {
754	                const shadowSignal = shadowSignals.get(action.action_id);
