1	import {
2	    MIN_SAMPLES,
3	    MIN_SAMPLES_HIGH_CONFIDENCE,
4	    MIN_SAMPLES_STABLE,
5	} from './constants.js';
6	
7	export type RecommendationScope = 'agent_scoped' | 'customer_blended';
8	
9	export type SampleThresholdBucket =
10	    | 'warmup'
11	    | 'transition'
12	    | 'stable'
13	    | 'cohort_anchor';
14	
15	export interface SampleThresholdProgress {
16	    bucket: SampleThresholdBucket;
17	    current_samples: number;
18	    next_threshold: number | null;
19	    remaining_to_next_bucket: number;
20	}
21	
22	export interface ScopeTransitionCandidate {
23	    state: 'no_data' | 'early_signal' | 'stable';
24	    min_sample_count: number;
25	    confidence: number | null;
26	    has_best_action: boolean;
27	}
28	
29	export const AGENT_SCOPE_MIN_CONFIDENCE = 0.50;
30	export const BLENDED_FALLBACK_MIN_CONFIDENCE = 0.30;
31	export const BLENDED_EVIDENCE_MARGIN = 0.15;
32	
33	function normalizeSampleCount(value: number): number {
34	    if (!Number.isFinite(value)) return 0;
35	    return Math.max(0, Math.floor(value));
36	}
37	
38	export function getSampleThresholdProgress(sampleCount: number): SampleThresholdProgress {
39	    const current = normalizeSampleCount(sampleCount);
40	
41	    if (current < MIN_SAMPLES) {
42	        return {
43	            bucket: 'warmup',
44	            current_samples: current,
45	            next_threshold: MIN_SAMPLES,
46	            remaining_to_next_bucket: MIN_SAMPLES - current,
47	        };
48	    }
49	
50	    if (current < MIN_SAMPLES_STABLE) {
51	        return {
52	            bucket: 'transition',
53	            current_samples: current,
54	            next_threshold: MIN_SAMPLES_STABLE,
55	            remaining_to_next_bucket: MIN_SAMPLES_STABLE - current,
56	        };
57	    }
58	
59	    if (current < MIN_SAMPLES_HIGH_CONFIDENCE) {
60	        return {
61	            bucket: 'stable',
62	            current_samples: current,
63	            next_threshold: MIN_SAMPLES_HIGH_CONFIDENCE,
64	            remaining_to_next_bucket: MIN_SAMPLES_HIGH_CONFIDENCE - current,
65	        };
66	    }
67	
68	    return {
69	        bucket: 'cohort_anchor',
70	        current_samples: current,
71	        next_threshold: null,
72	        remaining_to_next_bucket: 0,
73	    };
74	}
75	
76	function confidenceValue(result: ScopeTransitionCandidate): number {
77	    return Math.max(0, Math.min(1, result.confidence ?? 0));
78	}
79	
80	function evidenceScore(result: ScopeTransitionCandidate): number {
81	    const normalizedSamples = Math.min(1, result.min_sample_count / MIN_SAMPLES_STABLE);
82	    const confidence = confidenceValue(result);
83	    return Number((normalizedSamples * 0.6 + confidence * 0.4).toFixed(4));
84	}
85	
86	function isAgentEvidenceMature(result: ScopeTransitionCandidate): boolean {
87	    if (result.state === 'stable') {
88	        return true;
89	    }
90	    return result.min_sample_count >= MIN_SAMPLES_STABLE
91	        && confidenceValue(result) >= AGENT_SCOPE_MIN_CONFIDENCE;
92	}
93	
94	function canUseBlendedFallback(result: ScopeTransitionCandidate): boolean {
95	    if (result.state === 'no_data') {
96	        return false;
97	    }
98	    if (!result.has_best_action) {
99	        return false;
100	    }
101	    return result.min_sample_count >= MIN_SAMPLES
102	        && confidenceValue(result) >= BLENDED_FALLBACK_MIN_CONFIDENCE;
103	}
104	
105	export function chooseScopedOrBlendedCandidate(
106	    scopedResult: ScopeTransitionCandidate,
107	    blendedResult: ScopeTransitionCandidate,
108	): {
109	    servedScope: RecommendationScope;
110	    reason: string | null;
111	    threshold_progress: SampleThresholdProgress;
112	} {
113	    const thresholdProgress = getSampleThresholdProgress(scopedResult.min_sample_count);
114	
115	    if (isAgentEvidenceMature(scopedResult)) {
116	        return {
117	            servedScope: 'agent_scoped',
118	            reason: null,
119	            threshold_progress: thresholdProgress,
120	        };
121	    }
122	
123	    if (!canUseBlendedFallback(blendedResult)) {
124	        return {
125	            servedScope: 'agent_scoped',
126	            reason: 'Agent-specific evidence is still warming, and blended cohort evidence did not pass minimum reliability gates.',
127	            threshold_progress: thresholdProgress,
128	        };
129	    }
130	
131	    const scopedEvidence = evidenceScore(scopedResult);
132	    const blendedEvidence = evidenceScore(blendedResult);
133	
134	    if (blendedEvidence < scopedEvidence + BLENDED_EVIDENCE_MARGIN) {
135	        return {
136	            servedScope: 'agent_scoped',
137	            reason: 'Agent-specific evidence is warming, but blended cohort evidence is not meaningfully stronger yet.',
138	            threshold_progress: thresholdProgress,
139	        };
140	    }
141	
142	    return {
143	        servedScope: 'customer_blended',
144	        reason: 'Agent-specific evidence is below reliability targets. Serving blended cohort evidence to reduce early-run uncertainty.',
145	        threshold_progress: thresholdProgress,
146	    };
147	}
