77	            `No outcome data found for task "${taskName}". ` +
78	            `Ensure task_name is included when calling log_outcome.`
79	        );
80	    }
81	
82	    // Has a qualified leader but needs a second qualified action
83	    if (ctx && ctx.qualified_count === 1 && ctx.leading_action) {
84	        const l = ctx.leading_action;
85	        const needing = ctx.actions_needing_more
86	            .map((a) => `${a.action_name} needs ${a.needed} more outcome${a.needed === 1 ? '' : 's'}`)
87	            .join('; ');
88	        return (
89	            `"${l.name}" is the leading action for "${taskName}" ` +
90	            `(${l.total} outcomes, ${(l.rate * 100).toFixed(1)}% resolution score). ` +
91	            `A second qualified action is needed to generate a recommendation. ` +
92	            (needing ? `Progress: ${needing}.` : `Log more outcomes for other actions.`)
93	        );
94	    }
95	
96	    // Generic: multiple actions but none qualified
97	    if (ctx && ctx.actions_needing_more.length > 0) {
98	        const needing = ctx.actions_needing_more
99	            .map((a) => `${a.action_name} (${a.current}/${warmupSamples})`)
100	            .join(', ');
101	        return (
102	            `Collecting data for "${taskName}". ` +
103	            `Actions need ${warmupSamples}+ outcomes each: ${needing}.`
104	        );
105	    }
106	
107	    return (
108	        `Collecting data for "${taskName}" ` +
109	        `(${totalOutcomes} outcome${totalOutcomes === 1 ? '' : 's'} ` +
110	        `logged so far, ` +
111	        `need ${warmupSamples}+ per action across 2+ distinct actions).`
112	    );
113	}
