230	// Issue 1+2: Raw delta with uncertainty label, plus confidence-weighted delta
231	function buildImprovementDisplay(
232	    delta: number,
233	    confidence: number | null,
234	    minSamples: number,
235	    isEarlySignal: boolean,
236	): ActionableOutput['improvement_display'] {
237	    if (delta <= 0) return null;
238	    const conf = confidence ?? 0;
239	    const rawPct = `+${(delta * 100).toFixed(1)}%`;
240	    const qualifiedRaw = delta * conf;
241	    const qualifiedPct = `+${(qualifiedRaw * 100).toFixed(1)}%`;
242	    return {
243	        raw_delta_pct: rawPct,
244	        qualified_delta_pct: qualifiedPct,
245	        is_estimate: isEarlySignal || conf < 0.5,
246	        samples_basis: minSamples,
247	    };
248	}
