250	// Issue 3: Concrete monitor steps
251	function buildMonitorSteps(
252	    currentSamples: number,
253	    targetSamples: number,
254	    bestAction: string,
255	    taskName: string,
256	    bestRate?: number,
257	    worstAction?: string,
258	    worstRate?: number,
259	    confidencePct?: number,
260	): string[] {
261	    const remaining = Math.max(0, targetSamples - currentSamples);
262	    const steps: string[] = [];
263	
264	    if (remaining > 0) {
265	        steps.push(
266	            `Log ${remaining} more outcomes for task "${taskName}" to reach stable signal ` +
267	            `(currently ${currentSamples}/${targetSamples} per action).`
268	        );
269	    }
270	
271	    if (bestRate !== undefined) {
272	        steps.push(
273	            `Keep using "${bestAction}" as your primary action ` +
274	            `(current resolution score: ${(bestRate * 100).toFixed(1)}%).`
275	        );
276	    } else {
277	        steps.push(`Keep using "${bestAction}" as your primary action.`);
278	    }
279	
280	    if (worstAction && worstRate !== undefined && bestRate !== undefined) {
281	        steps.push(
282	            `Avoid "${worstAction}" until confidence improves ` +
283	            `(${(worstRate * 100).toFixed(1)}% vs ${(bestRate * 100).toFixed(1)}% for best action).`
284	        );
285	    }
286	
287	    const confNote = confidencePct !== undefined
288	        ? `currently ${confidencePct}%`
289	        : 'not yet 50%';
290	    steps.push(
291	        `Check back when confidence reaches 50%+ (${confNote}). ` +
292	        `Recommendation becomes fully actionable above this threshold.`
293	    );
294	
295	    return steps;
296	}
