300	    currentSamples: number,
301	    targetSamples: number,
302	    _confidencePct: number,
303	): string {
304	    const remaining = Math.max(0, targetSamples - currentSamples);
305	    if (remaining === 0) {
306	        return `Enough samples collected. Confidence will unlock once signal stabilizes above 50%.`;
307	    }
308	    return (
309	        `~${remaining} more outcomes needed to approach a stable signal. ` +
310	        `A high-confidence recommendation unlocks at ~${targetSamples} samples + 80% confidence.`
311	    );
