314	// Issue 6: Per-action margin of error using Wilson score interval (simplified)
315	// margin ≈ 1.96 × sqrt(p(1-p)/n) — 95% confidence interval half-width
316	function wilsonMargin(successRate: number, n: number): string {
317	    if (n === 0) return '±?%';
318	    const p = Math.min(1, Math.max(0, successRate));
319	    const margin = 1.96 * Math.sqrt((p * (1 - p)) / n);
320	    return `±${(margin * 100).toFixed(1)}%`;
321	}
322	
323	function buildActionUncertainty(
324	    best: { action_name: string; resolution_rate: number; success_rate: number; total_count: number },
325	    worst: { action_name: string; resolution_rate: number; success_rate: number; total_count: number },
326	): ActionableOutput['action_uncertainty'] {
327	    const bestRate = resolutionMetric(best);
328	    const worstRate = resolutionMetric(worst);
329	    return {
330	        best: {
331	            action: best.action_name,
332	            rate_pct: `${(bestRate * 100).toFixed(1)}%`,
333	            margin_pct: wilsonMargin(bestRate, best.total_count),
334	        },
335	        worst: {
336	            action: worst.action_name,
337	            rate_pct: `${(worstRate * 100).toFixed(1)}%`,
338	            margin_pct: wilsonMargin(worstRate, worst.total_count),
339	        },
340	    };
341	}
