343	// Issue 5: Relative time label from ISO string
344	function relativeTimeLabel(isoString: string | null): string {
345	    if (!isoString) return 'Unknown';
346	    const diffMs = Date.now() - new Date(isoString).getTime();
347	    const mins = Math.floor(diffMs / 60_000);
348	    if (mins < 2) return 'Updated just now';
349	    if (mins < 60) return `Updated ${mins} minutes ago`;
350	    const hrs = Math.floor(mins / 60);
351	    if (hrs < 24) return `Updated ${hrs} hour${hrs === 1 ? '' : 's'} ago`;
352	    const days = Math.floor(hrs / 24);
353	    return `Updated ${days} day${days === 1 ? '' : 's'} ago`;
354	}
