356	function buildInsight(r: RecommendationResult): ActionableOutput['insight'] {
357	    if (!r.best_action) {
358	        return {
359	            best_action: null,
360	            best_rate: null,
361	            worst_action: null,
362	            worst_rate: null,
363	            delta: null,
364	            sample_size: null,
365	        };
366	    }
367	    const bestRate = resolutionMetric(r.best_action);
368	    const worstRate = r.worst_action
369	        ? resolutionMetric(r.worst_action)
370	        : null;
371	    return {
372	        best_action: r.best_action.action_name,
373	        best_rate: Number(bestRate.toFixed(4)),
374	        worst_action: r.worst_action?.action_name ?? null,
375	        worst_rate: worstRate !== null
376	            ? Number(worstRate.toFixed(4))
377	            : null,
378	        delta: worstRate !== null
379	            ? Number((bestRate - worstRate).toFixed(4))
380	            : null,
381	        sample_size: r.worst_action
382	            ? { best: r.best_action.total_count, worst: r.worst_action.total_count }
383	            : null,
384	    };
385	}
