387	function buildMessage(
388	    state: RecommendationState,
389	    actionRequired: boolean,
390	    confidenceMeta: InternalConfidenceMeta,
391	    best: string | null,
392	    worst: string | null,
393	): string {
394	    if (state === 'no_data') {
395	        return 'We are observing this task. No action recommended yet. ' +
396	            'Log more outcomes to unlock a recommendation.';
397	    }
398	    if (state === 'early_signal') {
399	        return `Early signal: ${best ?? 'best action'} appears ahead of ` +
400	            `${worst ?? 'current action'}, but confidence is too low to act. ` +
401	            'Monitor and collect more outcomes before switching.';
402	    }
403	    if (!actionRequired) {
404	        return `${best ?? 'best action'} is outperforming, but confidence is ` +
405	            `${confidenceMeta.percent}%. Pilot it before a full rollout.`;
406	    }
407	    return `Replace ${worst ?? 'current action'} with ${best ?? 'best action'}. ` +
408	        `This recommendation has ${confidenceMeta.percent}% confidence.`;
409	}
