411	function buildProgress(
412	    minSampleCount: number,
413	    targetSamples: number,
414	): ActionableOutput['progress'] {
415	    const current = minSampleCount;
416	    const target = Math.max(1, targetSamples);
417	    const pctComplete = Math.min(100, Math.round((current / target) * 100));
418	    return {
419	        current_samples: current,
420	        target_samples: target,
421	        percent_complete: pctComplete,
422	    };
423	}
