425	function warmupSamplesFor(result: RecommendationResult): number {
426	    return Math.max(
427	        MIN_SAMPLES,
428	        Math.floor(Number((result as any)._noise_gate?.required_samples ?? MIN_SAMPLES)),
429	    );
430	}
431	
432	function stableSamplesFor(result: RecommendationResult): number {
433	    const stable = Math.floor(Number((result as any)._noise_gate?.stable_samples ?? MIN_SAMPLES_STABLE));
434	    return Math.max(warmupSamplesFor(result), stable);
435	}
436	
437	function highConfidenceSamplesFor(result: RecommendationResult): number {
438	    const high = Math.floor(
439	        Number((result as any)._noise_gate?.high_confidence_samples ?? MIN_SAMPLES_HIGH_CONFIDENCE),
440	    );
441	    return Math.max(stableSamplesFor(result), high);
442	}
