452	function buildReason(
453	    r: RecommendationResult,
454	    confidenceMeta: InternalConfidenceMeta,
455	    warmupSamples: number,
456	): ActionableOutput['reason'] {
457	    if (r.state === 'no_data') {
458	        const trustBlocked = (r as any)._trust_gate_blocked === true;
459	        const totalOutcomes = r.all_actions.reduce(
460	            (sum, a) => sum + a.total_count,
461	            0,
462	        );
463	        const reasonText = trustBlocked
464	            ? `Agent suspended (trust_status: ${(r as any)._trust_status ?? 'suspended'})`
465	            : templateNoData(r.task, totalOutcomes, warmupSamples, r._qualification_context);
466	        return {
467	            summary: trustBlocked
468	                ? 'Agent is suspended'
469	                : `Collecting data for "${r.task}"`,
470	            evidence: totalOutcomes > 0
471	                ? `${totalOutcomes} total outcome${totalOutcomes === 1 ? '' : 's'} logged`
472	                : 'No outcomes logged yet',
473	            confidence_note: reasonText,
474	        };
475	    }
476	
477	    const b = r.best_action!;
478	    const w = r.worst_action!;
479	    const bestRate = resolutionMetric(b);
480	    const worstRate = resolutionMetric(w);
481	    const confText = `${confidenceMeta.percent}% confidence`;
482	    const uncertainNote = confidenceMeta.label === 'low' || confidenceMeta.label === 'none'
483	        ? ' — result may change with more data'
484	        : confidenceMeta.label === 'very_high'
485	            ? ' — high confidence, signal is stable'
486	            : '';
487	
488	    if (r.state === 'early_signal') {
489	        const delta = bestRate - worstRate;
490	        return {
491	            summary: delta < 0.08
492	                ? `${b.action_name} and ${w.action_name} perform similarly`
493	                : `${b.action_name} outperforms ${w.action_name}`,
494	            evidence: `${pct(bestRate)} vs ${pct(worstRate)} (${b.total_count} and ${w.total_count} runs)`,
495	            confidence_note: `${confText}${uncertainNote}`,
496	        };
497	    }
498	
499	    const imp = r.improvement!;
500	    return {
501	        summary: `${b.action_name} outperforms ${w.action_name}`,
502	        evidence: `${pct(imp.improved_rate)} vs ${pct(imp.baseline_rate)} (+${pct(imp.absolute_delta)}, ${r.min_sample_count} runs each)`,
503	        confidence_note: `${confText}${uncertainNote}`,
504	    };
505	}
