507	export function buildActionableOutput(
508	    r: RecommendationResult,
509	): ActionableOutput {
510	    const confidenceMeta = toConfidenceMeta(r.confidence);
511	    const confidenceLabel = confidenceMeta.label;
512	    const stateMeta = STATE_META[r.state];
513	    const warmupSamples = warmupSamplesFor(r);
514	    const stableSamples = stableSamplesFor(r);
515	    const highConfidenceSamples = highConfidenceSamplesFor(r);
516	    const noisyGate = noiseGateActive(r);
517	    const simulationExploitGate = simulationExploitGateActive(r);
518	
519	    // Issue 7: threshold hint — always present
520	    const thresholdHint = (() => {
521	        const base =
522	            `Recommendations appear at 50%+ confidence and stabilize at 80%+. ` +
523	            `High-confidence recommendations include a direct "replace" action ` +
524	            `after ~${stableSamples}+ effective samples per action.`;
525	
526	        if (simulationExploitGate) {
527	            return `${base} Simulation exploit gate is active for this task; monitor mode is enforced until real evidence improves.`;
528	        }
529	
530	        if (noisyGate) {
531	            return `${base} Noise-aware gate is active: this task requires ${warmupSamples}+ effective samples before stronger recommendations.`;
532	        }
533	
534	        return base;
535	    })();
536	
537	    // Issue 8: scope label — placeholder, overwritten by route via spread
538	    const scopeLabel = '';
539	
540	    const base = {
541	        task: r.task,
542	        state: r.state,
543	        ui_label: stateMeta.ui_label,
544	        explanation: stateMeta.explanation,
545	        confidence_meta: {
546	            value: confidenceMeta.value,
547	            percent: confidenceMeta.percent,
548	            label: confidenceMeta.label,
549	        },
550	        progress: buildProgress(Math.floor(r.min_sample_count), highConfidenceSamples),
551	        generated_at: r.generated_at,
552	    };
553	
554	    if (r.state === 'no_data') {
555	        const trustBlocked = (r as any)._trust_gate_blocked === true;
556	        const noDataInsight: ActionableOutput['insight'] = {
557	            best_action: null,
558	            best_rate: null,
559	            worst_action: null,
560	            worst_rate: null,
561	            delta: null,
562	            sample_size: null,
563	        };
564	        return {
565	            ...base,
566	            decision: {
567	                type: 'collect_more_data',
568	                action_required: false,
569	            },
570	            problem: null,
571	            risk_context: trustBlocked
572	                ? 'This agent has critically low trust. Acting on its history may cause regressions.'
573	                : 'Evidence is insufficient. Acting now may cause regressions without measurable upside.',
574	            expected_improvement: null,
575	            reason: buildReason(r, confidenceMeta, warmupSamples),
576	            confidence: 0,
577	            confidence_label: confidenceLabel,
578	            validated: 'insufficient_data' as const,
579	            confidence_explanation: 'Not enough data to estimate confidence yet. ' +
580	                `Log outcomes with task_name="${r.task}" to unlock a recommendation ` +
581	                `(target: ${warmupSamples}+ effective samples per action).`,
582	            insight: noDataInsight,
583	            message: buildMessage('no_data', false, confidenceMeta, null, null),
584	            validation_hint: null,
585	            sample_size: null,
586	            improvement_display: null,
587	            monitor_steps: null,
588	            unlock_hint: buildUnlockHint(0, highConfidenceSamples, 0),
589	            data_window: null,
590	            action_uncertainty: null,
591	            threshold_hint: thresholdHint,
592	            scope_label: scopeLabel,
593	        };
594	    }
595	
596	    if (r.state === 'early_signal') {
597	        const b = r.best_action!;
598	        const w = r.worst_action!;
599	        const bestRate = resolutionMetric(b);
600	        const worstRate = resolutionMetric(w);
601	        const delta = bestRate - worstRate;
602	        const lastSeen = b.last_seen_at || w.last_seen_at || null;
603	        return {
604	            ...base,
605	            decision: {
606	                type: 'monitor',
607	                action_required: false,
608	            },
609	            problem: (() => {
610	                if (delta < 0.08) {
611	                    return (
612	                        `${b.action_name} and ${w.action_name} perform similarly ` +
613	                        `(${pct(bestRate)} vs ${pct(worstRate)}, ` +
614	                        `${b.total_count} and ${w.total_count} outcomes - monitoring)`
615	                    );
616	                }
617	                return (
618	                    `${w.action_name} is underperforming ` +
619	                    `(${pct(worstRate)} resolution score, ` +
620	                    `${w.total_count} outcomes - early data)`
621	                );
622	            })(),
623	            risk_context: (r as any)._silent_failure_warning
624	                ? 'Silent failures detected in the last 24h: some outcomes marked success=true had low outcome scores. Signal direction is promising but uncertainty remains high.'
625	                : 'Signal direction is promising but uncertainty remains high; immediate full replacement may be premature.',
626	            expected_improvement: (() => {
627	                if (delta <= 0) return null;
628	                return {
629	                    baseline: pct(worstRate),
630	                    improved: pct(bestRate),
631	                    delta: `+${(delta * 100).toFixed(1)}% (early estimate)`,
632	                    delta_raw: Number(delta.toFixed(4)),
633	                    based_on_samples: r.min_sample_count,
634	                    caution: `Based on ${r.min_sample_count} outcomes per action at ` +
635	                        `${Math.round((r.confidence ?? 0) * 100)}% confidence. ` +
636	                        `Effective reliable gain: ~${((delta * (r.confidence ?? 0)) * 100).toFixed(1)}%.`,
637	                };
638	            })(),
639	            reason: buildReason(r, confidenceMeta, warmupSamples),
640	            confidence: r.confidence ?? 0,
641	            confidence_label: confidenceLabel,
642	            validated: 'provisional' as const,
643	            confidence_explanation: (() => {
644	                const confPct = Math.round((r.confidence ?? 0) * 100);
645	                const samples = r.min_sample_count;
646	                const sampleNote = `${samples} outcomes per action recorded ` +
647	                    `(need ${stableSamples} for stable signal).`;
648	                if (confPct >= 50) {
649	                    return `${confPct}% confidence - moderate signal. ${sampleNote} ` +
650	                        `The performance gap is real but more data would make it more reliable.`;
651	                }
652	                if (confPct >= 30) {
653	                    return `${confPct}% confidence - early signal. ${sampleNote} ` +
654	                        `Continue logging - this recommendation may change as more data arrives.`;
655	                }
656	                return `${confPct}% confidence - low signal. ${sampleNote} ` +
657	                    `Log more outcomes before acting on this recommendation.`;
658	            })(),
659	            insight: buildInsight(r),
660	            message: (() => {
661	                if (delta < 0.08) {
662	                    return (
663	                        `${b.action_name} and ${w.action_name} are performing ` +
664	                        `similarly (${pct(bestRate)} vs ${pct(worstRate)}). ` +
665	                        `Continue collecting data before making a switch.`
666	                    );
667	                }
668	                return buildMessage(
669	                    'early_signal',
670	                    false,
671	                    confidenceMeta,
672	                    r.best_action?.action_name ?? null,
673	                    r.worst_action?.action_name ?? null,
674	                );
675	            })(),
676	            validation_hint: null,
677	            sample_size: {
678	                best: b.total_count,
679	                worst: w.total_count,
680	                min: r.min_sample_count,
681	            },
682	            improvement_display: buildImprovementDisplay(
683	                delta,
684	                r.confidence,
685	                r.min_sample_count,
686	                true,
687	            ),
688	            monitor_steps: buildMonitorSteps(
689	                r.min_sample_count,
690	                highConfidenceSamples,
691	                b.action_name,
692	                r.task,
693	                bestRate,
694	                w.action_name,
695	                worstRate,
696	                Math.round((r.confidence ?? 0) * 100),
697	            ),
698	            unlock_hint: buildUnlockHint(
