11	function parseAgeHours(lastSeenAt: string | null): number | null {
12	    if (!lastSeenAt) return null;
13	    const ts = Date.parse(lastSeenAt);
14	    if (!Number.isFinite(ts)) return null;
15	
16	    const ageMs = Math.max(0, Date.now() - ts);
17	    return Number((ageMs / (60 * 60 * 1000)).toFixed(2));
18	}
