20	export function buildRecommendationDataFreshness(
21	    source: RecommendationDataFreshness['source'],
22	    lastSeenAt: string | null,
23	    staleThresholdHours = RECOMMENDATION_STALE_THRESHOLD_HOURS,
24	): RecommendationDataFreshness {
25	    const ageHours = parseAgeHours(lastSeenAt);
26	    return {
27	        source,
28	        last_seen_at: lastSeenAt,
29	        age_hours: ageHours,
30	        is_stale: ageHours !== null && ageHours > staleThresholdHours,
31	        stale_threshold_hours: staleThresholdHours,
32	    };
33	}

