132	export function evaluateCohortCycleBoundary(
133	    active: CohortCycleState,
134	    observation: CohortCycleObservation,
135	): CohortCycleBoundaryDecision {
136	    const openedMs = toEpochMs(active.opened_at);
137	    const observedMs = toEpochMs(observation.observed_at);
138	    const elapsedDays = Math.max(0, (observedMs - openedMs) / (24 * 60 * 60 * 1000));
139	
140	    const outcomesInCycle = Math.max(
141	        0,
142	        normalizeTotalOutcomes(observation.total_outcomes) - active.opened_total_outcomes,
143	    );
144	
145	    const currentConfidence = clamp01(observation.median_confidence);
146	    const openedConfidence = clamp01(active.opened_median_confidence);
147	    const confidenceDrop =
148	        openedConfidence !== null && currentConfidence !== null
149	            ? Number((openedConfidence - currentConfidence).toFixed(4))
150	            : null;
151	
152	    const currentSuccessRate = clamp01(observation.median_success_rate);
153	    const openedSuccessRate = clamp01(active.opened_median_success_rate);
154	    const successRateDrop =
155	        openedSuccessRate !== null && currentSuccessRate !== null
156	            ? Number((openedSuccessRate - currentSuccessRate).toFixed(4))
157	            : null;
158	
159	    if (confidenceDrop !== null && confidenceDrop >= COHORT_EARLY_CLOSE_CONFIDENCE_DROP) {
160	        return {
161	            should_rotate: true,
162	            reason: 'confidence_drop',
163	            elapsed_days: Number(elapsedDays.toFixed(4)),
164	            outcomes_in_cycle: outcomesInCycle,
165	            confidence_drop: confidenceDrop,
166	            success_rate_drop: successRateDrop,
167	        };
168	    }
169	
170	    if (successRateDrop !== null && successRateDrop >= COHORT_EARLY_CLOSE_SUCCESS_RATE_DROP) {
171	        return {
172	            should_rotate: true,
173	            reason: 'success_rate_drop',
174	            elapsed_days: Number(elapsedDays.toFixed(4)),
175	            outcomes_in_cycle: outcomesInCycle,
176	            confidence_drop: confidenceDrop,
177	            success_rate_drop: successRateDrop,
178	        };
179	    }
180	
181	    if (outcomesInCycle >= COHORT_CYCLE_MAX_OUTCOMES) {
182	        return {
183	            should_rotate: true,
184	            reason: 'outcome_count',
185	            elapsed_days: Number(elapsedDays.toFixed(4)),
186	            outcomes_in_cycle: outcomesInCycle,
187	            confidence_drop: confidenceDrop,
188	            success_rate_drop: successRateDrop,
189	        };
190	    }
191	
192	    if (elapsedDays >= COHORT_CYCLE_MAX_DAYS) {
193	        return {
194	            should_rotate: true,
195	            reason: 'time_elapsed',
196	            elapsed_days: Number(elapsedDays.toFixed(4)),
197	            outcomes_in_cycle: outcomesInCycle,
198	            confidence_drop: confidenceDrop,
199	            success_rate_drop: successRateDrop,
200	        };
201	    }
202	
203	    return {
204	        should_rotate: false,
205	        reason: null,
206	        elapsed_days: Number(elapsedDays.toFixed(4)),
207	        outcomes_in_cycle: outcomesInCycle,
208	        confidence_drop: confidenceDrop,
209	        success_rate_drop: successRateDrop,
210	    };
211	}
