231	function fallbackUpsertRecommendationCohortCycle(
232	    observation: CohortCycleObservation,
233	): RecommendationCohortCycleResult {
234	    const key = cycleKey(observation.customer_id, observation.task_name);
235	    const existing = cycleStore.get(key);
236	
237	    if (!existing) {
238	        const created = newCycleState(observation);
239	        cycleStore.set(key, created);
240	
241	        return {
242	            active_cycle: buildActiveSnapshot(created, 0, 0),
243	            previous_cycle: null,
244	            rotation_triggered: false,
245	            rotation_reason: null,
246	            thresholds: {
247	                max_days: COHORT_CYCLE_MAX_DAYS,
248	                max_outcomes: COHORT_CYCLE_MAX_OUTCOMES,
249	                confidence_drop: COHORT_EARLY_CLOSE_CONFIDENCE_DROP,
250	                success_rate_drop: COHORT_EARLY_CLOSE_SUCCESS_RATE_DROP,
251	            },
252	        };
253	    }
254	
255	    const decision = evaluateCohortCycleBoundary(existing, observation);
256	
257	    if (!decision.should_rotate || !decision.reason) {
258	        return {
259	            active_cycle: buildActiveSnapshot(
260	                existing,
261	                decision.elapsed_days,
262	                decision.outcomes_in_cycle,
263	            ),
264	            previous_cycle: null,
265	            rotation_triggered: false,
266	            rotation_reason: null,
267	            thresholds: {
268	                max_days: COHORT_CYCLE_MAX_DAYS,
269	                max_outcomes: COHORT_CYCLE_MAX_OUTCOMES,
270	                confidence_drop: COHORT_EARLY_CLOSE_CONFIDENCE_DROP,
271	                success_rate_drop: COHORT_EARLY_CLOSE_SUCCESS_RATE_DROP,
272	            },
273	        };
274	    }
275	
276	    const previousCycle: RecommendationCohortCycleSnapshot = {
277	        cycle_id: existing.cycle_id,
278	        opened_at: existing.opened_at,
279	        closed_at: observation.observed_at,
280	        close_reason: decision.reason,
281	        elapsed_days: decision.elapsed_days,
282	        outcomes_in_cycle: decision.outcomes_in_cycle,
283	        opened_confidence_source: existing.opened_confidence_source,
284	        opened_confidence_source_reason: existing.opened_confidence_source_reason,
285	    };
286	
287	    const nextCycle = newCycleState(observation);
288	    cycleStore.set(key, nextCycle);
