290	    return {
291	        active_cycle: buildActiveSnapshot(nextCycle, 0, 0),
292	        previous_cycle: previousCycle,
293	        rotation_triggered: true,
294	        rotation_reason: decision.reason,
295	        thresholds: {
296	            max_days: COHORT_CYCLE_MAX_DAYS,
297	            max_outcomes: COHORT_CYCLE_MAX_OUTCOMES,
298	            confidence_drop: COHORT_EARLY_CLOSE_CONFIDENCE_DROP,
299	            success_rate_drop: COHORT_EARLY_CLOSE_SUCCESS_RATE_DROP,
