321	export async function upsertRecommendationCohortCycle(
322	    observation: CohortCycleObservation,
323	): Promise<RecommendationCohortCycleResult> {
324	    const resolvedConfidenceSource = normalizeConfidenceSource(observation.confidence_source);
325	    const resolvedConfidenceSourceReason = normalizeConfidenceSourceReason(observation.confidence_source_reason);
326	
327	    const payload = {
328	        p_customer_id: observation.customer_id,
329	        p_task_name: observation.task_name,
330	        p_observed_at: observation.observed_at,
331	        p_total_outcomes: normalizeTotalOutcomes(observation.total_outcomes),
332	        p_median_confidence: clamp01(observation.median_confidence),
333	        p_median_success_rate: clamp01(observation.median_success_rate),
334	        p_opened_confidence_source: resolvedConfidenceSource,
335	        p_opened_confidence_source_reason: resolvedConfidenceSourceReason,
336	    };
337	
338	    try {
339	        const { data, error } = await supabase.rpc('upsert_recommendation_cohort_cycle', payload as any);
340	
341	        if (error) {
342	            const fallback = fallbackUpsertRecommendationCohortCycle(observation);
343	            if (isMissingRpcFunctionError(error)) {
344	                console.warn(
345	                    '[cohort-cycle] upsert_recommendation_cohort_cycle RPC unavailable; using in-memory fallback:',
346	                    error.message,
347	                );
348	                return fallback;
349	            }
350	
351	            console.warn(
352	                '[cohort-cycle] RPC failed; using in-memory fallback:',
353	                error.message,
354	            );
355	            return fallback;
356	        }
357	
358	        if (!isCohortCycleResult(data)) {
359	            console.warn(
360	                '[cohort-cycle] RPC returned unexpected payload shape; using in-memory fallback.',
361	            );
362	            return fallbackUpsertRecommendationCohortCycle(observation);
363	        }
364	
365	        return {
366	            ...data,
367	            active_cycle: {
368	                ...data.active_cycle,
369	                opened_confidence_source:
370	                    data.active_cycle.opened_confidence_source
371	                    ?? resolvedConfidenceSource
372	                    ?? null,
373	                opened_confidence_source_reason:
374	                    data.active_cycle.opened_confidence_source_reason
375	                    ?? resolvedConfidenceSourceReason
376	                    ?? null,
377	            },
378	            previous_cycle: data.previous_cycle
379	                ? {
380	                    ...data.previous_cycle,
381	                    opened_confidence_source:
382	                        data.previous_cycle.opened_confidence_source ?? null,
383	                    opened_confidence_source_reason:
384	                        data.previous_cycle.opened_confidence_source_reason ?? null,
385	                }
386	                : null,
387	        };
388	    } catch (err: any) {
389	        console.warn(
390	            '[cohort-cycle] RPC threw; using in-memory fallback:',
391	            err?.message ?? 'unknown error',
392	        );
393	        return fallbackUpsertRecommendationCohortCycle(observation);
394	    }
395	}
