62	function cycleAnomalyContribution(
63	    cohortCycle: RecommendationCohortCycleResult,
64	): { score: number; reasons: string[] } {
65	    if (!cohortCycle.rotation_triggered || !cohortCycle.rotation_reason) {
66	        return { score: 0, reasons: [] };
67	    }
68	
69	    const byReason: Record<CohortCycleCloseReason, number> = {
70	        confidence_drop: 0.35,
71	        success_rate_drop: 0.30,
72	        outcome_count: 0.12,
73	        time_elapsed: 0.08,
74	    };
75	
76	    const score = byReason[cohortCycle.rotation_reason] ?? 0.10;
77	
78	    return {
79	        score: Number(score.toFixed(4)),
80	        reasons: [`cycle_rotation:${cohortCycle.rotation_reason}`],
81	    };
82	}
