84	export function computeCohortReliability(
85	    recommendation: RecommendationResult,
86	    cohortCycle: RecommendationCohortCycleResult,
87	): CohortReliabilityResult {
88	    const reasons: string[] = [];
89	    let anomalyScore = 0;
90	
91	    const cycleSignal = cycleAnomalyContribution(cohortCycle);
92	    anomalyScore += cycleSignal.score;
93	    reasons.push(...cycleSignal.reasons);
94	
95	    const noiseSignal = noiseAnomalyContribution(recommendation._noise_gate);
96	    anomalyScore += noiseSignal.score;
97	    reasons.push(...noiseSignal.reasons);
98	
99	    const confidence = clamp01(recommendation.confidence ?? 0);
100	    if (confidence < 0.30) {
101	        anomalyScore += 0.22;
102	        reasons.push('confidence_below_0_30');
103	    } else if (confidence < 0.50) {
104	        anomalyScore += 0.12;
105	        reasons.push('confidence_below_0_50');
106	    }
107	
108	    const minSamples = Math.max(0, Number(recommendation.min_sample_count ?? 0));
109	    if (minSamples < 10) {
110	        anomalyScore += 0.20;
111	        reasons.push('insufficient_min_samples_lt_10');
112	    } else if (minSamples < 25) {
113	        anomalyScore += 0.12;
114	        reasons.push('insufficient_min_samples_lt_25');
115	    }
116	
117	    if (recommendation._silent_failure_warning === true) {
118	        anomalyScore += 0.20;
119	        reasons.push('silent_failure_warning_active');
120	    }
121	
122	    if (recommendation.state === 'no_data') {
123	        anomalyScore = Math.max(anomalyScore, 0.70);
124	        reasons.push('recommendation_state_no_data');
125	    } else if (recommendation.state === 'early_signal') {
126	        anomalyScore += 0.08;
127	        reasons.push('recommendation_state_early_signal');
128	    }
129	
130	    const normalizedAnomaly = Number(clamp01(anomalyScore).toFixed(4));
131	    const reliabilityScore = Number((1 - normalizedAnomaly).toFixed(4));
132	
133	    return {
134	        anomaly_score: normalizedAnomaly,
135	        reliability_score: reliabilityScore,
136	        band: toBand(reliabilityScore),
137	        signals: {
138	            rotation_triggered: cohortCycle.rotation_triggered,
139	            rotation_reason: cohortCycle.rotation_reason,
140	            noisy_task: recommendation._noise_gate?.is_noisy_task ?? false,
141	            confidence,
142	            min_sample_count: minSamples,
143	            silent_failure_warning: recommendation._silent_failure_warning === true,
144	        },
145	        reasons,
146	    };
147	}
