262	function computeSemanticClusterConvergence(params: {
263	    clusterCounts: Map<string, number>;
264	    clusterSamples: number;
265	    clusterConfidenceSum: number;
266	    clusterConfidenceCount: number;
267	}): number {
268	    const {
269	        clusterCounts,
270	        clusterSamples,
271	        clusterConfidenceSum,
272	        clusterConfidenceCount,
273	    } = params;
274	
275	    if (clusterSamples <= 0) {
276	        return 0.5;
277	    }
278	
279	    let dominantClusterCount = 0;
280	    for (const count of clusterCounts.values()) {
281	        if (count > dominantClusterCount) dominantClusterCount = count;
