312	function computeActionDriftSlope(signalRows: ResolutionSignalRow[]): number {
313	    const chronologicalScores = signalRows
314	        .filter((row) => row.ingestionSource !== 'import')
315	        .map((row) => ({
316	            score: row.score,
317	            time: parseIso(row.timestamp),
318	            sequence: row.sequence,
