506	
507	        const timestamp = typeof row.timestamp === 'string' ? row.timestamp : null;
508	        const rawQuality = typeof row.data_quality === 'number' ? row.data_quality : null;
509	        const qualityMultiplier = rawQuality !== null ? Math.max(0, Math.min(1, rawQuality)) : 1.0;
510	        const reliabilityMultiplier = reliabilitySignalWeight({
511	            isInconsistent: row.is_inconsistent,
512	            outcomeClass: row.outcome_class,
513	        });
514	
515	        const current = grouped.get(actionId) ?? {
516	            total: 0,
517	            success_count: 0,
518	            score_sum: 0,
519	            weighted_score_sum: 0,
520	            weight_total: 0,
521	            cluster_counts: new Map<string, number>(),
522	            cluster_samples: 0,
523	            cluster_confidence_sum: 0,
524	            cluster_confidence_count: 0,
525	            signal_rows: [],
526	        };
527	        current.total += 1;
528	        if (derivedSuccess) {
529	            current.success_count += 1;
530	        }
531	        current.score_sum += score;
532	
533	        current.signal_rows.push({
534	            score,
535	            timestamp,
536	            ingestionSource: row.ingestion_source,
537	            qualityMultiplier,
538	            reliabilityMultiplier,
539	            sequence: sequence++,
540	        });
541	
542	        const clusterKey = typeof row.semantic_cluster_key === 'string' ? row.semantic_cluster_key.trim() : '';
543	        if (clusterKey.length > 0) {
544	            current.cluster_counts.set(clusterKey, (current.cluster_counts.get(clusterKey) ?? 0) + 1);
545	            current.cluster_samples += 1;
546	        }
547	        if (typeof row.semantic_cluster_confidence === 'number') {
548	            current.cluster_confidence_sum += clamp01(row.semantic_cluster_confidence);
549	            current.cluster_confidence_count += 1;
550	        }
551	
552	        grouped.set(actionId, current);
553	    }
554	
555	    for (const bucket of grouped.values()) {
556	        const dynamicImportFloor = computeDynamicImportFloor(bucket.success_count, bucket.total);
557	        const sampleConfidence = computeSampleConfidence(bucket.total);
558	        const driftSlope = computeActionDriftSlope(bucket.signal_rows);
559	        bucket.weight_total = 0;
560	        bucket.weighted_score_sum = 0;
561	
562	        for (const signalRow of bucket.signal_rows) {
563	            const recencyWeight = computeOutcomeEffectiveWeightForScore(
564	                signalRow.score,
565	                signalRow.timestamp,
566	            );
567	            const sourceMultiplier = sourceSignalWeight(
568	                signalRow.ingestionSource,
569	                signalRow.timestamp,
570	                driftSlope,
571	                dynamicImportFloor,
572	            );
573	            const effectiveWeight = recencyWeight
574	                * signalRow.qualityMultiplier
575	                * sourceMultiplier
576	                * signalRow.reliabilityMultiplier
577	                * sampleConfidence;
578	            if (effectiveWeight > 0) {
579	                bucket.weight_total += effectiveWeight;
580	                bucket.weighted_score_sum += signalRow.score * effectiveWeight;
581	            }
582	        }
583	    }
584	
585	    return grouped;
586	}
