588	function groupedToStats(
589	    grouped: Map<string, ResolutionAggregationBucket>,
590	): Map<string, TaskResolutionStats & { effectiveSampleCount: number }> {
591	    const out = new Map<string, TaskResolutionStats & { effectiveSampleCount: number }>();
592	    for (const [actionId, stats] of grouped.entries()) {
593	        if (stats.total <= 0) continue;
594	        const weightedRate = stats.weight_total > 0
595	            ? stats.weighted_score_sum / stats.weight_total
596	            : stats.score_sum / stats.total;
597	        const effectiveSamples = stats.weight_total > 0 ? stats.weight_total : stats.total;
598	        out.set(actionId, {
599	            resolutionRate: Number(weightedRate.toFixed(4)),
600	            effectiveSamples: Number(effectiveSamples.toFixed(4)),
601	            effectiveSampleCount: stats.total,
602	            semanticClusterConvergence: computeSemanticClusterConvergence({
603	                clusterCounts: stats.cluster_counts,
604	                clusterSamples: stats.cluster_samples,
605	                clusterConfidenceSum: stats.cluster_confidence_sum,
606	                clusterConfidenceCount: stats.cluster_confidence_count,
607	            }),
608	        });
609	    }
610	    return out;
611	}
