97	function normalizeToken(token: string): string {
98	    const cleaned = token
99	        .trim()
100	        .toLowerCase()
101	        .replace(/[^a-z0-9_]/g, '');
102	    if (!cleaned) return '';
103	    return TOKEN_ALIASES[cleaned] ?? cleaned;
104	}
105	
106	function tokenize(value: string): string[] {
107	    // CamelCase/PascalCase decomposition — MUST happen before toLowerCase().
108	    // processTicketRefundV2 → process Ticket Refund V2
109	    // XMLParser             → XML Parser
110	    const camelSplit = value
111	        .trim()
112	        .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
113	        .replace(/([A-Z]+)([A-Z][a-z])/g, '$1 $2');
114	
115	    const raw = camelSplit
116	        .toLowerCase()
117	        .replace(/[^a-z0-9]+/g, ' ')
118	        .split(/\s+/)
119	        .filter(t => !/^(v\d+|\d+)$/.test(t))
120	        .map((token) => normalizeToken(token))
121	        .filter((token) => token.length > 0 && !STOPWORDS.has(token));
122	
123	    return [...new Set(raw)];
124	}
