126	function resolveIntent(tokens: string[]): {
127	    intent: string;
128	    matchedTokens: string[];
129	    confidenceBoost: number;
130	} {
131	    let bestIntent = 'general';
132	    let bestMatches: string[] = [];
133	
134	    for (const [intent, keywords] of Object.entries(INTENT_TOKENS)) {
135	        const matches = keywords.filter((keyword) => tokens.includes(keyword));
136	        if (matches.length > bestMatches.length) {
137	            bestIntent = intent;
138	            bestMatches = matches;
139	        }
140	    }
141	
142	    if (bestMatches.length > 0) {
143	        return {
144	            intent: bestIntent,
145	            matchedTokens: bestMatches,
146	            confidenceBoost: bestMatches.length >= 2 ? 0.35 : 0.30,
147	        };
148	    }
149	
150	    return {
151	        intent: tokens[0] ?? 'general',
152	        matchedTokens: tokens[0] ? [tokens[0]] : [],
153	        confidenceBoost: tokens.length > 0 ? 0.18 : 0.05,
154	    };
155	}
