157	function resolveDomain(taskName: string | null | undefined, issueType: string, tokens: string[]): {
158	    domain: string;
159	    confidenceBoost: number;
160	} {
161	    const taskTokens = tokenize(taskName ?? '');
162	    const issueTokens = tokenize(issueType);
163	    const candidates = [...taskTokens, ...issueTokens, ...tokens];
164	
165	    for (const token of candidates) {
166	        const mapped = DOMAIN_HINTS[token];
167	        if (mapped) {
168	            return {
169	                domain: mapped,
170	                confidenceBoost: taskTokens.includes(token) ? 0.30 : 0.22,
171	            };
172	        }
173	    }
174	
175	    if (taskTokens.length > 0) {
176	        return {
177	            domain: taskTokens[0] ?? 'general',
178	            confidenceBoost: 0.16,
179	        };
180	    }
181	
182	    if (issueTokens.length > 0) {
183	        return {
184	            domain: issueTokens[0] ?? 'general',
185	            confidenceBoost: 0.12,
186	        };
187	    }
188	
189	    return {
190	        domain: 'general',
191	        confidenceBoost: 0.05,
192	    };
193	}
