195	export function inferSemanticActionCluster(params: SemanticActionClusterParams): SemanticActionClusterResult {
196	    const tokens = tokenize(params.actionName);
197	    const intent = resolveIntent(tokens);
198	    const domain = resolveDomain(params.taskName ?? null, params.issueType, tokens);
199	
200	    let confidence = 0.35;
201	    confidence += intent.confidenceBoost;
202	    confidence += domain.confidenceBoost;
203	
204	    if (intent.matchedTokens.length >= 2) {
205	        confidence += 0.05;
206	    }
207	
208	    const clusterKey = `${domain.domain}__${intent.intent}`;
209	
210	    return {
211	        clusterKey,
212	        domain: domain.domain,
213	        intent: intent.intent,
214	        confidence: Number(clamp01(confidence).toFixed(4)),
215	        matchedTokens: intent.matchedTokens,
216	    };
217	}
