1	// ══════════════════════════════════════════════════════════════
2	// task-infer.ts
3	// Rule-based task name inference from issue_type.
4	//
5	// RULE (from v3 plan):
6	//   If developer provides task_name → ALWAYS use it (caller handles this)
7	//   Else → infer from issue_type using lookup table
8	//   Fallback → slugify issue_type (spaces to underscores, lowercase)
9	//
10	// This function is ONLY called when task_name is absent from request.
11	// It never overrides a developer-provided task_name.
12	// ══════════════════════════════════════════════════════════════
13	
14	// Known issue_type → task_name mappings
15	// These cover the most common patterns seen across agent deployments.
16	// Add new mappings here as new issue types are discovered.
17	const ISSUE_TYPE_TO_TASK: Record<string, string> = {
18	  // Payment & billing
19	  'billing_dispute': 'payment_failed',
20	  'payment_failure': 'payment_failed',
21	  'payment_failed': 'payment_failed',
22	  'charge_failed': 'payment_failed',
23	  'refund_request': 'refund_processing',
24	  'refund_failed': 'refund_processing',
25	  'subscription_cancel': 'subscription_management',
26	  'subscription_failed': 'subscription_management',
27	  'invoice_dispute': 'payment_failed',
28	
29	  // Support & escalation
30	  'ticket_open': 'ticket_resolution',
31	  'ticket_escalation': 'ticket_resolution',
32	  'support_request': 'ticket_resolution',
33	  'complaint': 'ticket_resolution',
34	  'angry_customer': 'ticket_resolution',
35	
36	  // Auth & access
37	  'login_failed': 'auth_recovery',
38	  'account_locked': 'auth_recovery',
39	  'password_reset': 'auth_recovery',
40	  'access_denied': 'auth_recovery',
41	
42	  // Order & fulfilment
43	  'order_failed': 'order_recovery',
44	  'delivery_failed': 'order_recovery',
45	  'order_cancelled': 'order_recovery',
46	  'item_missing': 'order_recovery',
47	
48	  // Onboarding
49	  'onboarding_stuck': 'onboarding',
50	  'setup_failed': 'onboarding',
51	  'integration_failed': 'onboarding',
52	};
53	
54	const VALID_TASK_PATTERN = /^[a-z][a-z0-9_]{1,63}$/;
55	const MAX_TASK_NAME_LENGTH = 64;
56	const GENERIC_TASK_NAME = 'unspecified_issue';
57	const GENERIC_PLACEHOLDER_TOKENS = new Set([
58	  'unknown',
59	  'unknown_task',
60	  'unspecified',
61	  'unspecified_issue',
62	  'n_a',
63	  'na',
64	  'none',
65	  'null',
66	  'undefined',
67	]);
68	
69	function stableTaskHash(raw: string): string {
70	  // Deterministic short hash so unparseable labels still map to a stable task bucket.
71	  let hash = 2166136261;
72	  const input = raw.trim().toLowerCase();
73	  for (let i = 0; i < input.length; i += 1) {
74	    hash ^= input.charCodeAt(i);
75	    hash = Math.imul(hash, 16777619);
76	  }
77	  return (hash >>> 0).toString(36).padStart(7, '0').slice(0, 10);
78	}
79	
80	function normalizeTaskToken(raw: string): string {
81	  return raw
82	    .normalize('NFKD')
83	    .replace(/[\u0300-\u036f]/g, '')
84	    .trim()
85	    .toLowerCase()
86	    .replace(/[\s\-]+/g, '_')
87	    .replace(/[^a-z0-9_]/g, '_')
88	    .replace(/_+/g, '_')
89	    .replace(/^_+|_+$/g, '');
90	}
91	
92	function fallbackTaskName(raw: string): string {
93	  return `task_${stableTaskHash(raw)}`;
94	}
95	
96	function buildTaskCandidate(raw: string): string {
97	  const normalized = normalizeTaskToken(raw);
98	  if (!normalized) return '';
99	
100	  const prefixed = /^[a-z]/.test(normalized)
101	    ? normalized
102	    : `task_${normalized}`;
103	
104	  return prefixed
105	    .slice(0, MAX_TASK_NAME_LENGTH)
106	    .replace(/^_+|_+$/g, '')
107	    .replace(/_+$/g, '');
108	}
109	
110	export function validateTaskName(raw: string | null | undefined): string {
111	  if (!raw) return 'unknown_task_empty';
112	  if (raw.trim() === '') return 'unknown_task_empty';
113	
114	  const candidate = buildTaskCandidate(raw);
115	  if (!candidate) return fallbackTaskName(raw);
116	
117	  if (GENERIC_PLACEHOLDER_TOKENS.has(candidate)) {
118	    return GENERIC_TASK_NAME;
119	  }
120	
121	  if (!VALID_TASK_PATTERN.test(candidate)) {
122	    return fallbackTaskName(raw);
123	  }
124	
125	  return candidate;
126	}
127	
128	export function isGenericTaskName(taskName: string | null | undefined): boolean {
129	  if (!taskName) return false;
130	  const normalized = validateTaskName(taskName);
131	  return normalized.startsWith('unknown_task') || normalized === GENERIC_TASK_NAME;
132	}
133	
134	/**
135	 * Confidence tiers for issue_type → task_name mapping.
136	 *
137	 * DEVELOPER_PROVIDED (1.0): Developer explicitly set task_name — authoritative.
138	 * EXACT_MATCH        (0.90): issue_type found verbatim in ISSUE_TYPE_TO_TASK table.
139	 * PREFIX_MATCH       (0.70): issue_type shares a known prefix — plausible but inferred.
140	 * SLUGIFIED_FALLBACK (0.50): No known mapping; issue_type used directly after slugify.
141	 * UNKNOWN            (0.30): issue_type was blank.
142	 */
143	export type TaskMappingTier =
144	  | 'developer_provided'
145	  | 'exact_match'
146	  | 'prefix_match'
147	  | 'slugified_fallback'
148	  | 'unknown';
149	
150	export const TASK_MAPPING_CONFIDENCE: Record<TaskMappingTier, number> = {
151	  developer_provided: 1.00,
152	  exact_match: 0.90,
153	  prefix_match: 0.70,
154	  slugified_fallback: 0.50,
155	  unknown: 0.30,
156	};
157	
158	export interface TaskInferResult {
159	  /** Resolved task name — always a non-empty string. */
160	  task: string;
161	  /**
162	   * Confidence that this task name is correct (0.0–1.0).
163	   * Store in fact_outcomes.mapping_confidence.
164	   * Scoring engine down-weights outcomes with low confidence.
165	   */
166	  confidence: number;
167	  /** Which resolution tier was used. */
168	  tier: TaskMappingTier;
169	}
170	
171	/**
172	 * Infers a task_name from issue_type when the developer did not provide one.
173	 *
174	 * Priority:
175	 *   1. Exact match in ISSUE_TYPE_TO_TASK lookup  → confidence 0.90
176	 *   2. Prefix match (e.g. "payment_" → "payment_failed") → confidence 0.70
177	 *   3. Slugified issue_type (spaces/hyphens → underscores, lowercase) → confidence 0.50
178	 *   4. Blank issue_type → 'unknown_task', confidence 0.30
179	 *
180	 * @param issueType - The issue_type field from the log_outcome request.
181	 * @returns TaskInferResult with task name, confidence, and tier.
182	 */
183	export function inferTask(issueType: string): TaskInferResult {
184	  if (!issueType || issueType.trim() === '') {
185	    return {
186	      task: 'unknown_task_empty',
187	      confidence: TASK_MAPPING_CONFIDENCE.unknown,
188	      tier: 'unknown',
189	    };
190	  }
191	
192	  const normalized = normalizeTaskToken(issueType);
193	  if (!normalized) {
194	    return {
195	      task: fallbackTaskName(issueType),
196	      confidence: TASK_MAPPING_CONFIDENCE.slugified_fallback,
197	      tier: 'slugified_fallback',
198	    };
199	  }
200	
201	  // 1. Exact match — highest confidence inferred mapping
202	  if (ISSUE_TYPE_TO_TASK[normalized]) {
203	    return {
204	      task: ISSUE_TYPE_TO_TASK[normalized]!,
205	      confidence: TASK_MAPPING_CONFIDENCE.exact_match,
206	      tier: 'exact_match',
207	    };
208	  }
209	
210	  // 2. Prefix match — plausible but not certain
211	  for (const [key, value] of Object.entries(ISSUE_TYPE_TO_TASK)) {
212	    const prefix = key.split('_')[0];
213	    if (prefix && (normalized === prefix || normalized.startsWith(`${prefix}_`))) {
214	      return {
215	        task: value,
216	        confidence: TASK_MAPPING_CONFIDENCE.prefix_match,
217	        tier: 'prefix_match',
218	      };
219	    }
220	  }
221	
222	  // 3. Slugified fallback — structural normalization only, no semantic claim
223	  const slugified = validateTaskName(normalized);
224	  // Return the slugified result if it's a meaningful name (not a scoped unknown).
225	  // GENERIC_TASK_NAME ('unspecified_issue') is meaningful — it's the canonical
226	  // placeholder for known generic inputs like 'unknown_task', 'na', 'null', etc.
227	  if (!slugified.startsWith('unknown_task')) {
228	    return {
229	      task: slugified,
230	      confidence: slugified === GENERIC_TASK_NAME
231	        ? TASK_MAPPING_CONFIDENCE.slugified_fallback
232	        : TASK_MAPPING_CONFIDENCE.slugified_fallback,
233	      tier: 'slugified_fallback',
234	    };
235	  }
236	
237	  // 4. Unresolvable — scoped bucket via stable hash (NOT one global bucket)
238	  return {
239	    task: `unknown_${stableTaskHash(issueType)}`,
240	    confidence: TASK_MAPPING_CONFIDENCE.unknown,
241	    tier: 'unknown',
242	  };
243	}
