71	export interface NarrativeOutput {
72	    summary: string;
73	    evidence: string;
74	    confidence_note: string;
75	    message: string;
76	    /** One-line plain-English headline for the card header */
77	    headline: string;
78	    /** 2-3 sentence narrative expanding on why one action is better */
79	    narrative: string;
80	    /** 1-3 concrete next steps the developer should take */
81	    next_steps: string[];
82	    /** 0-2 risk factors that could change this recommendation */
83	    risk_factors: string[];
84	    /** Overall trend direction based on available signal */
85	    trend_direction: 'improving' | 'stable' | 'degrading' | 'unknown';
