144	// Hack to make the prompt builder not need a method on context
145	function decision_type_label(type: NarrativeContext['decision_type']): string {
146	    if (type === 'replace') return 'Replace worst action with best action';
147	    if (type === 'monitor') return 'Monitor — do not switch yet';
148	    return 'Collect more data — no recommendation yet';
149	}
150	
151	// In-flight dedup: same context fingerprint → share one LLM promise
152	const inflightCalls = new Map<string, Promise<NarrativeOutput | null>>();
153	const responseCache = new Map<string, { value: NarrativeOutput; expiresAt: number }>();
154	
155	function contextFingerprint(ctx: NarrativeContext): string {
156	    return [
157	        ctx.task,
158	        ctx.state,
159	        ctx.confidence_pct,
160	        ctx.best_action,
161	        ctx.worst_action,
162	        ctx.delta_pct,
163	        ctx.min_sample_count,
164	        ctx.reliability_band,
165	        ctx.silent_failure_warning,
166	        ctx.scope,
167	        ctx.scope_fallback_applied,
