1	/**
2	 * Layerinfinite — lib/adapters/langchain-adapter.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Flattens LangChain/LangSmith trace exports into NormalizedOutcomeRow[].
5	 *
6	 * LangSmith exports contain nested `runs[]` with `run_type`:
7	 *   - "chain"  → wrapper, skip
8	 *   - "llm"    → LLM call, skip (no action outcome)
9	 *   - "tool"   → actual action execution → extract as outcome
10	 *
11	 * Maps:
12	 *   name            → action_name
13	 *   error !== null   → success: false
14	 *   outputs          → success: true (if no error)
15	 *   start_time/end   → response_time_ms
16	 *   extra.token_usage → resource_cost_units
17	 *   parent_run_id    → episode_id (groups agent steps)
18	 * ══════════════════════════════════════════════════════════════
19	 */
20	
21	import type { NormalizedOutcomeRow } from '../ingest-core.js';
22	
23	// ── Types ─────────────────────────────────────────────────────
24	
25	interface LangChainRun {
26	    id?: string;
27	    name?: string;
28	    run_type?: string;
29	    tags?: unknown;
30	    parent_run_id?: string | null;
31	    inputs?: Record<string, unknown>;
32	    outputs?: Record<string, unknown> | null;
33	    error?: string | null;
34	    start_time?: string;
35	    end_time?: string;
36	    execution_order?: number;
37	    child_runs?: LangChainRun[];
38	    extra?: {
39	        token_usage?: {
40	            total_tokens?: number;
41	            prompt_tokens?: number;
42	            completion_tokens?: number;
43	        };
44	        [key: string]: unknown;
45	    };
46	    [key: string]: unknown;
47	}
48	
49	interface LangChainTrace {
50	    runs?: LangChainRun[];
51	    // LangSmith export may also have a top-level run
52	    id?: string;
53	    name?: string;
54	    run_type?: string;
55	    child_runs?: LangChainRun[];
56	    [key: string]: unknown;
57	}
58	
59	// ── Detection ─────────────────────────────────────────────────
60	
61	/**
62	 * Detects whether raw parsed JSON looks like a LangChain/LangSmith trace.
63	 * Checks for `runs[]` array with objects containing `run_type` field,
64	 * or a single top-level object with `run_type`.
65	 */
66	export function isLangChainTrace(data: unknown): boolean {
67	    if (data === null || typeof data !== 'object') return false;
68	
69	    const obj = data as Record<string, unknown>;
70	
71	    // Array of runs
72	    if (Array.isArray(obj.runs)) {
73	        return obj.runs.some(
74	            (run: unknown) =>
75	                typeof run === 'object' &&
76	                run !== null &&
77	                'run_type' in run,
78	        );
79	    }
80	
81	    // Single trace export with child_runs
82	    if (typeof obj.run_type === 'string' && Array.isArray(obj.child_runs)) {
83	        return true;
84	    }
85	
86	    // Array of run objects at top level
87	    if (Array.isArray(data)) {
88	        return (data as unknown[]).some(
89	            (item: unknown) =>
90	                typeof item === 'object' &&
91	                item !== null &&
92	                'run_type' in item,
93	        );
94	    }
95	
96	    return false;
97	}
98	
99	// ── Extraction ────────────────────────────────────────────────
100	
101	function collectToolRuns(runs: LangChainRun[], parentEpisodeId?: string): LangChainRun[] {
102	    const tools: (LangChainRun & { _episodeId?: string })[] = [];
103	
104	    for (const run of runs) {
105	        const episodeId = run.parent_run_id ?? parentEpisodeId;
106	
107	        if (run.run_type === 'tool') {
108	            (run as any)._episodeId = episodeId;
109	            tools.push(run as any);
110	        }
111	
112	        // Recursively collect from child_runs
113	        if (Array.isArray(run.child_runs) && run.child_runs.length > 0) {
114	            tools.push(...collectToolRuns(run.child_runs, run.id ?? episodeId));
115	        }
116	    }
117	
118	    return tools;
119	}
120	
121	function computeResponseMs(startTime?: string, endTime?: string): number | null {
122	    if (!startTime || !endTime) return null;
123	    const start = new Date(startTime).getTime();
124	    const end = new Date(endTime).getTime();
125	    if (Number.isNaN(start) || Number.isNaN(end) || end < start) return null;
126	    return Math.round(end - start);
127	}
128	
129	function extractTokenUsage(run: LangChainRun): number | null {
130	    // Direct token_usage on the tool run
131	    const directTokens = run.extra?.token_usage?.total_tokens;
132	    if (typeof directTokens === 'number' && directTokens > 0) return directTokens;
133	
134	    // Check for token_usage in outputs (some frameworks put it there)
135	    const outputTokens = (run.outputs as any)?.token_usage?.total_tokens;
136	    if (typeof outputTokens === 'number' && outputTokens > 0) return outputTokens;
137	
138	    return null;
139	}
140	
141	function extractErrorMessage(run: LangChainRun): string | null {
142	    if (typeof run.error === 'string' && run.error.length > 0) {
143	        return run.error.slice(0, 1000);
144	    }
145	    return null;
146	}
147	
148	function normalizeActionName(name: string | undefined): string {
149	    if (!name || typeof name !== 'string') return 'unknown_tool';
150	    // Snake-case normalize: SearchDatabase → search_database
151	    return name
152	        .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
153	        .replace(/([A-Z]+)([A-Z][a-z])/g, '$1_$2')
154	        .toLowerCase()
155	        .replace(/[^a-z0-9_]/g, '_')
156	        .replace(/_+/g, '_')
157	        .replace(/^_+|_+$/g, '')
158	        || 'unknown_tool';
159	}
160	
161	// ── Main Flatten Function ─────────────────────────────────────
162	
163	/**
164	 * Flattens a LangChain/LangSmith trace into NormalizedOutcomeRow[].
165	 * Only extracts `run_type: "tool"` runs — chains and LLM calls are skipped.
166	 *
167	 * @param trace Raw parsed JSON from LangSmith export
168	 * @param agentId Agent ID from the API key (caller provides)
169	 * @param issueType Issue type context (caller provides or defaults to 'langchain_trace')
170	 * @returns Array of normalized outcome rows ready for the import pipeline
171	 */
172	export function flattenLangChainTrace(
173	    trace: unknown,
174	    agentId: string,
175	    issueType: string = 'langchain_trace',
176	): NormalizedOutcomeRow[] {
177	    if (!trace || typeof trace !== 'object') return [];
178	
179	    const obj = trace as LangChainTrace;
180	
181	    // Collect all runs from various export formats
182	    let allRuns: LangChainRun[] = [];
183	
184	    if (Array.isArray(obj.runs)) {
185	        allRuns = obj.runs;
186	    } else if (Array.isArray(trace)) {
187	        allRuns = trace as LangChainRun[];
188	    } else if (obj.run_type && Array.isArray(obj.child_runs)) {
189	        // Single trace at top level — treat as one run tree
190	        allRuns = [obj as unknown as LangChainRun];
191	    }
192	
193	    if (allRuns.length === 0) return [];
194	
195	    // Extract only tool-level runs (recursive)
196	    const toolRuns = collectToolRuns(allRuns);
197	
198	    return toolRuns.map((run): NormalizedOutcomeRow => {
199	        const hasError = run.error !== null && run.error !== undefined && run.error !== '';
200	        const hasOutput = run.outputs !== null && run.outputs !== undefined;
201	        const success = !hasError && hasOutput;
202	        const responseMs = computeResponseMs(run.start_time, run.end_time);
203	        const tokenCost = extractTokenUsage(run);
204	        const errorMessage = extractErrorMessage(run);
205	
206	        let resolvedIssue = issueType;
207	        if (run.inputs && typeof run.inputs === 'object') {
208	            const ri = run.inputs as Record<string, unknown>;
209	            if (typeof ri.issue_type === 'string' && ri.issue_type.trim()) resolvedIssue = ri.issue_type.trim();
210	            else if (typeof ri.task_name === 'string' && ri.task_name.trim()) resolvedIssue = ri.task_name.trim();
211	            else if (typeof ri.task === 'string' && ri.task.trim()) resolvedIssue = ri.task.trim();
212	        }
213	
214	        return {
215	            agent_id: agentId,
216	            action_name: normalizeActionName(run.name),
217	            issue_type: resolvedIssue,
218	            success,
219	            response_time_ms: responseMs,
220	            error_message: errorMessage,
221	            error_code: hasError ? 'tool_error' : null,
222	            episode_id: (run as any)._episodeId ?? null,
223	            session_id: run.id ?? null,
224	            resource_cost_units: tokenCost,
225	            resource_cost_type: tokenCost !== null ? 'tokens' : null,
226	            environment: 'production',
227	            feedback_signal: 'immediate',
228	            signal_source: 'explicit',
229	            raw_context: {
230	                inputs: run.inputs,
231	                outputs: run.outputs,
232	                tags: run.tags,
233	                extra: run.extra,
234	            },
235	        };
236	    });
237	}
