1	/**
2	 * Layerinfinite — lib/adapters/langgraph-adapter.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Flattens LangGraph checkpoint/state exports into NormalizedOutcomeRow[].
5	 *
6	 * LangGraph uses a state machine model:
7	 *   - Nodes represent processing steps (tools, LLM calls, routing)
8	 *   - State transitions carry channel_values between nodes
9	 *   - Checkpoints capture the full graph state at each node exit
10	 *
11	 * Maps:
12	 *   node_name         → action_name
13	 *   error in state    → success: false
14	 *   channel_values    → outcome context
15	 *   timestamps        → response_time_ms
16	 *   thread_id          → episode_id
17	 * ══════════════════════════════════════════════════════════════
18	 */
19	
20	import type { NormalizedOutcomeRow } from '../ingest-core.js';
21	
22	// ── Types ─────────────────────────────────────────────────────
23	
24	interface LangGraphCheckpoint {
25	    thread_id?: string;
26	    checkpoint_id?: string;
27	    node?: string;
28	    channel_values?: Record<string, unknown>;
29	    error?: string | null;
30	    metadata?: {
31	        source?: string;
32	        step?: number;
33	        writes?: Record<string, unknown>;
34	        [key: string]: unknown;
35	    };
36	    created_at?: string;
37	    parent_checkpoint_id?: string | null;
38	    [key: string]: unknown;
39	}
40	
41	interface LangGraphEvent {
42	    event?: string;
43	    name?: string;
44	    data?: {
45	        input?: Record<string, unknown>;
46	        output?: Record<string, unknown>;
47	        chunk?: unknown;
48	    };
49	    metadata?: {
50	        thread_id?: string;
51	        checkpoint_id?: string;
52	        [key: string]: unknown;
53	    };
54	    run_id?: string;
55	    parent_ids?: string[];
56	    tags?: string[];
57	    [key: string]: unknown;
58	}
59	
60	// ── Detection ─────────────────────────────────────────────────
61	
62	/**
63	 * Detects whether raw parsed JSON looks like a LangGraph export.
64	 * Checks for checkpoint arrays or astream_events format.
65	 */
66	export function isLangGraphTrace(data: unknown): boolean {
67	    if (data === null || typeof data !== 'object') return false;
68	
69	    // Array of checkpoints
70	    if (Array.isArray(data)) {
71	        return (data as unknown[]).some(
72	            (item: unknown) =>
73	                typeof item === 'object' &&
74	                item !== null &&
75	                ('channel_values' in item || 'checkpoint_id' in item),
76	        );
77	    }
78	
79	    const obj = data as Record<string, unknown>;
80	
81	    // Direct checkpoint export with channel_values
82	    if (obj.channel_values && typeof obj.node === 'string') return true;
83	
84	    // astream_events format
85	    if (Array.isArray(obj.events)) {
86	        return (obj.events as unknown[]).some(
87	            (ev: unknown) =>
88	                typeof ev === 'object' &&
89	                ev !== null &&
90	                'event' in ev &&
91	                typeof (ev as Record<string, unknown>).event === 'string' &&
92	                ((ev as Record<string, unknown>).event as string).startsWith('on_'),
93	        );
94	    }
95	
96	    // Nested under checkpoints key
97	    if (Array.isArray(obj.checkpoints)) {
98	        return (obj.checkpoints as unknown[]).some(
99	            (item: unknown) =>
100	                typeof item === 'object' &&
101	                item !== null &&
102	                ('channel_values' in item || 'node' in item),
103	        );
104	    }
105	
106	    return false;
107	}
108	
109	// ── Helpers ───────────────────────────────────────────────────
110	
111	const SKIP_NODES = new Set([
112	    '__start__',
113	    '__end__',
114	    '__root__',
115	    'start',
116	    'end',
117	]);
118	
119	function normalizeNodeName(name: string | undefined): string {
120	    if (!name || typeof name !== 'string') return 'unknown_node';
121	    return name
122	        .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
123	        .replace(/([A-Z]+)([A-Z][a-z])/g, '$1_$2')
124	        .toLowerCase()
125	        .replace(/[^a-z0-9_]/g, '_')
126	        .replace(/_+/g, '_')
127	        .replace(/^_+|_+$/g, '')
128	        || 'unknown_node';
129	}
130	
131	function hasError(checkpoint: LangGraphCheckpoint): boolean {
132	    if (typeof checkpoint.error === 'string' && checkpoint.error.length > 0) return true;
133	    // Check for error in channel_values
134	    const channels = checkpoint.channel_values;
135	    if (channels && typeof channels === 'object') {
136	        if ('error' in channels && channels.error) return true;
137	    }
138	    return false;
139	}
140	
141	function extractErrorMessage(checkpoint: LangGraphCheckpoint): string | null {
142	    if (typeof checkpoint.error === 'string' && checkpoint.error.length > 0) {
143	        return checkpoint.error.slice(0, 1000);
144	    }
145	    const channels = checkpoint.channel_values;
146	    if (channels && typeof channels === 'object' && 'error' in channels) {
147	        const err = channels.error;
148	        if (typeof err === 'string') return err.slice(0, 1000);
149	        if (err && typeof err === 'object' && 'message' in err) {
150	            return String((err as any).message).slice(0, 1000);
151	        }
152	    }
153	    return null;
154	}
155	
156	// ── Checkpoint Flatten ────────────────────────────────────────
157	
158	function flattenCheckpoints(
159	    checkpoints: LangGraphCheckpoint[],
160	    agentId: string,
161	    issueType: string,
162	): NormalizedOutcomeRow[] {
163	    return checkpoints
164	        .filter((cp) => {
165	            const nodeName = cp.node ?? cp.metadata?.source;
166	            return typeof nodeName === 'string' && !SKIP_NODES.has(nodeName.toLowerCase());
167	        })
168	        .map((cp, index): NormalizedOutcomeRow => {
169	            const nodeName = cp.node ?? cp.metadata?.source ?? 'unknown_node';
170	            const errored = hasError(cp);
171	            
172	            // Dynamic context extraction for tasks
173	            let resolvedIssue = issueType;
174	            if (cp.channel_values && typeof cp.channel_values === 'object') {
175	                const cv = cp.channel_values as Record<string, unknown>;
176	                if (typeof cv.issue_type === 'string' && cv.issue_type.trim()) resolvedIssue = cv.issue_type.trim();
177	                else if (typeof cv.task_name === 'string' && cv.task_name.trim()) resolvedIssue = cv.task_name.trim();
178	                else if (typeof cv.task === 'string' && cv.task.trim()) resolvedIssue = cv.task.trim();
179	            }
180	
181	            return {
182	                agent_id: agentId,
183	                action_name: normalizeNodeName(nodeName),
184	                issue_type: resolvedIssue,
185	                success: !errored,
186	                error_message: extractErrorMessage(cp),
187	                error_code: errored ? 'node_error' : null,
188	                episode_id: cp.thread_id ?? null,
189	                session_id: cp.checkpoint_id ?? null,
190	                environment: 'production',
191	                feedback_signal: 'immediate',
192	                signal_source: 'explicit',
193	                retry_attempt: cp.metadata?.step ?? index,
194	                raw_context: {
195	                    channel_values: cp.channel_values,
196	                },
197	            };
198	        });
199	}
200	
201	// ── Event Stream Flatten ──────────────────────────────────────
202	
203	function flattenEvents(
204	    events: LangGraphEvent[],
205	    agentId: string,
206	    issueType: string,
207	): NormalizedOutcomeRow[] {
208	    // Only extract on_tool_end events (actual action completions)
209	    return events
210	        .filter((ev) => ev.event === 'on_tool_end' || ev.event === 'on_chain_end')
211	        .filter((ev) => {
212	            const name = ev.name ?? '';
213	            return !SKIP_NODES.has(name.toLowerCase());
214	        })
215	        .map((ev): NormalizedOutcomeRow => {
216	            const hasOutput = ev.data?.output !== null && ev.data?.output !== undefined;
217	            const errored = !hasOutput;
218	
219	            let resolvedIssue = issueType;
220	            if (ev.data && typeof ev.data === 'object') {
221	                const ed = ev.data as Record<string, unknown>;
222	                if (typeof ed.issue_type === 'string' && ed.issue_type.trim()) resolvedIssue = ed.issue_type.trim();
223	                else if (typeof ed.task_name === 'string' && ed.task_name.trim()) resolvedIssue = ed.task_name.trim();
224	            } else if (ev.metadata && typeof ev.metadata === 'object') {
225	                const md = ev.metadata as Record<string, unknown>;
226	                if (typeof md.issue_type === 'string' && md.issue_type.trim()) resolvedIssue = md.issue_type.trim();
227	            }
228	
229	            return {
230	                agent_id: agentId,
231	                action_name: normalizeNodeName(ev.name),
232	                issue_type: resolvedIssue,
233	                success: !errored,
234	                episode_id: ev.metadata?.thread_id ?? ev.run_id ?? null,
235	                session_id: ev.run_id ?? null,
236	                environment: 'production',
237	                feedback_signal: 'immediate',
238	                signal_source: 'explicit',
239	                raw_context: ev.data ?? ev,
240	            };
241	        });
242	}
243	
244	// ── Main Flatten Function ─────────────────────────────────────
245	
246	/**
247	 * Flattens a LangGraph trace export into NormalizedOutcomeRow[].
248	 * Supports checkpoint arrays and astream_events format.
249	 *
250	 * @param trace Raw parsed JSON from LangGraph export
251	 * @param agentId Agent ID from the API key
252	 * @param issueType Issue type context (defaults to 'langgraph_trace')
253	 * @returns Array of normalized outcome rows
254	 */
255	export function flattenLangGraphTrace(
256	    trace: unknown,
257	    agentId: string,
258	    issueType: string = 'langgraph_trace',
259	): NormalizedOutcomeRow[] {
260	    if (!trace || typeof trace !== 'object') return [];
261	
262	    // Array of checkpoints at top level
263	    if (Array.isArray(trace)) {
264	        const items = trace as unknown[];
265	        const hasCheckpoints = items.some(
266	            (item) =>
267	                typeof item === 'object' &&
268	                item !== null &&
269	                ('channel_values' in item || 'checkpoint_id' in item),
270	        );
271	        if (hasCheckpoints) {
272	            return flattenCheckpoints(items as LangGraphCheckpoint[], agentId, issueType);
273	        }
274	        // Could be array of events
275	        const hasEvents = items.some(
276	            (item) =>
277	                typeof item === 'object' &&
278	                item !== null &&
279	                'event' in item,
280	        );
281	        if (hasEvents) {
282	            return flattenEvents(items as LangGraphEvent[], agentId, issueType);
283	        }
284	        return [];
285	    }
286	
287	    const obj = trace as Record<string, unknown>;
288	
289	    // Nested under checkpoints key
290	    if (Array.isArray(obj.checkpoints)) {
291	        return flattenCheckpoints(obj.checkpoints as LangGraphCheckpoint[], agentId, issueType);
292	    }
293	
294	    // Nested under events key
295	    if (Array.isArray(obj.events)) {
296	        return flattenEvents(obj.events as LangGraphEvent[], agentId, issueType);
297	    }
298	
299	    // Single checkpoint
300	    if (obj.channel_values && typeof obj.node === 'string') {
301	        return flattenCheckpoints([obj as unknown as LangGraphCheckpoint], agentId, issueType);
302	    }
303	
304	    return [];
305	}
